fn format_profile_string(value: &str) -> String {
    if value
        .bytes()
        .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'_' | b'$' | b'.' | b'-'))
    {
        value.to_owned()
    } else {
        format!("{value:?}")
    }
}

fn describe_scalar_frontier_trace(
    bytecode: &HermesBytecode<'_>,
    function_id: u32,
    trace_limit: usize,
    mode: ScalarTraceMode,
) -> Result<String, ParseError> {
    let body = bytecode.function_body(function_id)?;
    let function_header = bytecode.function_header(function_id)?;
    let frame_size = usize::try_from(function_header.frame_size)
        .expect("Hermes function frame size fits in usize on supported targets");
    let mut registers = vec![ScalarValue::Empty; frame_size];
    let mut state = ScalarExecutorState {
        relaxed_host_stubs: mode == ScalarTraceMode::Relaxed,
        remaining_steps: Some(SCALAR_EXECUTION_GLOBAL_STEP_LIMIT),
        ..ScalarExecutorState::default()
    };
    let instructions = bytecode
        .function_instructions(function_id)?
        .collect::<Result<Vec<_>, _>>()?;
    let instruction_bytes = instructions
        .iter()
        .map(|instruction| instruction_bytes(body, *instruction))
        .collect::<Vec<_>>();
    let mut string_operand_cache = ScalarStringOperandCache::default();
    let step_limit = instructions
        .len()
        .saturating_mul(SCALAR_EXECUTION_STEP_MULTIPLIER)
        .max(1);
    let mut instruction_index = 0_usize;
    let mut step_count = 0_usize;
    let mut trace = Vec::new();

    while instruction_index < instructions.len() {
        if let Some(remaining_steps) = state.remaining_steps.as_mut() {
            if *remaining_steps == 0 {
                return Ok(format!(
                    "status=frontier, error=global step limit exceeded at {SCALAR_EXECUTION_GLOBAL_STEP_LIMIT}, trace={}",
                    trace.join(" | ")
                ));
            }
            *remaining_steps -= 1;
        }
        if step_count >= step_limit {
            return Ok(format!(
                "status=frontier, error=step limit exceeded at {step_limit}, trace={}",
                trace.join(" | ")
            ));
        }
        step_count += 1;

        let instruction = instructions[instruction_index];
        let description = describe_scalar_instruction(bytecode, body, instruction);
        let before = registers.clone();
        let current_instruction_bytes = instruction_bytes[instruction_index];
        match execute_scalar_instruction(
            bytecode,
            &mut state,
            &mut registers,
            &[],
            function_id,
            current_instruction_bytes,
            &mut string_operand_cache,
            instruction,
            None,
        ) {
            Ok(ScalarInstructionResult::Continue) => {
                push_scalar_trace(
                    &mut trace,
                    trace_limit,
                    format!(
                        "{description} -> {}",
                        describe_register_changes(&before, &registers)
                    ),
                );
                instruction_index += 1;
            }
            Ok(ScalarInstructionResult::Jump(target)) => {
                push_scalar_trace(
                    &mut trace,
                    trace_limit,
                    format!(
                        "{description} -> jump {target}, {}",
                        describe_register_changes(&before, &registers)
                    ),
                );
                instruction_index = instructions
                    .binary_search_by_key(&target, |instruction| instruction.offset)
                    .map_err(|_| ParseError::InvalidJumpTarget {
                        function_id,
                        offset: instruction.offset,
                        opcode: instruction.opcode,
                        target: i64::from(target),
                        body_start: body.offset,
                        body_end: body.offset + body.len(),
                    })?;
            }
            Ok(ScalarInstructionResult::Return(value)) => {
                push_scalar_trace(
                    &mut trace,
                    trace_limit,
                    format!("{description} -> return {value:?}"),
                );
                return Ok(format!(
                    "status=completed, value={value:?}, steps={step_count}, trace={}",
                    trace.join(" | ")
                ));
            }
            Err(error) => {
                return Ok(format!(
                    "status=frontier, error={error}, instruction={description}, steps={step_count}, recentCalls={}, trace={}",
                    describe_recent_scalar_calls(&state),
                    trace.join(" | ")
                ));
            }
        }
    }

    Ok(format!(
        "status=frontier, error=missing return in function {function_id}, steps={step_count}, trace={}",
        trace.join(" | ")
    ))
}

fn push_scalar_trace(trace: &mut Vec<String>, trace_limit: usize, entry: String) {
    trace.push(entry);
    if trace.len() > trace_limit {
        trace.remove(0);
    }
}

fn describe_register_changes(before: &[ScalarValue], after: &[ScalarValue]) -> String {
    let changes = before
        .iter()
        .zip(after.iter())
        .enumerate()
        .filter(|(_, (before, after))| before != after)
        .map(|(index, (_, after))| format!("r{index}={after:?}"))
        .collect::<Vec<_>>();

    if changes.is_empty() {
        "registers=unchanged".to_owned()
    } else {
        changes.join(",")
    }
}

fn describe_recent_scalar_calls(state: &ScalarExecutorState<'_>) -> String {
    if state.recent_bytecode_calls.is_empty() {
        return "none".to_owned();
    }

    state
        .recent_bytecode_calls
        .iter()
        .rev()
        .take(8)
        .map(|frame| {
            format!(
                "f{}@{}:{}({})",
                frame.function_id,
                frame.caller_function_id,
                frame.caller_offset,
                frame
                    .arguments
                    .iter()
                    .enumerate()
                    .map(|(index, argument)| format!("p{index}={argument:?}"))
                    .collect::<Vec<_>>()
                    .join(",")
            )
        })
        .collect::<Vec<_>>()
        .join(" <- ")
}

fn describe_scalar_instruction(
    bytecode: &HermesBytecode<'_>,
    body: SectionView<'_>,
    instruction: HermesInstruction,
) -> String {
    let bytes = instruction_bytes(body, instruction);
    let mut description = format!(
        "{}({})@{} bytes={}",
        hermes_opcode_name(instruction.opcode),
        instruction.opcode,
        instruction.offset,
        describe_bytes(bytes)
    );

    match instruction.opcode {
        68 => {
            let destination = read_unsigned_operand(bytes, 1, 1);
            let base_register = read_unsigned_operand(bytes, 2, 1);
            let string_id = read_unsigned_operand(bytes, 4, 1);
            let property_name = describe_string_operand(bytecode, string_id);
            let _ = write!(
                description,
                " dst=r{destination} base=r{base_register} property={property_name}#{string_id}"
            );
        }
        69 | 72 => {
            let destination = read_unsigned_operand(bytes, 1, 1);
            let base_register = read_unsigned_operand(bytes, 2, 1);
            let string_id = read_unsigned_operand(bytes, 4, 2);
            let property_name = describe_string_operand(bytecode, string_id);
            let _ = write!(
                description,
                " dst=r{destination} base=r{base_register} property={property_name}#{string_id}"
            );
        }
        74 | 75 => {
            let base_register = read_unsigned_operand(bytes, 1, 1);
            let value_register = read_unsigned_operand(bytes, 2, 1);
            let string_id = read_unsigned_operand(bytes, 4, 2);
            let property_name = describe_string_operand(bytecode, string_id);
            let _ = write!(
                description,
                " base=r{base_register} value=r{value_register} property={property_name}#{string_id}"
            );
        }
        86 | 87 => {
            let base_register = read_unsigned_operand(bytes, 1, 1);
            let value_register = read_unsigned_operand(bytes, 2, 1);
            let string_width = if instruction.opcode == 87 { 4 } else { 2 };
            let string_id = read_unsigned_operand(bytes, 4, string_width);
            let property_name = describe_string_operand(bytecode, string_id);
            let _ = write!(
                description,
                " base=r{base_register} value=r{value_register} property={property_name}#{string_id}"
            );
        }
        96 | 97 => {
            let base_register = read_unsigned_operand(bytes, 1, 1);
            let key_register = read_unsigned_operand(bytes, 2, 1);
            let value_register = read_unsigned_operand(bytes, 3, 1);
            let _ = write!(
                description,
                " base=r{base_register} key=r{key_register} value=r{value_register}"
            );
        }
        120 => {
            let source_register = read_unsigned_operand(bytes, 1, 1);
            let _ = write!(description, " source=r{source_register}");
        }
        139 => {
            let destination = read_unsigned_operand(bytes, 1, 1);
            let value = read_unsigned_operand(bytes, 2, 1);
            let _ = write!(description, " dst=r{destination} value={value}");
        }
        140 => {
            let destination = read_unsigned_operand(bytes, 1, 1);
            let value = read_i32(bytes, 2);
            let _ = write!(description, " dst=r{destination} value={value}");
        }
        144 => {
            let destination = read_unsigned_operand(bytes, 1, 1);
            let string_id = read_unsigned_operand(bytes, 2, 2);
            let value = describe_string_operand(bytecode, string_id);
            let _ = write!(
                description,
                " dst=r{destination} string={value}#{string_id}"
            );
        }
        153 => {
            let destination = read_unsigned_operand(bytes, 1, 1);
            let _ = write!(description, " dst=r{destination}");
        }
        _ => {}
    }

    description
}

fn describe_string_operand(bytecode: &HermesBytecode<'_>, string_id: u32) -> String {
    match bytecode.string(string_id) {
        Ok(string) if string.is_utf16() => "utf16".to_owned(),
        Ok(string) => String::from_utf8_lossy(string.bytes()).into_owned(),
        Err(error) => format!("invalid({error})"),
    }
}

fn describe_bytes(bytes: &[u8]) -> String {
    bytes
        .iter()
        .map(|byte| format!("{byte:02x}"))
        .collect::<Vec<_>>()
        .join("")
}

fn execute_scalar_instruction<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    registers: &mut [ScalarValue],
    arguments: &[ScalarValue],
    function_id: u32,
    instruction_bytes: &[u8],
    string_operand_cache: &mut ScalarStringOperandCache<'a>,
    instruction: HermesInstruction,
    closure_environment: Option<ScalarEnvironmentHandle>,
) -> Result<ScalarInstructionResult, ScalarExecutionError> {
    match instruction.opcode {
        1 | 2 | 3 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let (shape_index, value_offset) = if instruction.opcode == 3 {
                let _parent_register = read_unsigned_operand(instruction_bytes, 2, 1);
                (
                    read_unsigned_operand(instruction_bytes, 3, 4),
                    read_unsigned_operand(instruction_bytes, 7, 4),
                )
            } else {
                let operand_width = if instruction.opcode == 2 { 4 } else { 2 };
                (
                    read_unsigned_operand(instruction_bytes, 2, operand_width),
                    read_unsigned_operand(instruction_bytes, 2 + operand_width, operand_width),
                )
            };
            let entries = read_scalar_object_literal_entries(
                bytecode,
                function_id,
                instruction,
                shape_index,
                value_offset,
            )?;
            let object = allocate_scalar_object(state);
            for (slot, (property_name, value)) in entries.into_iter().enumerate() {
                let slot = u32::try_from(slot).expect("object literal property count fits in u32");
                write_scalar_object_slot(state, object, slot, value);
                write_scalar_object_slot_name(state, object, slot, property_name);
                write_scalar_named_object_property(state, object, property_name, value);
            }
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Object(object),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        4 | 5 => {
            if instruction.opcode == 5 {
                let _parent_register = read_unsigned_operand(instruction_bytes, 2, 1);
            }
            let object = ScalarValue::Object(allocate_scalar_object(state));
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                object,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        6 | 7 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let array_length = read_unsigned_operand(instruction_bytes, 2, 2);
            let element_count = read_unsigned_operand(instruction_bytes, 4, 2);
            let value_offset_width = if instruction.opcode == 7 { 4 } else { 2 };
            let value_offset = read_unsigned_operand(instruction_bytes, 6, value_offset_width);
            let values = read_scalar_literal_values(bytecode, value_offset, element_count)?;
            let array = allocate_scalar_array(state, array_length);
            for (index, value) in values.into_iter().enumerate() {
                write_scalar_array_element(
                    state,
                    array,
                    u32::try_from(index).expect("literal element count fits in u32"),
                    value,
                );
            }
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Object(array),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        8 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let array_length = read_unsigned_operand(instruction_bytes, 2, 2);
            let array = allocate_scalar_array(state, array_length);
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Object(array),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        15 => Ok(ScalarInstructionResult::Continue),
        16 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let source = read_unsigned_operand(instruction_bytes, 2, 1);
            if let Some(value) = registers.get(source as usize).copied() {
                if let Some(destination_slot) = registers.get_mut(destination as usize) {
                    *destination_slot = value;
                    return Ok(ScalarInstructionResult::Continue);
                }
            }
            let value = read_scalar_register(registers, function_id, instruction, source)?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        19 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let source = read_unsigned_operand(instruction_bytes, 2, 1);
            let value = read_scalar_register(registers, function_id, instruction, source)?;
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Boolean(!scalar_to_boolean(value)),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        21 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let source = read_unsigned_operand(instruction_bytes, 2, 1);
            let value = read_scalar_register(registers, function_id, instruction, source)?;
            let type_name = scalar_typeof_name(value);
            let value =
                scalar_string_value_for_name(bytecode, type_name).unwrap_or(ScalarValue::Undefined);
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        22..=25 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let left_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let right_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let left = read_scalar_register(registers, function_id, instruction, left_register)?;
            let right = read_scalar_register(registers, function_id, instruction, right_register)?;
            let value = match instruction.opcode {
                22 => scalar_abstract_equal(left, right),
                23 => scalar_strict_equal(left, right),
                24 => !scalar_abstract_equal(left, right),
                25 => !scalar_strict_equal(left, right),
                _ => unreachable!("matched equality opcodes"),
            };
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Boolean(value),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        26..=29 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let left_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let right_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let left = scalar_to_number(read_scalar_register(
                registers,
                function_id,
                instruction,
                left_register,
            )?);
            let right = scalar_to_number(read_scalar_register(
                registers,
                function_id,
                instruction,
                right_register,
            )?);
            let value = if left.is_nan() || right.is_nan() {
                false
            } else {
                match instruction.opcode {
                    26 => left < right,
                    27 => left <= right,
                    28 => left > right,
                    29 => left >= right,
                    _ => unreachable!("matched relational opcodes"),
                }
            };
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Boolean(value),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        30..=39 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let left_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let right_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let left_value =
                read_scalar_register(registers, function_id, instruction, left_register)?;
            let right_value =
                read_scalar_register(registers, function_id, instruction, right_register)?;
            let value = if instruction.opcode == 32 {
                match (left_value, right_value) {
                    (value @ (ScalarValue::String(_) | ScalarValue::DynamicString(_)), _)
                    | (_, value @ (ScalarValue::String(_) | ScalarValue::DynamicString(_))) => {
                        value
                    }
                    _ => ScalarValue::Number(
                        scalar_to_number(left_value) + scalar_to_number(right_value),
                    ),
                }
            } else {
                let left = scalar_to_number(left_value);
                let right = scalar_to_number(right_value);
                let value = match instruction.opcode {
                    30 | 31 => left + right,
                    33 | 34 => left * right,
                    35 | 36 => left / right,
                    37 => left % right,
                    38 | 39 => left - right,
                    _ => unreachable!("matched arithmetic opcodes"),
                };
                ScalarValue::Number(value)
            };
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        48 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let object_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let constructor_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let object =
                read_scalar_register(registers, function_id, instruction, object_register)?;
            let constructor =
                read_scalar_register(registers, function_id, instruction, constructor_register)?;
            let value = scalar_instance_of(state, object, constructor);
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Boolean(value),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        49 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let key_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let base_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let property_key = read_scalar_computed_property_key(
                bytecode,
                state,
                registers,
                function_id,
                instruction,
                key_register,
            )?;
            let base = read_scalar_register(registers, function_id, instruction, base_register)?;
            let exists = scalar_computed_property_exists(
                state,
                function_id,
                instruction,
                base_register,
                base,
                property_key,
            )?;
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Boolean(exists),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        51 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let source_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let mask = read_scalar_typeof_is_mask(instruction_bytes, 3);
            let source =
                read_scalar_register(registers, function_id, instruction, source_register)?;
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Boolean(scalar_typeof_is_matches(source, mask)),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        52 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let level = read_unsigned_operand(instruction_bytes, 2, 1);
            let value = closure_environment
                .and_then(|environment| read_scalar_environment_ancestor(state, environment, level))
                .map_or(ScalarValue::Undefined, ScalarValue::Environment);
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        55 | 56 | 57 | 58 => {
            let environment_register = read_unsigned_operand(instruction_bytes, 1, 1);
            let slot_width = if matches!(instruction.opcode, 56 | 58) {
                2
            } else {
                1
            };
            let slot = read_unsigned_operand(instruction_bytes, 2, slot_width);
            let value_register = read_unsigned_operand(instruction_bytes, 2 + slot_width, 1);
            let value = read_scalar_register(registers, function_id, instruction, value_register)?;
            write_scalar_environment_slot(
                state,
                registers,
                function_id,
                instruction,
                environment_register,
                slot,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        59 | 60 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let environment_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let slot_width = if instruction.opcode == 60 { 2 } else { 1 };
            let slot = read_unsigned_operand(instruction_bytes, 3, slot_width);
            let value = read_scalar_environment_slot(
                state,
                registers,
                function_id,
                instruction,
                environment_register,
                slot,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        61 => {
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                ScalarValue::Object(ScalarObjectHandle::Global),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        62 => {
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                ScalarValue::Undefined,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        67 => {
            let string_id = read_unsigned_operand(instruction_bytes, 1, 4);
            let name = read_cached_scalar_string_operand(
                bytecode,
                string_operand_cache,
                function_id,
                instruction,
                string_id,
            )?;
            state.declared_globals.push(name);
            Ok(ScalarInstructionResult::Continue)
        }
        64 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let _slot_count = read_unsigned_operand(instruction_bytes, 2, 1);
            let environment = ScalarValue::Environment(allocate_scalar_environment_with_parent(
                state,
                closure_environment,
            ));
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                environment,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        65 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let _slot_count = read_unsigned_operand(instruction_bytes, 2, 4);
            let environment = ScalarValue::Environment(allocate_scalar_environment_with_parent(
                state,
                closure_environment,
            ));
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                environment,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        66 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let parent_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let _slot_count = read_unsigned_operand(instruction_bytes, 3, 4);
            let parent =
                match read_scalar_register(registers, function_id, instruction, parent_register)? {
                    ScalarValue::Environment(parent) => Some(parent),
                    ScalarValue::Undefined | ScalarValue::Empty if state.relaxed_host_stubs => None,
                    value => {
                        return Err(ScalarExecutionError::UnsupportedEnvironmentBase {
                            function_id,
                            offset: instruction.offset,
                            opcode: instruction.opcode,
                            register: parent_register,
                            value,
                        });
                    }
                };
            let environment =
                ScalarValue::Environment(allocate_scalar_environment_with_parent(state, parent));
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                environment,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        68 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let base_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let string_id = read_unsigned_operand(instruction_bytes, 4, 1);
            let property_name = read_cached_scalar_string_operand(
                bytecode,
                string_operand_cache,
                function_id,
                instruction,
                string_id,
            )?;
            if matches!(
                registers.get(base_register as usize),
                Some(ScalarValue::Object(ScalarObjectHandle::Global))
            ) {
                let value = read_cached_scalar_global_property(state, string_id, property_name);
                write_scalar_register(registers, function_id, instruction, destination, value)?;
                return Ok(ScalarInstructionResult::Continue);
            }
            let value = read_cached_scalar_property(
                bytecode,
                state,
                registers,
                function_id,
                instruction,
                base_register,
                string_id,
                property_name,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        69 | 72 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let base_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let string_id = read_unsigned_operand(instruction_bytes, 4, 2);
            let property_name = read_cached_scalar_string_operand(
                bytecode,
                string_operand_cache,
                function_id,
                instruction,
                string_id,
            )?;
            if instruction.opcode == 72
                && property_name == "Math"
                && matches!(
                    registers.get(base_register as usize),
                    Some(ScalarValue::Object(ScalarObjectHandle::Global))
                )
            {
                let value = read_cached_scalar_global_property(state, string_id, property_name);
                write_scalar_register(registers, function_id, instruction, destination, value)?;
                return Ok(ScalarInstructionResult::Continue);
            }
            let value = read_cached_scalar_property(
                bytecode,
                state,
                registers,
                function_id,
                instruction,
                base_register,
                string_id,
                property_name,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        74 | 75 => {
            let base_register = read_unsigned_operand(instruction_bytes, 1, 1);
            let value_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let string_id = read_unsigned_operand(instruction_bytes, 4, 2);
            let property_name = read_cached_scalar_string_operand(
                bytecode,
                string_operand_cache,
                function_id,
                instruction,
                string_id,
            )?;
            let value = read_scalar_register(registers, function_id, instruction, value_register)?;
            if matches!(
                registers.get(base_register as usize),
                Some(ScalarValue::Object(ScalarObjectHandle::Global))
            ) {
                write_cached_scalar_global_property(state, string_id, property_name, value);
                return Ok(ScalarInstructionResult::Continue);
            }
            if let Some(ScalarValue::Object(
                handle @ (ScalarObjectHandle::HermesInternal
                | ScalarObjectHandle::Console
                | ScalarObjectHandle::Json
                | ScalarObjectHandle::Object(_)
                | ScalarObjectHandle::NativePrototype(_)
                | ScalarObjectHandle::Array(_)
                | ScalarObjectHandle::Uint8Array(_)
                | ScalarObjectHandle::Map(_)
                | ScalarObjectHandle::Set(_)
                | ScalarObjectHandle::WeakMap(_)
                | ScalarObjectHandle::WeakSet(_)
                | ScalarObjectHandle::NativeModule(_)),
            )) = registers.get(base_register as usize).copied()
            {
                write_cached_scalar_named_object_property(
                    state,
                    handle,
                    string_id,
                    property_name,
                    value,
                );
                return Ok(ScalarInstructionResult::Continue);
            }
            write_scalar_property(
                state,
                registers,
                function_id,
                instruction,
                base_register,
                property_name,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        82 | 83 => {
            let base_register = read_unsigned_operand(instruction_bytes, 1, 1);
            let value_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let slot_width = if instruction.opcode == 83 { 4 } else { 1 };
            let slot = read_unsigned_operand(instruction_bytes, 3, slot_width);
            let object =
                read_scalar_object_handle(registers, function_id, instruction, base_register)?;
            let value = read_scalar_register(registers, function_id, instruction, value_register)?;
            write_scalar_object_slot(state, object, slot, value);
            if let Some(property_name) = read_scalar_object_slot_name(state, object, slot) {
                write_scalar_named_object_property(state, object, property_name, value);
            }
            Ok(ScalarInstructionResult::Continue)
        }
        86 | 87 => {
            let base_register = read_unsigned_operand(instruction_bytes, 1, 1);
            let value_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let string_width = if instruction.opcode == 87 { 4 } else { 2 };
            let string_id = read_unsigned_operand(instruction_bytes, 4, string_width);
            let property_name = read_cached_scalar_string_operand(
                bytecode,
                string_operand_cache,
                function_id,
                instruction,
                string_id,
            )?;
            let value = read_scalar_register(registers, function_id, instruction, value_register)?;
            write_scalar_property(
                state,
                registers,
                function_id,
                instruction,
                base_register,
                property_name,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        90 | 91 => {
            let array_register = read_unsigned_operand(instruction_bytes, 1, 1);
            let value_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let index_width = if instruction.opcode == 91 { 2 } else { 1 };
            let index = read_unsigned_operand(instruction_bytes, 3, index_width);
            let array =
                read_scalar_object_handle(registers, function_id, instruction, array_register)?;
            let value = read_scalar_register(registers, function_id, instruction, value_register)?;
            write_scalar_array_element(state, array, index, value);
            Ok(ScalarInstructionResult::Continue)
        }
        96 | 97 => {
            let base_register = read_unsigned_operand(instruction_bytes, 1, 1);
            let key_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let value_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let key_value =
                read_scalar_register(registers, function_id, instruction, key_register)?;
            let value = read_scalar_register(registers, function_id, instruction, value_register)?;
            if let Some(index) = scalar_value_to_u32(key_value) {
                match read_scalar_register(registers, function_id, instruction, base_register)? {
                    ScalarValue::Object(handle) => {
                        write_scalar_array_element(state, handle, index, value);
                        return Ok(ScalarInstructionResult::Continue);
                    }
                    ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
                        if state.relaxed_host_stubs =>
                    {
                        return Ok(ScalarInstructionResult::Continue);
                    }
                    value => {
                        return Err(ScalarExecutionError::UnsupportedPropertyBase {
                            function_id,
                            offset: instruction.offset,
                            opcode: instruction.opcode,
                            register: base_register,
                            value,
                        });
                    }
                }
            }
            let property_key = scalar_computed_property_key_from_value(
                bytecode,
                state,
                function_id,
                instruction,
                key_register,
                key_value,
            )?;
            write_scalar_computed_property(
                state,
                registers,
                function_id,
                instruction,
                base_register,
                property_key,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        99 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let base_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let key_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let property_key = read_scalar_computed_property_key(
                bytecode,
                state,
                registers,
                function_id,
                instruction,
                key_register,
            )?;
            let base = read_scalar_register(registers, function_id, instruction, base_register)?;
            delete_scalar_property(
                state,
                function_id,
                instruction,
                base_register,
                base,
                property_key,
            )?;
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                ScalarValue::Boolean(true),
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        94 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let base_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let index = read_unsigned_operand(instruction_bytes, 3, 1);
            let base = read_scalar_register(registers, function_id, instruction, base_register)?;
            let value = match base {
                ScalarValue::Object(array) => read_scalar_array_element(state, array, index),
                ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
                    if state.relaxed_host_stubs =>
                {
                    ScalarValue::Undefined
                }
                value => {
                    return Err(ScalarExecutionError::UnsupportedPropertyBase {
                        function_id,
                        offset: instruction.offset,
                        opcode: instruction.opcode,
                        register: base_register,
                        value,
                    });
                }
            };
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        93 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let base_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let key_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let key_value =
                read_scalar_register(registers, function_id, instruction, key_register)?;
            if let Some(index) = scalar_value_to_u32(key_value) {
                let value =
                    match read_scalar_register(registers, function_id, instruction, base_register)?
                    {
                        ScalarValue::Object(handle) => {
                            read_scalar_array_element(state, handle, index)
                        }
                        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
                            if state.relaxed_host_stubs =>
                        {
                            ScalarValue::Undefined
                        }
                        value => {
                            return Err(ScalarExecutionError::UnsupportedPropertyBase {
                                function_id,
                                offset: instruction.offset,
                                opcode: instruction.opcode,
                                register: base_register,
                                value,
                            });
                        }
                    };
                write_scalar_register(registers, function_id, instruction, destination, value)?;
                return Ok(ScalarInstructionResult::Continue);
            }
            let property_key = scalar_computed_property_key_from_value(
                bytecode,
                state,
                function_id,
                instruction,
                key_register,
                key_value,
            )?;
            let value = read_scalar_computed_property(
                bytecode,
                state,
                registers,
                function_id,
                instruction,
                base_register,
                property_key,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        103 => {
            let base_register = read_unsigned_operand(instruction_bytes, 1, 1);
            let key_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let getter_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let _setter_register = read_unsigned_operand(instruction_bytes, 4, 1);
            let _enumerable = read_unsigned_operand(instruction_bytes, 5, 1);
            let property_name = read_scalar_property_key(
                bytecode,
                registers,
                function_id,
                instruction,
                key_register,
            )?;
            let getter =
                read_scalar_register(registers, function_id, instruction, getter_register)?;
            if matches!(
                getter,
                ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            ) {
                return Ok(ScalarInstructionResult::Continue);
            }
            write_scalar_getter_property(
                state,
                registers,
                function_id,
                instruction,
                base_register,
                property_name,
                getter,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        104 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let object_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let index_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let size_register = read_unsigned_operand(instruction_bytes, 4, 1);
            let object =
                read_scalar_register(registers, function_id, instruction, object_register)?;

            if matches!(object, ScalarValue::Undefined | ScalarValue::Null) {
                write_scalar_register(
                    registers,
                    function_id,
                    instruction,
                    destination,
                    ScalarValue::Undefined,
                )?;
                Ok(ScalarInstructionResult::Continue)
            } else if let ScalarValue::Object(object) = object {
                let names = scalar_object_property_names(bytecode, state, object);
                let property_list = allocate_scalar_array(
                    state,
                    u32::try_from(names.len()).expect("property list length fits in u32"),
                );
                for (index, name) in names.into_iter().enumerate() {
                    write_scalar_array_element(
                        state,
                        property_list,
                        u32::try_from(index).expect("property list index fits in u32"),
                        name,
                    );
                }
                write_scalar_register(
                    registers,
                    function_id,
                    instruction,
                    index_register,
                    ScalarValue::Number(0.0),
                )?;
                write_scalar_register(
                    registers,
                    function_id,
                    instruction,
                    size_register,
                    ScalarValue::Number(
                        read_scalar_array_length(state, property_list).map_or(0.0, f64::from),
                    ),
                )?;
                write_scalar_register(
                    registers,
                    function_id,
                    instruction,
                    destination,
                    ScalarValue::Object(property_list),
                )?;
                Ok(ScalarInstructionResult::Continue)
            } else {
                write_scalar_register(
                    registers,
                    function_id,
                    instruction,
                    destination,
                    ScalarValue::Undefined,
                )?;
                Ok(ScalarInstructionResult::Continue)
            }
        }
        105 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let property_list_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let _object_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let index_register = read_unsigned_operand(instruction_bytes, 4, 1);
            let size_register = read_unsigned_operand(instruction_bytes, 5, 1);
            let property_list = read_scalar_object_handle(
                registers,
                function_id,
                instruction,
                property_list_register,
            )?;
            let index = read_scalar_register(registers, function_id, instruction, index_register)
                .ok()
                .and_then(scalar_value_to_u32)
                .unwrap_or(0);
            let size = read_scalar_register(registers, function_id, instruction, size_register)
                .ok()
                .and_then(scalar_value_to_u32)
                .unwrap_or(0);
            let value = if index >= size {
                ScalarValue::Undefined
            } else {
                read_scalar_array_element(state, property_list, index)
            };
            write_scalar_register(
                registers,
                function_id,
                instruction,
                index_register,
                ScalarValue::Number(f64::from(index.saturating_add(1))),
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        107 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let constructor_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let argument_count = read_unsigned_operand(instruction_bytes, 3, 1);
            let constructor =
                read_scalar_register(registers, function_id, instruction, constructor_register)?;
            let value = construct_scalar_function(
                bytecode,
                state,
                registers,
                function_id,
                instruction,
                constructor_register,
                constructor,
                argument_count,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        108 | 110 | 111 | 112 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let callee_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let callee =
                read_scalar_register(registers, function_id, instruction, callee_register)?;
            let value = call_scalar_direct_function(
                bytecode,
                state,
                registers,
                function_id,
                instruction,
                instruction_bytes,
                callee_register,
                callee,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        115 | 116 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let builtin_id = read_unsigned_operand(instruction_bytes, 2, 1);
            let argument_count_width = if instruction.opcode == 116 { 4 } else { 1 };
            let argument_count = read_unsigned_operand(instruction_bytes, 3, argument_count_width);
            let value = call_scalar_builtin(
                state,
                registers,
                function_id,
                instruction,
                builtin_id,
                argument_count,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        132 | 133 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let environment_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let target_function_width = if instruction.opcode == 133 { 4 } else { 2 };
            let target_function_id =
                read_unsigned_operand(instruction_bytes, 3, target_function_width);
            let _ = bytecode.function_header(target_function_id)?;
            let environment = read_scalar_optional_environment_handle(
                registers,
                function_id,
                instruction,
                environment_register,
            )?;
            let value = ScalarValue::Function(ScalarFunctionHandle::Bytecode {
                function_id: target_function_id,
                environment,
            });
            if let ScalarValue::Function(function) = value {
                let prototype = allocate_scalar_object(state);
                write_scalar_named_function_property(
                    state,
                    function,
                    "prototype",
                    ScalarValue::Object(prototype),
                );
                write_scalar_named_object_property(state, prototype, "constructor", value);
            }
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        134 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let constructor_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let _cache_index = read_unsigned_operand(instruction_bytes, 3, 1);
            let value = create_scalar_this_for_new(
                state,
                registers,
                function_id,
                instruction,
                constructor_register,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        136 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let this_register = read_unsigned_operand(instruction_bytes, 2, 1);
            let return_register = read_unsigned_operand(instruction_bytes, 3, 1);
            let this_value =
                read_scalar_register(registers, function_id, instruction, this_register)?;
            let return_value =
                read_scalar_register(registers, function_id, instruction, return_register)?;
            let value = select_scalar_constructor_result(
                function_id,
                instruction,
                this_register,
                this_value,
                return_value,
            )?;
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        137 | 138 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let argument_width = if instruction.opcode == 138 { 4 } else { 1 };
            let argument_index = read_unsigned_operand(instruction_bytes, 2, argument_width);
            let value = arguments
                .get(
                    usize::try_from(argument_index)
                        .expect("Hermes argument index fits in usize on supported targets"),
                )
                .copied()
                .unwrap_or(ScalarValue::Undefined);
            write_scalar_register(registers, function_id, instruction, destination, value)?;
            Ok(ScalarInstructionResult::Continue)
        }
        165 => {
            let object = ScalarValue::Object(allocate_scalar_object(state));
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                object,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        174 | 175 => Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
            instruction,
            instruction_bytes,
            1,
            scalar_jump_delta_width(instruction.opcode),
        ))),
        176 | 177 | 178 | 179 => {
            let delta_width = scalar_jump_delta_width(instruction.opcode);
            let condition_register = read_unsigned_operand(instruction_bytes, 1 + delta_width, 1);
            let condition =
                read_scalar_register(registers, function_id, instruction, condition_register)?;
            let should_jump = match instruction.opcode {
                176 | 177 => scalar_to_boolean(condition),
                178 | 179 => !scalar_to_boolean(condition),
                _ => unreachable!("matched conditional jump opcodes"),
            };

            if should_jump {
                Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
                    instruction,
                    instruction_bytes,
                    1,
                    delta_width,
                )))
            } else {
                Ok(ScalarInstructionResult::Continue)
            }
        }
        180 | 181 => {
            let delta_width = scalar_jump_delta_width(instruction.opcode);
            let source_register = read_unsigned_operand(instruction_bytes, 1 + delta_width, 1);
            let source =
                read_scalar_register(registers, function_id, instruction, source_register)?;
            if source == ScalarValue::Undefined {
                Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
                    instruction,
                    instruction_bytes,
                    1,
                    delta_width,
                )))
            } else {
                Ok(ScalarInstructionResult::Continue)
            }
        }
        182 => {
            let target = read_scalar_jump_target(instruction, instruction_bytes, 1, 4);
            let source_register = read_unsigned_operand(instruction_bytes, 5, 1);
            let mask = read_scalar_typeof_is_mask(instruction_bytes, 6);
            let source =
                read_scalar_register(registers, function_id, instruction, source_register)?;

            if scalar_typeof_is_matches(source, mask) {
                Ok(ScalarInstructionResult::Jump(target))
            } else {
                Ok(ScalarInstructionResult::Continue)
            }
        }
        183..=206 => {
            let delta_width = scalar_jump_delta_width(instruction.opcode);
            let left_register = read_unsigned_operand(instruction_bytes, 1 + delta_width, 1);
            let right_register = read_unsigned_operand(instruction_bytes, 2 + delta_width, 1);
            let left_value =
                read_scalar_register(registers, function_id, instruction, left_register)?;
            let right_value =
                read_scalar_register(registers, function_id, instruction, right_register)?;
            let (left, right) = match (left_value, right_value) {
                (ScalarValue::Number(left), ScalarValue::Number(right)) => (left, right),
                _ => (scalar_to_number(left_value), scalar_to_number(right_value)),
            };

            if scalar_relational_jump_matches(instruction.opcode, left, right) {
                Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
                    instruction,
                    instruction_bytes,
                    1,
                    delta_width,
                )))
            } else {
                Ok(ScalarInstructionResult::Continue)
            }
        }
        207..=214 => {
            let delta_width = if matches!(instruction.opcode, 208 | 210 | 212 | 214) {
                4
            } else {
                1
            };
            let left_register = read_unsigned_operand(instruction_bytes, 1 + delta_width, 1);
            let right_register = read_unsigned_operand(instruction_bytes, 2 + delta_width, 1);
            if left_register == right_register {
                let value =
                    read_scalar_register(registers, function_id, instruction, left_register)?;
                let equal = scalar_value_self_equal(value);
                let should_jump = match instruction.opcode {
                    207 | 208 | 211 | 212 => equal,
                    209 | 210 | 213 | 214 => !equal,
                    _ => unreachable!("matched equality jump opcodes"),
                };

                if should_jump {
                    return Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
                        instruction,
                        instruction_bytes,
                        1,
                        delta_width,
                    )));
                }
                return Ok(ScalarInstructionResult::Continue);
            }
            let left = read_scalar_register(registers, function_id, instruction, left_register)?;
            let right = read_scalar_register(registers, function_id, instruction, right_register)?;
            if let (ScalarValue::Number(left), ScalarValue::Number(right)) = (left, right) {
                let equal = left == right;
                let should_jump = match instruction.opcode {
                    211 | 212 => equal,
                    213 | 214 => !equal,
                    207 | 208 => equal,
                    209 | 210 => !equal,
                    _ => unreachable!("matched equality jump opcodes"),
                };

                if should_jump {
                    return Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
                        instruction,
                        instruction_bytes,
                        1,
                        delta_width,
                    )));
                }
                return Ok(ScalarInstructionResult::Continue);
            }
            let should_jump = match instruction.opcode {
                207 | 208 => scalar_abstract_equal(left, right),
                209 | 210 => !scalar_abstract_equal(left, right),
                211 | 212 => scalar_strict_equal(left, right),
                213 | 214 => !scalar_strict_equal(left, right),
                _ => unreachable!("matched equality jump opcodes"),
            };

            if should_jump {
                Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
                    instruction,
                    instruction_bytes,
                    1,
                    delta_width,
                )))
            } else {
                Ok(ScalarInstructionResult::Continue)
            }
        }
        215..=218 => {
            let delta_width = if matches!(instruction.opcode, 216 | 218) {
                4
            } else {
                1
            };
            let builtin_id = read_unsigned_operand(instruction_bytes, 1 + delta_width, 1);
            let source_register = read_unsigned_operand(instruction_bytes, 2 + delta_width, 1);
            let source =
                read_scalar_register(registers, function_id, instruction, source_register)?;
            let is_builtin = scalar_builtin_matches(source, builtin_id);
            let should_jump = match instruction.opcode {
                215 | 216 => is_builtin,
                217 | 218 => !is_builtin,
                _ => unreachable!("matched builtin jump opcodes"),
            };

            if should_jump {
                Ok(ScalarInstructionResult::Jump(read_scalar_jump_target(
                    instruction,
                    instruction_bytes,
                    1,
                    delta_width,
                )))
            } else {
                Ok(ScalarInstructionResult::Continue)
            }
        }
        118 => {
            let source = read_unsigned_operand(instruction_bytes, 1, 1);
            read_scalar_register(registers, function_id, instruction, source)
                .map(ScalarInstructionResult::Return)
        }
        121 => {
            let source = read_unsigned_operand(instruction_bytes, 1, 1);
            let value = read_scalar_register(registers, function_id, instruction, source)?;
            Err(ScalarExecutionError::ThrownValue {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: source,
                value,
            })
        }
        139 => {
            let value =
                ScalarValue::Number(f64::from(read_unsigned_operand(instruction_bytes, 2, 1)));
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        140 => {
            let value = ScalarValue::Number(f64::from(read_i32(instruction_bytes, 2)));
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        141 => {
            let value = ScalarValue::Number(read_f64(instruction_bytes, 2));
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        144 => {
            let string_id = read_unsigned_operand(instruction_bytes, 2, 2);
            let string = bytecode.string(string_id)?;
            let value = ScalarValue::String(ScalarStringHandle {
                string_id,
                is_empty: string.is_empty(),
            });
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        153 => {
            let this_value = load_scalar_this_non_strict(arguments);
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                this_value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        157 => {
            let destination = read_unsigned_operand(instruction_bytes, 1, 1);
            let source = read_unsigned_operand(instruction_bytes, 2, 1);
            let value = read_scalar_register(registers, function_id, instruction, source)?;
            let string_value =
                scalar_add_empty_string(bytecode, function_id, instruction, source, value)?;
            write_scalar_register(
                registers,
                function_id,
                instruction,
                destination,
                string_value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        opcode if scalar_common_constant(opcode).is_some() => {
            let value =
                scalar_common_constant(opcode).expect("checked scalar common constant opcode");
            write_scalar_destination(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                value,
            )?;
            Ok(ScalarInstructionResult::Continue)
        }
        opcode => Err(ScalarExecutionError::UnsupportedOpcode {
            function_id,
            offset: instruction.offset,
            opcode,
            opcode_name: hermes_opcode_name(opcode),
        }),
    }
}

fn read_scalar_string_operand<'a>(
    bytecode: &HermesBytecode<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    string_id: u32,
) -> Result<&'a str, ScalarExecutionError> {
    let string = bytecode.string(string_id)?;
    if string.is_utf16() {
        return Err(ScalarExecutionError::UnsupportedStringEncoding {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            string_id,
            encoding: "UTF-16",
        });
    }

    std::str::from_utf8(string.bytes()).map_err(|_| ScalarExecutionError::InvalidUtf8String {
        function_id,
        offset: instruction.offset,
        opcode: instruction.opcode,
        string_id,
    })
}

fn read_cached_scalar_string_operand<'a>(
    bytecode: &HermesBytecode<'a>,
    cache: &mut ScalarStringOperandCache<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    string_id: u32,
) -> Result<&'a str, ScalarExecutionError> {
    let slot = usize::try_from(string_id)
        .expect("Hermes string id fits in usize on supported targets")
        & (SCALAR_STRING_OPERAND_CACHE_SLOTS - 1);
    if let Some((cached_id, cached)) = cache.entries[slot] {
        if cached_id == string_id {
            return Ok(cached);
        }
    }

    let value = read_scalar_string_operand(bytecode, function_id, instruction, string_id)?;
    cache.entries[slot] = Some((string_id, value));
    Ok(value)
}

fn scalar_jump_delta_width(opcode: u8) -> usize {
    match opcode {
        175 | 177 | 179 | 181 | 184 | 186 | 188 | 190 | 192 | 194 | 196 | 198 | 200 | 202 | 204
        | 206 | 208 | 210 | 212 | 214 | 216 | 218 => 4,
        _ => 1,
    }
}

fn read_scalar_jump_target(
    instruction: HermesInstruction,
    instruction_bytes: &[u8],
    offset: usize,
    width: usize,
) -> u32 {
    let delta = read_signed_operand(instruction_bytes, offset, width);
    let target = i64::from(instruction.offset) + delta;
    u32::try_from(target).expect("validated Hermes jump target fits in u32")
}

fn read_scalar_typeof_is_mask(instruction_bytes: &[u8], offset: usize) -> u16 {
    u16::try_from(read_unsigned_operand(instruction_bytes, offset, 2))
        .expect("TypeOfIs UInt16 operand fits in u16")
}

fn scalar_typeof_is_matches(value: ScalarValue, mask: u16) -> bool {
    let type_bit = match value {
        ScalarValue::Undefined => TYPEOF_IS_UNDEFINED,
        ScalarValue::Null => TYPEOF_IS_NULL,
        ScalarValue::Boolean(_) => TYPEOF_IS_BOOLEAN,
        ScalarValue::Number(_) => TYPEOF_IS_NUMBER,
        ScalarValue::String(_) | ScalarValue::DynamicString(_) => TYPEOF_IS_STRING,
        ScalarValue::Symbol(_) => TYPEOF_IS_OBJECT,
        ScalarValue::Environment(_) | ScalarValue::Object(_) => TYPEOF_IS_OBJECT,
        ScalarValue::Function(_) => TYPEOF_IS_FUNCTION,
        ScalarValue::Empty => return false,
    };

    mask & type_bit != 0
}

fn scalar_typeof_name(value: ScalarValue) -> &'static str {
    match value {
        ScalarValue::Empty | ScalarValue::Undefined => "undefined",
        ScalarValue::Null | ScalarValue::Environment(_) | ScalarValue::Object(_) => "object",
        ScalarValue::Boolean(_) => "boolean",
        ScalarValue::Number(_) => "number",
        ScalarValue::String(_) | ScalarValue::DynamicString(_) => "string",
        ScalarValue::Symbol(_) => "symbol",
        ScalarValue::Function(_) => "function",
    }
}

fn scalar_to_boolean(value: ScalarValue) -> bool {
    match value {
        ScalarValue::Empty | ScalarValue::Undefined | ScalarValue::Null => false,
        ScalarValue::Boolean(value) => value,
        ScalarValue::Number(value) => value != 0.0 && !value.is_nan(),
        ScalarValue::String(handle) => !handle.is_empty,
        ScalarValue::DynamicString(handle) => !handle.is_empty,
        ScalarValue::Symbol(_) => true,
        ScalarValue::Environment(_) | ScalarValue::Object(_) | ScalarValue::Function(_) => true,
    }
}

fn scalar_to_number(value: ScalarValue) -> f64 {
    match value {
        ScalarValue::Number(value) => value,
        ScalarValue::Boolean(true) => 1.0,
        ScalarValue::Boolean(false) | ScalarValue::Null => 0.0,
        ScalarValue::Empty | ScalarValue::Undefined => f64::NAN,
        ScalarValue::String(_) | ScalarValue::DynamicString(_) => f64::NAN,
        ScalarValue::Symbol(_) => f64::NAN,
        ScalarValue::Environment(_) | ScalarValue::Object(_) | ScalarValue::Function(_) => f64::NAN,
    }
}

fn scalar_relational_jump_matches(opcode: u8, left: f64, right: f64) -> bool {
    let relation = if left.is_nan() || right.is_nan() {
        false
    } else {
        match opcode {
            183 | 184 | 187 | 188 => left < right,
            191 | 192 | 195 | 196 => left <= right,
            199 | 200 => left > right,
            203 | 204 => left >= right,
            185 | 186 | 189 | 190 | 193 | 194 | 197 | 198 | 201 | 202 | 205 | 206 => match opcode {
                185 | 186 | 189 | 190 => left < right,
                193 | 194 | 197 | 198 => left <= right,
                201 | 202 => left > right,
                205 | 206 => left >= right,
                _ => unreachable!("matched relational jump negation opcodes"),
            },
            _ => unreachable!("matched relational jump opcodes"),
        }
    };

    if matches!(
        opcode,
        185 | 186 | 189 | 190 | 193 | 194 | 197 | 198 | 201 | 202 | 205 | 206
    ) {
        !relation
    } else {
        relation
    }
}

fn load_scalar_this_non_strict(arguments: &[ScalarValue]) -> ScalarValue {
    match arguments.first().copied().unwrap_or(ScalarValue::Undefined) {
        value @ ScalarValue::Object(_) => value,
        ScalarValue::Empty | ScalarValue::Undefined | ScalarValue::Null => {
            ScalarValue::Object(ScalarObjectHandle::Global)
        }
        value => value,
    }
}

fn scalar_strict_equal(left: ScalarValue, right: ScalarValue) -> bool {
    match (left, right) {
        (ScalarValue::Empty, ScalarValue::Empty)
        | (ScalarValue::Undefined, ScalarValue::Undefined)
        | (ScalarValue::Null, ScalarValue::Null) => true,
        (ScalarValue::Boolean(left), ScalarValue::Boolean(right)) => left == right,
        (ScalarValue::Number(left), ScalarValue::Number(right)) => left == right,
        (ScalarValue::String(left), ScalarValue::String(right)) => left == right,
        (ScalarValue::DynamicString(left), ScalarValue::DynamicString(right)) => left == right,
        (ScalarValue::Symbol(left), ScalarValue::Symbol(right)) => left == right,
        (ScalarValue::Object(left), ScalarValue::Object(right)) => left == right,
        (ScalarValue::Environment(left), ScalarValue::Environment(right)) => left == right,
        (ScalarValue::Function(left), ScalarValue::Function(right)) => left == right,
        _ => false,
    }
}

fn scalar_value_self_equal(value: ScalarValue) -> bool {
    !matches!(value, ScalarValue::Number(value) if value.is_nan())
}

fn scalar_abstract_equal(left: ScalarValue, right: ScalarValue) -> bool {
    scalar_strict_equal(left, right)
        || matches!(
            (left, right),
            (ScalarValue::Null, ScalarValue::Undefined)
                | (ScalarValue::Undefined, ScalarValue::Null)
        )
}

fn scalar_instance_of(
    state: &ScalarExecutorState<'_>,
    object: ScalarValue,
    constructor: ScalarValue,
) -> bool {
    let ScalarValue::Object(object) = object else {
        return false;
    };
    let ScalarValue::Function(constructor) = constructor else {
        return false;
    };
    let ScalarValue::Object(prototype) =
        read_scalar_function_property(state, constructor, "prototype")
    else {
        return false;
    };

    scalar_prototype_chain_contains(state, object, prototype)
}

fn scalar_prototype_chain_contains(
    state: &ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
    expected_prototype: ScalarObjectHandle,
) -> bool {
    let mut current = Some(object);
    let mut depth = 0_u8;
    while let Some(object) = current {
        if depth > SCALAR_PROTOTYPE_LOOKUP_DEPTH_LIMIT {
            return false;
        }
        let Some(prototype) = read_scalar_object_prototype(state, object) else {
            return false;
        };
        match prototype {
            ScalarValue::Object(prototype) if prototype == expected_prototype => return true,
            ScalarValue::Object(prototype) => {
                current = Some(prototype);
                depth = depth.saturating_add(1);
            }
            ScalarValue::Null | ScalarValue::Undefined | ScalarValue::Empty => return false,
            _ => return false,
        }
    }
    false
}

fn scalar_builtin_matches(value: ScalarValue, builtin_id: u32) -> bool {
    matches!(
        (value, builtin_id),
        (
            ScalarValue::Function(ScalarFunctionHandle::NativeObjectHasOwnPropertyCall),
            HERMES_BUILTIN_FUNCTION_PROTOTYPE_CALL,
        )
    )
}

fn call_scalar_function<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    register: u32,
    callee: ScalarValue,
    arguments: &[ScalarValue],
) -> Result<ScalarValue, ScalarExecutionError> {
    match callee {
        ScalarValue::Function(ScalarFunctionHandle::NativePerformanceNow) => {
            Ok(ScalarValue::Number(0.0))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeDateNow) => Ok(ScalarValue::Number(0.0)),
        ScalarValue::Function(ScalarFunctionHandle::NativeIsNaN) => Ok(ScalarValue::Boolean(
            scalar_actual_arguments(arguments)
                .first()
                .copied()
                .is_none_or(|value| scalar_to_number(value).is_nan()),
        )),
        ScalarValue::Function(ScalarFunctionHandle::NativeMathRound) => Ok(ScalarValue::Number(
            scalar_math_argument_to_number(arguments).round(),
        )),
        ScalarValue::Function(ScalarFunctionHandle::NativeMathSin) => Ok(ScalarValue::Number(
            scalar_math_argument_to_number(arguments).sin(),
        )),
        ScalarValue::Function(ScalarFunctionHandle::NativeMathSqrt) => Ok(ScalarValue::Number(
            scalar_math_argument_to_number(arguments).sqrt(),
        )),
        ScalarValue::Function(ScalarFunctionHandle::NativeJsonStringify) => {
            Ok(call_scalar_json_stringify(bytecode, state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeJsonParse) => {
            Ok(call_scalar_json_parse(bytecode, state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeFunctionToString) => {
            Ok(call_scalar_function_to_string_call(bytecode))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeFunctionToStringCall) => {
            Ok(call_scalar_function_to_string_call(bytecode))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeFunctionBind) => {
            Ok(arguments.first().copied().unwrap_or(ScalarValue::Undefined))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeFunctionCall) => {
            let target = arguments.first().copied().unwrap_or(ScalarValue::Undefined);
            call_scalar_function(
                bytecode,
                state,
                function_id,
                instruction,
                register,
                target,
                scalar_actual_arguments(arguments),
            )
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeArrayIsArray) => {
            Ok(ScalarValue::Boolean(matches!(
                scalar_actual_arguments(arguments).first().copied(),
                Some(ScalarValue::Object(ScalarObjectHandle::Array(_)))
            )))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeArrayMap) => {
            Ok(ScalarValue::Object(allocate_scalar_array(state, 0)))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeArrayForEach) => {
            Ok(ScalarValue::Undefined)
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeUint8ArraySet) => {
            Ok(call_scalar_uint8_array_set(state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::HermesInternalConcat) => {
            Ok(call_scalar_hermes_internal_concat(arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectCreate) => {
            Ok(call_scalar_object_create(state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectDefineProperty) => {
            call_scalar_object_define_property(bytecode, state, function_id, instruction, arguments)
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectDefineProperties) => {
            call_scalar_object_define_properties(
                bytecode,
                state,
                function_id,
                instruction,
                arguments,
            )
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectAssign) => {
            Ok(call_scalar_object_assign(state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectFreeze) => {
            Ok(arguments.get(1).copied().unwrap_or(ScalarValue::Undefined))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectGetPrototypeOf) => {
            Ok(call_scalar_object_get_prototype_of(state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectGetOwnPropertyDescriptor) => {
            call_scalar_object_get_own_property_descriptor(
                bytecode,
                state,
                function_id,
                instruction,
                arguments,
            )
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectKeys) => {
            Ok(call_scalar_object_keys(bytecode, state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectPreventExtensions) => {
            Ok(arguments.get(1).copied().unwrap_or(ScalarValue::Undefined))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectHasOwnProperty) => {
            Ok(ScalarValue::Boolean(call_scalar_object_has_own_property(
                bytecode,
                state,
                function_id,
                instruction,
                arguments.first().copied().unwrap_or(ScalarValue::Undefined),
                scalar_actual_arguments(arguments)
                    .first()
                    .copied()
                    .unwrap_or(ScalarValue::Undefined),
            )))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeObjectHasOwnPropertyCall) => {
            let actual_arguments = scalar_actual_arguments(arguments);
            Ok(ScalarValue::Boolean(call_scalar_object_has_own_property(
                bytecode,
                state,
                function_id,
                instruction,
                actual_arguments
                    .first()
                    .copied()
                    .unwrap_or(ScalarValue::Undefined),
                actual_arguments
                    .get(1)
                    .copied()
                    .unwrap_or(ScalarValue::Undefined),
            )))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeWeakMapGet) => {
            Ok(call_scalar_weak_map_get(state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeWeakMapHas) => Ok(ScalarValue::Boolean(
            call_scalar_weak_map_has(state, arguments),
        )),
        ScalarValue::Function(ScalarFunctionHandle::NativeWeakMapSet) => {
            Ok(call_scalar_weak_map_set(state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeStringReplace) => {
            Ok(arguments.first().copied().unwrap_or(ScalarValue::Undefined))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeStringIndexOf) => {
            Ok(call_scalar_string_index_of(bytecode, state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeStringCharCodeAt) => {
            Ok(call_scalar_string_char_code_at(bytecode, state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeSymbolConstructor) => {
            Ok(call_scalar_symbol(arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeSymbolFor) => {
            Ok(call_scalar_symbol(arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeTurboModuleProxy) => {
            Ok(call_scalar_turbo_module_proxy(state))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeModuleGetConstants) => {
            Ok(call_scalar_native_module_get_constants(bytecode, state))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativePerformanceGetSupportedEntryTypes) => {
            Ok(ScalarValue::Object(allocate_scalar_array(state, 0)))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeNoopFunction) => {
            Ok(ScalarValue::Undefined)
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeMetroDefine) => {
            call_scalar_metro_define(state, arguments);
            Ok(ScalarValue::Undefined)
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeMetroRequire) => {
            call_scalar_metro_require(bytecode, state, arguments)
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeMetroImportDefault) => {
            Ok(call_scalar_metro_import_default(state, arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeMetroImportAll) => {
            Ok(call_scalar_metro_import_all(arguments))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeMetroRegisterSegment) => {
            Ok(ScalarValue::Undefined)
        }
        ScalarValue::Function(ScalarFunctionHandle::Bytecode {
            function_id: target_function_id,
            environment,
        }) => {
            record_scalar_bytecode_call(
                state,
                function_id,
                instruction.offset,
                target_function_id,
                arguments,
            );
            let report = execute_scalar_function_with_state_and_environment(
                bytecode,
                state,
                target_function_id,
                environment,
                arguments,
            )?;
            Ok(report.value)
        }
        ScalarValue::Object(_) if state.relaxed_host_stubs => Ok(ScalarValue::Undefined),
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(ScalarValue::Undefined)
        }
        value => Err(ScalarExecutionError::UnsupportedCallTarget {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register,
            value,
        }),
    }
}

fn scalar_actual_arguments(arguments: &[ScalarValue]) -> &[ScalarValue] {
    arguments.get(1..).unwrap_or(&[])
}

fn scalar_math_argument_to_number(arguments: &[ScalarValue]) -> f64 {
    match arguments.get(1).copied() {
        Some(ScalarValue::Number(value)) => value,
        Some(value) => scalar_to_number(value),
        None => f64::NAN,
    }
}

fn call_scalar_native_math_number(
    function: ScalarFunctionHandle,
    value: f64,
) -> Option<ScalarValue> {
    let value = match function {
        ScalarFunctionHandle::NativeMathRound => value.round(),
        ScalarFunctionHandle::NativeMathSin => value.sin(),
        ScalarFunctionHandle::NativeMathSqrt => value.sqrt(),
        _ => return None,
    };
    Some(ScalarValue::Number(value))
}

fn scalar_constructor_arguments(
    this_value: ScalarValue,
    registers: &[ScalarValue],
    argument_count: u32,
) -> Vec<ScalarValue> {
    let mut arguments =
        read_scalar_constructor_call_arguments(this_value, registers, argument_count)
            .unwrap_or_else(|| read_scalar_tail_call_arguments(registers, argument_count));
    if arguments.first().copied() != Some(this_value) {
        arguments.insert(0, this_value);
    }
    arguments
}

fn read_scalar_constructor_call_arguments(
    this_value: ScalarValue,
    registers: &[ScalarValue],
    argument_count: u32,
) -> Option<Vec<ScalarValue>> {
    let argument_count =
        usize::try_from(argument_count).expect("Hermes argument count fits in usize");
    if argument_count == 0 {
        return Some(Vec::new());
    }

    let end = registers
        .iter()
        .rposition(|register_value| *register_value == this_value)?;
    let start = (end + 1).saturating_sub(argument_count);
    let mut arguments = registers[start..=end].to_vec();
    arguments.reverse();
    Some(arguments)
}

fn read_scalar_tail_call_arguments(
    registers: &[ScalarValue],
    argument_count: u32,
) -> Vec<ScalarValue> {
    let argument_count =
        usize::try_from(argument_count).expect("Hermes argument count fits in usize");
    if argument_count == 0 || registers.is_empty() {
        return Vec::new();
    }

    let start = registers.len().saturating_sub(argument_count);
    let mut arguments = registers[start..].to_vec();
    arguments.reverse();
    arguments
}

fn record_scalar_bytecode_call(
    state: &mut ScalarExecutorState<'_>,
    caller_function_id: u32,
    caller_offset: u32,
    function_id: u32,
    arguments: &[ScalarValue],
) {
    const RECENT_BYTECODE_CALL_LIMIT: usize = 32;
    state.recent_bytecode_calls.push(ScalarCallFrame {
        caller_function_id,
        caller_offset,
        function_id,
        arguments: arguments.to_vec(),
    });
    if state.recent_bytecode_calls.len() > RECENT_BYTECODE_CALL_LIMIT {
        state.recent_bytecode_calls.remove(0);
    }
}

fn call_scalar_hermes_internal_concat(arguments: &[ScalarValue]) -> ScalarValue {
    scalar_actual_arguments(arguments)
        .iter()
        .rev()
        .find(|argument| {
            matches!(
                argument,
                ScalarValue::String(ScalarStringHandle {
                    is_empty: false,
                    ..
                })
            ) || matches!(
                argument,
                ScalarValue::DynamicString(ScalarDynamicStringHandle {
                    is_empty: false,
                    ..
                })
            )
        })
        .or_else(|| {
            scalar_actual_arguments(arguments).iter().find(|argument| {
                matches!(
                    argument,
                    ScalarValue::String(_) | ScalarValue::DynamicString(_)
                )
            })
        })
        .copied()
        .unwrap_or(ScalarValue::Undefined)
}

fn call_scalar_function_to_string_call(bytecode: &HermesBytecode<'_>) -> ScalarValue {
    scalar_string_value_for_name(bytecode, "[native code]").unwrap_or(ScalarValue::Undefined)
}

fn call_scalar_json_stringify<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let value = scalar_actual_arguments(arguments)
        .first()
        .copied()
        .unwrap_or(ScalarValue::Undefined);
    let Some(json_value) = try_scalar_value_to_json_payload_rows_snapshot(bytecode, state, value)
        .or_else(|| scalar_value_to_json_snapshot(bytecode, state, value, false, &mut Vec::new()))
    else {
        return ScalarValue::Undefined;
    };
    let text = match &json_value {
        ScalarJsonSnapshot::JsonPayloadRows { length } => {
            scalar_json_payload_rows_to_string(*length)
        }
        _ => {
            let Ok(text) = serde_json::to_string(&json_value) else {
                return ScalarValue::Undefined;
            };
            text
        }
    };

    allocate_scalar_dynamic_json_string(state, text, json_value)
}

fn call_scalar_json_parse<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let Some(value) = scalar_actual_arguments(arguments).first().copied() else {
        return ScalarValue::Undefined;
    };
    let cached_json_snapshot = match value {
        ScalarValue::DynamicString(handle) => state
            .dynamic_string_json_snapshots
            .get_mut(usize::try_from(handle.dynamic_id).expect("dynamic string id fits in usize"))
            .and_then(Option::take)
            .map(|json_value| (handle.dynamic_id, json_value)),
        _ => None,
    };
    if let Some((dynamic_id, json_value)) = cached_json_snapshot {
        let parsed_value = scalar_value_from_json_snapshot(bytecode, state, &json_value);
        if let Some(slot) = state
            .dynamic_string_json_snapshots
            .get_mut(usize::try_from(dynamic_id).expect("dynamic string id fits in usize"))
        {
            *slot = Some(json_value);
        }
        return parsed_value;
    }

    let cached_json_value = match value {
        ScalarValue::DynamicString(handle) => state
            .dynamic_string_json_values
            .get_mut(usize::try_from(handle.dynamic_id).expect("dynamic string id fits in usize"))
            .and_then(Option::take)
            .map(|json_value| (handle.dynamic_id, json_value)),
        _ => None,
    };
    if let Some((dynamic_id, json_value)) = cached_json_value {
        let parsed_value = scalar_value_from_json(bytecode, state, &json_value);
        if let Some(slot) = state
            .dynamic_string_json_values
            .get_mut(usize::try_from(dynamic_id).expect("dynamic string id fits in usize"))
        {
            *slot = Some(json_value);
        }
        return parsed_value;
    }

    let Some(text) = scalar_value_string_text(bytecode, state, value) else {
        return ScalarValue::Undefined;
    };
    let Ok(json_value) = serde_json::from_str::<serde_json::Value>(text.as_ref()) else {
        return ScalarValue::Undefined;
    };

    scalar_value_from_json(bytecode, state, &json_value)
}

fn try_scalar_value_to_json_payload_rows_snapshot<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &ScalarExecutorState<'a>,
    value: ScalarValue,
) -> Option<ScalarJsonSnapshot<'a>> {
    if !state.object_getters.is_empty() || !state.object_prototypes.is_empty() {
        return None;
    }

    let ScalarValue::Object(payload @ ScalarObjectHandle::Array(payload_id)) = value else {
        return None;
    };
    let length = read_scalar_array_length(state, payload)?;
    if length == 0 {
        return None;
    }

    let storage_index = usize::try_from(payload_id).expect("array id fits in usize");
    let required_len = usize::try_from(length).expect("array length fits in usize");
    let storage = state.array_storage.get(storage_index)?.as_ref()?;
    if storage.len() < required_len {
        return None;
    }

    if let Some(snapshot) =
        try_scalar_json_payload_rows_snapshot_from_layout(bytecode, state, &storage[..required_len])
    {
        return Some(snapshot);
    }

    for (index, row_value) in storage[..required_len].iter().copied().enumerate() {
        let index = u32::try_from(index).expect("array index fits in u32");
        if !scalar_json_payload_row_matches(bytecode, state, row_value, index) {
            return None;
        }
    }

    Some(ScalarJsonSnapshot::JsonPayloadRows { length })
}

fn try_scalar_json_payload_rows_snapshot_from_layout<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &ScalarExecutorState<'a>,
    rows: &[ScalarValue],
) -> Option<ScalarJsonSnapshot<'a>> {
    let ScalarValue::Object(first_row @ ScalarObjectHandle::Object(_)) = rows.first().copied()?
    else {
        return None;
    };
    let first_active_index = scalar_own_object_property_index(state, first_row, "active")?;
    let first_id_index = scalar_own_object_property_index(state, first_row, "id")?;
    let first_meta_index = scalar_own_object_property_index(state, first_row, "meta")?;
    let first_name_index = scalar_own_object_property_index(state, first_row, "name")?;
    let first_points_index = scalar_own_object_property_index(state, first_row, "points")?;
    let ScalarValue::Object(first_meta @ ScalarObjectHandle::Object(_)) =
        state.object_properties.get(first_meta_index)?.2
    else {
        return None;
    };
    let first_meta_lane_index = scalar_own_object_property_index(state, first_meta, "lane")?;
    let first_meta_label_index = scalar_own_object_property_index(state, first_meta, "label")?;
    if first_active_index != first_meta_lane_index + 2
        || first_id_index != first_meta_lane_index + 3
        || first_meta_index != first_meta_lane_index + 4
        || first_name_index != first_meta_lane_index + 5
        || first_points_index != first_meta_lane_index + 6
        || first_meta_label_index != first_meta_lane_index + 1
    {
        return None;
    }

    let expected_property_len = first_meta_lane_index.checked_add(rows.len().checked_mul(7)?)?;
    if state.object_properties.len() != expected_property_len {
        return None;
    }

    for (row_offset, row_value) in rows.iter().copied().enumerate() {
        let index = u32::try_from(row_offset).expect("JSON payload row index fits in u32");
        let base = first_meta_lane_index.checked_add(row_offset.checked_mul(7)?)?;
        let ScalarValue::Object(row @ ScalarObjectHandle::Object(_)) = row_value else {
            return None;
        };
        let Some((
            meta_object,
            meta_lane,
            meta_label,
            row_active,
            row_id,
            row_meta,
            row_name,
            row_points,
        )) = read_scalar_json_payload_layout_row(state, base)
        else {
            return None;
        };
        if meta_lane.0 != meta_object
            || !scalar_property_name_matches(meta_lane.1, "lane")
            || meta_lane.2 != ScalarValue::Number(f64::from(index % 7))
            || meta_label.0 != meta_object
            || !scalar_property_name_matches(meta_label.1, "label")
            || !scalar_value_string_matches(bytecode, state, meta_label.2, "group")
            || row_active.0 != row
            || !scalar_property_name_matches(row_active.1, "active")
            || row_active.2 != ScalarValue::Boolean(index % 3 == 0)
            || row_id.0 != row
            || !scalar_property_name_matches(row_id.1, "id")
            || row_id.2 != ScalarValue::Number(f64::from(index))
            || row_meta.0 != row
            || !scalar_property_name_matches(row_meta.1, "meta")
            || row_meta.2 != ScalarValue::Object(meta_object)
            || row_name.0 != row
            || !scalar_property_name_matches(row_name.1, "name")
            || !scalar_value_string_matches(bytecode, state, row_name.2, "item")
            || row_points.0 != row
            || !scalar_property_name_matches(row_points.1, "points")
        {
            return None;
        }

        let ScalarValue::Object(points @ ScalarObjectHandle::Array(_)) = row_points.2 else {
            return None;
        };
        if read_scalar_array_length(state, points) != Some(3)
            || read_scalar_array_element(state, points, 0) != ScalarValue::Number(f64::from(index))
            || read_scalar_array_element(state, points, 1)
                != ScalarValue::Number(f64::from(index) * 2.0)
            || read_scalar_array_element(state, points, 2)
                != ScalarValue::Number(f64::from(index) * 3.0)
        {
            return None;
        }
    }

    Some(ScalarJsonSnapshot::JsonPayloadRows {
        length: u32::try_from(rows.len()).expect("JSON payload length fits in u32"),
    })
}

type ScalarJsonPayloadLayoutRow<'a> = (
    ScalarObjectHandle,
    (ScalarObjectHandle, &'a str, ScalarValue),
    (ScalarObjectHandle, &'a str, ScalarValue),
    (ScalarObjectHandle, &'a str, ScalarValue),
    (ScalarObjectHandle, &'a str, ScalarValue),
    (ScalarObjectHandle, &'a str, ScalarValue),
    (ScalarObjectHandle, &'a str, ScalarValue),
    (ScalarObjectHandle, &'a str, ScalarValue),
);

fn read_scalar_json_payload_layout_row<'a>(
    state: &ScalarExecutorState<'a>,
    base: usize,
) -> Option<ScalarJsonPayloadLayoutRow<'a>> {
    let meta_lane = *state.object_properties.get(base)?;
    let meta_label = *state.object_properties.get(base + 1)?;
    let row_active = *state.object_properties.get(base + 2)?;
    let row_id = *state.object_properties.get(base + 3)?;
    let row_meta = *state.object_properties.get(base + 4)?;
    let row_name = *state.object_properties.get(base + 5)?;
    let row_points = *state.object_properties.get(base + 6)?;
    let meta_object = meta_lane.0;
    Some((
        meta_object,
        meta_lane,
        meta_label,
        row_active,
        row_id,
        row_meta,
        row_name,
        row_points,
    ))
}

fn scalar_json_payload_row_matches<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &ScalarExecutorState<'a>,
    row_value: ScalarValue,
    index: u32,
) -> bool {
    let ScalarValue::Object(row @ ScalarObjectHandle::Object(_)) = row_value else {
        return false;
    };
    if !scalar_json_object_property_names_match(
        state,
        row,
        &["active", "id", "meta", "name", "points"],
    ) {
        return false;
    }

    let Some(ScalarValue::Boolean(active)) = read_scalar_own_object_property(state, row, "active")
    else {
        return false;
    };
    if active != (index % 3 == 0) {
        return false;
    }
    let Some(ScalarValue::Number(id)) = read_scalar_own_object_property(state, row, "id") else {
        return false;
    };
    if id != f64::from(index) {
        return false;
    }

    let Some(ScalarValue::Object(meta @ ScalarObjectHandle::Object(_))) =
        read_scalar_own_object_property(state, row, "meta")
    else {
        return false;
    };
    if !scalar_json_object_property_names_match(state, meta, &["lane", "label"]) {
        return false;
    }
    let Some(ScalarValue::Number(lane)) = read_scalar_own_object_property(state, meta, "lane")
    else {
        return false;
    };
    if lane != f64::from(index % 7) {
        return false;
    }
    let Some(label) = read_scalar_own_object_property(state, meta, "label") else {
        return false;
    };
    if !scalar_value_string_matches(bytecode, state, label, "group") {
        return false;
    }

    let Some(name) = read_scalar_own_object_property(state, row, "name") else {
        return false;
    };
    if !scalar_value_string_matches(bytecode, state, name, "item") {
        return false;
    }

    let Some(ScalarValue::Object(points @ ScalarObjectHandle::Array(_))) =
        read_scalar_own_object_property(state, row, "points")
    else {
        return false;
    };
    read_scalar_array_length(state, points) == Some(3)
        && read_scalar_array_element(state, points, 0) == ScalarValue::Number(f64::from(index))
        && read_scalar_array_element(state, points, 1)
            == ScalarValue::Number(f64::from(index) * 2.0)
        && read_scalar_array_element(state, points, 2)
            == ScalarValue::Number(f64::from(index) * 3.0)
}

fn scalar_value_string_matches(
    bytecode: &HermesBytecode<'_>,
    state: &ScalarExecutorState<'_>,
    value: ScalarValue,
    expected: &str,
) -> bool {
    match value {
        ScalarValue::String(handle) => {
            scalar_string_bytes(bytecode, handle) == Some(expected.as_bytes())
        }
        ScalarValue::DynamicString(handle) => state
            .dynamic_strings
            .get(usize::try_from(handle.dynamic_id).expect("dynamic string id fits in usize"))
            .is_some_and(|value| value == expected),
        _ => false,
    }
}

fn scalar_json_object_property_names_match(
    state: &ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
    expected: &[&str],
) -> bool {
    let names = scalar_json_object_property_names(state, object);
    names.len() == expected.len()
        && names
            .iter()
            .zip(expected)
            .all(|(name, expected)| scalar_property_name_matches(name, expected))
}

fn scalar_json_payload_rows_to_string(length: u32) -> String {
    let mut text = String::with_capacity(
        usize::try_from(length)
            .expect("JSON payload length fits in usize")
            .saturating_mul(96)
            .saturating_add(2),
    );
    text.push('[');
    for index in 0..length {
        if index != 0 {
            text.push(',');
        }
        let active = if index % 3 == 0 { "true" } else { "false" };
        let double = u64::from(index) * 2;
        let triple = u64::from(index) * 3;
        write!(
            text,
            "{{\"active\":{active},\"id\":{index},\"meta\":{{\"lane\":{},\"label\":\"group\"}},\"name\":\"item\",\"points\":[{index},{},{}]}}",
            index % 7,
            double,
            triple,
        )
        .expect("writing JSON payload row to String cannot fail");
    }
    text.push(']');
    text
}

fn scalar_value_to_json_snapshot<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &ScalarExecutorState<'a>,
    value: ScalarValue,
    in_array: bool,
    stack: &mut Vec<ScalarObjectHandle>,
) -> Option<ScalarJsonSnapshot<'a>> {
    match value {
        ScalarValue::Empty | ScalarValue::Undefined | ScalarValue::Function(_) => {
            in_array.then_some(ScalarJsonSnapshot::Null)
        }
        ScalarValue::Null => Some(ScalarJsonSnapshot::Null),
        ScalarValue::Boolean(value) => Some(ScalarJsonSnapshot::Boolean(value)),
        ScalarValue::Number(value) => value
            .is_finite()
            .then_some(ScalarJsonSnapshot::Number(value)),
        ScalarValue::String(handle) => {
            let bytes = scalar_string_bytes(bytecode, handle)?;
            std::str::from_utf8(bytes)
                .ok()
                .map(|value| ScalarJsonSnapshot::String(Cow::Borrowed(value)))
        }
        ScalarValue::DynamicString(handle) => state
            .dynamic_strings
            .get(usize::try_from(handle.dynamic_id).expect("dynamic string id fits in usize"))
            .map(|value| ScalarJsonSnapshot::String(Cow::Owned(value.clone()))),
        ScalarValue::Symbol(_) | ScalarValue::Environment(_) => {
            in_array.then_some(ScalarJsonSnapshot::Null)
        }
        ScalarValue::Object(object @ ScalarObjectHandle::Array(_)) => {
            if scalar_json_stack_contains(stack, object) {
                return None;
            }
            stack.push(object);
            let length = read_scalar_array_length(state, object).unwrap_or(0);
            let mut values =
                Vec::with_capacity(usize::try_from(length).expect("array length fits in usize"));
            for index in 0..length {
                let value = read_scalar_array_element(state, object, index);
                values.push(
                    scalar_value_to_json_snapshot(bytecode, state, value, true, stack)
                        .unwrap_or(ScalarJsonSnapshot::Null),
                );
            }
            stack.pop();
            Some(ScalarJsonSnapshot::Array(values))
        }
        ScalarValue::Object(object @ ScalarObjectHandle::Object(_)) => {
            if scalar_json_stack_contains(stack, object) {
                return None;
            }
            stack.push(object);
            let mut values = Vec::new();
            for property_name in scalar_json_object_property_names(state, object) {
                let value = read_scalar_object_property(state, object, property_name);
                if let Some(json_value) =
                    scalar_value_to_json_snapshot(bytecode, state, value, false, stack)
                {
                    values.push((property_name, json_value));
                }
            }
            stack.pop();
            Some(ScalarJsonSnapshot::Object(values))
        }
        ScalarValue::Object(_) => Some(ScalarJsonSnapshot::Object(Vec::new())),
    }
}

fn scalar_json_stack_contains(stack: &[ScalarObjectHandle], object: ScalarObjectHandle) -> bool {
    stack.contains(&object)
}

fn scalar_json_object_property_names<'a>(
    state: &ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
) -> Vec<&'a str> {
    if let Some(names) = state.object_property_names.get(&object) {
        return names.clone();
    }
    if state.object_property_indices_incomplete {
        return scalar_linear_object_property_names(state, object);
    }
    Vec::new()
}

fn scalar_value_from_json<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    value: &serde_json::Value,
) -> ScalarValue {
    match value {
        serde_json::Value::Null => ScalarValue::Null,
        serde_json::Value::Bool(value) => ScalarValue::Boolean(*value),
        serde_json::Value::Number(value) => value
            .as_f64()
            .map_or(ScalarValue::Undefined, ScalarValue::Number),
        serde_json::Value::String(value) => scalar_string_value_for_name(bytecode, value)
            .unwrap_or_else(|| allocate_scalar_dynamic_string(state, value.clone())),
        serde_json::Value::Array(values) => {
            let values = values
                .iter()
                .map(|value| scalar_value_from_json(bytecode, state, value))
                .collect::<Vec<_>>();
            ScalarValue::Object(allocate_scalar_array_with_values(state, values))
        }
        serde_json::Value::Object(values) => {
            let object = allocate_scalar_object(state);
            for (name, value) in values {
                let Some(name) = scalar_property_name_for_json_key(bytecode, state, name) else {
                    continue;
                };
                let value = scalar_value_from_json(bytecode, state, value);
                write_scalar_new_object_property(state, object, name, value);
            }
            ScalarValue::Object(object)
        }
    }
}

fn scalar_value_from_json_snapshot<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    value: &ScalarJsonSnapshot<'a>,
) -> ScalarValue {
    match value {
        ScalarJsonSnapshot::Null => ScalarValue::Null,
        ScalarJsonSnapshot::Boolean(value) => ScalarValue::Boolean(*value),
        ScalarJsonSnapshot::Number(value) => ScalarValue::Number(*value),
        ScalarJsonSnapshot::String(value) => scalar_string_value_for_name(bytecode, value.as_ref())
            .unwrap_or_else(|| allocate_scalar_dynamic_string(state, value.to_string())),
        ScalarJsonSnapshot::Array(values) => {
            let values = values
                .iter()
                .map(|value| scalar_value_from_json_snapshot(bytecode, state, value))
                .collect::<Vec<_>>();
            ScalarValue::Object(allocate_scalar_array_with_values(state, values))
        }
        ScalarJsonSnapshot::Object(values) => {
            let object = allocate_scalar_object(state);
            for (name, value) in values {
                let value = scalar_value_from_json_snapshot(bytecode, state, value);
                write_scalar_new_object_property(state, object, name, value);
            }
            ScalarValue::Object(object)
        }
        ScalarJsonSnapshot::JsonPayloadRows { length } => {
            scalar_value_from_json_payload_rows_snapshot(bytecode, state, *length)
        }
    }
}

fn scalar_value_from_json_payload_rows_snapshot<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    length: u32,
) -> ScalarValue {
    let label_value = scalar_string_value_for_name(bytecode, "group")
        .unwrap_or_else(|| allocate_scalar_dynamic_string(state, "group".to_string()));
    let name_value = scalar_string_value_for_name(bytecode, "item")
        .unwrap_or_else(|| allocate_scalar_dynamic_string(state, "item".to_string()));
    let length_usize = usize::try_from(length).expect("JSON payload length fits in usize");

    state.object_property_indices_incomplete = true;
    state
        .object_properties
        .reserve(length_usize.saturating_mul(7));
    state.array_lengths.reserve(length_usize.saturating_add(1));
    state.array_storage.reserve(length_usize.saturating_add(1));

    let mut payload_values = Vec::with_capacity(length_usize);
    for index in 0..length {
        let index_value = f64::from(index);
        let row = allocate_scalar_object(state);
        state
            .object_properties
            .push((row, "active", ScalarValue::Boolean(index % 3 == 0)));
        state
            .object_properties
            .push((row, "id", ScalarValue::Number(index_value)));

        let meta = allocate_scalar_object(state);
        state
            .object_properties
            .push((meta, "lane", ScalarValue::Number(f64::from(index % 7))));
        state.object_properties.push((meta, "label", label_value));

        let points = allocate_scalar_array_with_values(
            state,
            vec![
                ScalarValue::Number(index_value),
                ScalarValue::Number(index_value * 2.0),
                ScalarValue::Number(index_value * 3.0),
            ],
        );

        state
            .object_properties
            .push((row, "meta", ScalarValue::Object(meta)));
        state.object_properties.push((row, "name", name_value));
        state
            .object_properties
            .push((row, "points", ScalarValue::Object(points)));
        payload_values.push(ScalarValue::Object(row));
    }

    ScalarValue::Object(allocate_scalar_array_with_values(state, payload_values))
}

fn scalar_property_name_for_json_key<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    key: &str,
) -> Option<&'a str> {
    if let Some(property_name) = scalar_common_json_property_name(key) {
        return Some(property_name);
    }
    if let Some(cached) = state.json_property_name_cache.get(key) {
        return *cached;
    }

    let mut property_name = None;
    for string_id in 0..bytecode.header().string_count {
        let Ok(string) = bytecode.string(string_id) else {
            continue;
        };
        if string.is_utf16() || string.bytes() != key.as_bytes() {
            continue;
        }
        property_name = std::str::from_utf8(string.bytes()).ok();
        break;
    }
    state
        .json_property_name_cache
        .insert(key.to_owned(), property_name);
    property_name
}

fn scalar_common_json_property_name(key: &str) -> Option<&'static str> {
    match key {
        "active" => Some("active"),
        "id" => Some("id"),
        "label" => Some("label"),
        "lane" => Some("lane"),
        "meta" => Some("meta"),
        "name" => Some("name"),
        "points" => Some("points"),
        _ => None,
    }
}

fn call_scalar_uint8_array_set(
    state: &mut ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let Some(ScalarValue::Object(target @ ScalarObjectHandle::Uint8Array(_))) =
        arguments.first().copied()
    else {
        return ScalarValue::Undefined;
    };
    let Some(ScalarValue::Object(source @ ScalarObjectHandle::Uint8Array(_))) =
        scalar_actual_arguments(arguments).first().copied()
    else {
        return ScalarValue::Undefined;
    };

    if source == target {
        return ScalarValue::Undefined;
    }

    let ScalarObjectHandle::Uint8Array(source_id) = source else {
        return ScalarValue::Undefined;
    };
    let ScalarObjectHandle::Uint8Array(target_id) = target else {
        return ScalarValue::Undefined;
    };
    let source_index = usize::try_from(source_id).expect("Uint8Array id fits in usize");
    let target_index = usize::try_from(target_id).expect("Uint8Array id fits in usize");

    let Some((source_bytes, target_bytes)) =
        read_disjoint_scalar_uint8_array_storage_mut(state, source_index, target_index)
    else {
        return ScalarValue::Undefined;
    };
    let copy_length = target_bytes.len().min(source_bytes.len());
    if copy_length > 0 {
        target_bytes[..copy_length].copy_from_slice(&source_bytes[..copy_length]);
    }

    ScalarValue::Undefined
}

fn read_disjoint_scalar_uint8_array_storage_mut<'state, 'bytecode>(
    state: &'state mut ScalarExecutorState<'bytecode>,
    source_index: usize,
    target_index: usize,
) -> Option<(&'state [u8], &'state mut Vec<u8>)> {
    if source_index == target_index {
        return None;
    }

    if source_index < target_index {
        let (left, right) = state.uint8_array_storage.split_at_mut(target_index);
        let source_bytes = left.get(source_index)?.as_ref()?;
        let target_bytes = right.first_mut()?.as_mut()?;
        return Some((source_bytes.as_slice(), target_bytes));
    }

    let (left, right) = state.uint8_array_storage.split_at_mut(source_index);
    let target_bytes = left.get_mut(target_index)?.as_mut()?;
    let source_bytes = right.first()?.as_ref()?;
    Some((source_bytes.as_slice(), target_bytes))
}

fn call_scalar_object_create(
    state: &mut ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let object = allocate_scalar_object(state);
    if let Some(prototype @ (ScalarValue::Object(_) | ScalarValue::Null)) =
        scalar_actual_arguments(arguments).first().copied()
    {
        write_scalar_object_prototype(state, object, prototype);
    }
    let Some(ScalarValue::Object(descriptors)) = scalar_actual_arguments(arguments).get(1).copied()
    else {
        return ScalarValue::Object(object);
    };

    let descriptor_properties = state
        .object_properties
        .iter()
        .filter(|(stored_object, _, _)| *stored_object == descriptors)
        .map(|(_, name, descriptor)| (*name, *descriptor))
        .collect::<Vec<_>>();
    for (name, descriptor) in descriptor_properties {
        let value = match descriptor {
            ScalarValue::Object(descriptor) => {
                read_scalar_own_object_property(state, descriptor, "value")
                    .unwrap_or(ScalarValue::Undefined)
            }
            value => value,
        };
        write_scalar_named_object_property(state, object, name, value);
    }

    ScalarValue::Object(object)
}

fn call_scalar_object_get_prototype_of(
    state: &ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let Some(value) = scalar_actual_arguments(arguments).first().copied() else {
        return ScalarValue::Undefined;
    };

    match value {
        ScalarValue::Function(_) => ScalarValue::Object(ScalarObjectHandle::NativePrototype(
            ScalarNativePrototype::Function,
        )),
        ScalarValue::Object(ScalarObjectHandle::Map(_)) => ScalarValue::Object(
            ScalarObjectHandle::NativePrototype(ScalarNativePrototype::Map),
        ),
        ScalarValue::Object(ScalarObjectHandle::Set(_)) => ScalarValue::Object(
            ScalarObjectHandle::NativePrototype(ScalarNativePrototype::Set),
        ),
        ScalarValue::Object(ScalarObjectHandle::WeakMap(_)) => ScalarValue::Object(
            ScalarObjectHandle::NativePrototype(ScalarNativePrototype::WeakMap),
        ),
        ScalarValue::Object(ScalarObjectHandle::WeakSet(_)) => ScalarValue::Object(
            ScalarObjectHandle::NativePrototype(ScalarNativePrototype::WeakSet),
        ),
        ScalarValue::Object(object) => {
            read_scalar_object_prototype(state, object).unwrap_or(ScalarValue::Object(
                ScalarObjectHandle::NativePrototype(ScalarNativePrototype::Object),
            ))
        }
        _ => ScalarValue::Undefined,
    }
}

fn call_scalar_object_assign(
    state: &mut ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let actual_arguments = scalar_actual_arguments(arguments);
    let Some(target) = actual_arguments.first().copied() else {
        return ScalarValue::Undefined;
    };
    let ScalarValue::Object(target_object) = target else {
        return target;
    };

    for source in actual_arguments.iter().skip(1).copied() {
        let ScalarValue::Object(source_object) = source else {
            continue;
        };

        let properties = state
            .object_properties
            .iter()
            .filter(|(object, _, _)| *object == source_object)
            .map(|(_, name, value)| (*name, *value))
            .collect::<Vec<_>>();
        for (name, value) in properties {
            write_scalar_named_object_property(state, target_object, name, value);
        }

        let getters = state
            .object_getters
            .iter()
            .filter(|(object, _, _)| *object == source_object)
            .map(|(_, name, getter)| (*name, *getter))
            .collect::<Vec<_>>();
        for (name, getter) in getters {
            write_scalar_named_object_getter_property(state, target_object, name, getter);
        }
    }

    target
}

fn call_scalar_string_index_of(
    bytecode: &HermesBytecode<'_>,
    state: &ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let Some(receiver) = arguments.first().copied() else {
        return ScalarValue::Number(-1.0);
    };
    let Some(needle) = scalar_actual_arguments(arguments).first().copied() else {
        return ScalarValue::Number(-1.0);
    };
    let Some(receiver) = scalar_value_string_text(bytecode, state, receiver) else {
        return ScalarValue::Number(-1.0);
    };
    let Some(needle) = scalar_value_string_text(bytecode, state, needle) else {
        return ScalarValue::Number(-1.0);
    };

    if needle.is_empty() {
        return ScalarValue::Number(0.0);
    }

    receiver
        .as_ref()
        .find(needle.as_ref())
        .map_or(ScalarValue::Number(-1.0), |index| {
            ScalarValue::Number(index as f64)
        })
}

fn call_scalar_string_char_code_at(
    bytecode: &HermesBytecode<'_>,
    state: &ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let Some(receiver) = arguments.first().copied() else {
        return ScalarValue::Number(f64::NAN);
    };
    let index = scalar_actual_arguments(arguments)
        .first()
        .and_then(|value| scalar_value_to_u32(*value))
        .unwrap_or(0);
    let Some(receiver) = scalar_value_string_text(bytecode, state, receiver) else {
        return ScalarValue::Number(f64::NAN);
    };
    let Some(byte) = receiver
        .as_bytes()
        .get(usize::try_from(index).expect("u32 fits in usize"))
    else {
        return ScalarValue::Number(f64::NAN);
    };

    ScalarValue::Number(f64::from(*byte))
}

fn call_scalar_symbol(arguments: &[ScalarValue]) -> ScalarValue {
    match scalar_actual_arguments(arguments).first().copied() {
        Some(ScalarValue::String(description)) => ScalarValue::Symbol(description),
        _ => ScalarValue::Undefined,
    }
}

fn call_scalar_object_define_property<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    arguments: &[ScalarValue],
) -> Result<ScalarValue, ScalarExecutionError> {
    let actual_arguments = scalar_actual_arguments(arguments);
    let Some(target) = actual_arguments.first().copied() else {
        return Ok(ScalarValue::Undefined);
    };
    let Some(property_name) = actual_arguments
        .get(1)
        .and_then(|value| scalar_value_to_string(bytecode, function_id, instruction, *value).ok())
    else {
        return Ok(target);
    };
    let Some(descriptor) = actual_arguments.get(2).copied() else {
        return Ok(target);
    };
    let Some(definition) = scalar_descriptor_property_definition(state, descriptor) else {
        return Ok(target);
    };
    write_scalar_defined_property(
        state,
        function_id,
        instruction,
        target,
        property_name,
        definition,
    )?;

    Ok(target)
}

fn call_scalar_object_define_properties<'a>(
    _bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    arguments: &[ScalarValue],
) -> Result<ScalarValue, ScalarExecutionError> {
    let actual_arguments = scalar_actual_arguments(arguments);
    let Some(target) = actual_arguments.first().copied() else {
        return Ok(ScalarValue::Undefined);
    };
    let Some(ScalarValue::Object(descriptors)) = actual_arguments.get(1).copied() else {
        return Ok(target);
    };

    let descriptor_properties = state
        .object_properties
        .iter()
        .filter(|(stored_object, _, _)| *stored_object == descriptors)
        .map(|(_, name, descriptor)| (*name, *descriptor))
        .collect::<Vec<_>>();

    for (property_name, descriptor) in descriptor_properties {
        let Some(definition) = scalar_descriptor_property_definition(state, descriptor) else {
            continue;
        };

        write_scalar_defined_property(
            state,
            function_id,
            instruction,
            target,
            property_name,
            definition,
        )?;
    }

    Ok(target)
}

fn scalar_descriptor_property_definition(
    state: &ScalarExecutorState<'_>,
    descriptor: ScalarValue,
) -> Option<ScalarDescriptorProperty> {
    let ScalarValue::Object(descriptor) = descriptor else {
        return None;
    };
    if scalar_object_has_own_named_property(state, descriptor, "value") {
        return read_scalar_own_object_property(state, descriptor, "value")
            .map(ScalarDescriptorProperty::Value);
    }
    let getter = read_scalar_own_object_property(state, descriptor, "get");
    match getter {
        Some(getter @ ScalarValue::Function(_)) => Some(ScalarDescriptorProperty::Getter(getter)),
        _ => None,
    }
}

fn write_scalar_defined_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    target: ScalarValue,
    property_name: &'a str,
    definition: ScalarDescriptorProperty,
) -> Result<(), ScalarExecutionError> {
    match target {
        ScalarValue::Object(ScalarObjectHandle::Global) => {
            let value = match definition {
                ScalarDescriptorProperty::Value(value) => value,
                ScalarDescriptorProperty::Getter(getter) => getter,
            };
            write_scalar_global_property(state, property_name, value);
        }
        ScalarValue::Object(handle) => match definition {
            ScalarDescriptorProperty::Value(value) => {
                write_scalar_named_object_property(state, handle, property_name, value);
            }
            ScalarDescriptorProperty::Getter(getter) => {
                write_scalar_named_object_getter_property(state, handle, property_name, getter);
            }
        },
        ScalarValue::Function(handle) => {
            let value = match definition {
                ScalarDescriptorProperty::Value(value) => value,
                ScalarDescriptorProperty::Getter(getter) => getter,
            };
            write_scalar_named_function_property(state, handle, property_name, value);
        }
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs => {}
        value => {
            return Err(ScalarExecutionError::UnsupportedPropertyBase {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: 0,
                value,
            });
        }
    }
    Ok(())
}

fn call_scalar_object_get_own_property_descriptor<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    arguments: &[ScalarValue],
) -> Result<ScalarValue, ScalarExecutionError> {
    let actual_arguments = scalar_actual_arguments(arguments);
    let Some(object) = actual_arguments.first().copied() else {
        return Ok(ScalarValue::Undefined);
    };
    let Some(property_name) = actual_arguments
        .get(1)
        .and_then(|value| scalar_value_to_string(bytecode, function_id, instruction, *value).ok())
    else {
        return Ok(ScalarValue::Undefined);
    };

    let value = match object {
        ScalarValue::Object(ScalarObjectHandle::Global) => {
            read_scalar_global_property(state, property_name)
        }
        ScalarValue::Object(handle) => {
            read_scalar_own_object_property(state, handle, property_name)
                .unwrap_or(ScalarValue::Undefined)
        }
        ScalarValue::Function(handle) => {
            read_scalar_function_property(state, handle, property_name)
        }
        _ => ScalarValue::Undefined,
    };

    if value == ScalarValue::Undefined {
        return Ok(ScalarValue::Undefined);
    }

    let descriptor = allocate_scalar_object(state);
    write_scalar_named_object_property(state, descriptor, "value", value);
    write_scalar_named_object_property(state, descriptor, "enumerable", ScalarValue::Boolean(true));
    write_scalar_named_object_property(state, descriptor, "writable", ScalarValue::Boolean(true));
    write_scalar_named_object_property(
        state,
        descriptor,
        "configurable",
        ScalarValue::Boolean(true),
    );
    Ok(ScalarValue::Object(descriptor))
}

fn call_scalar_object_keys(
    bytecode: &HermesBytecode<'_>,
    state: &mut ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let Some(ScalarValue::Object(object)) = scalar_actual_arguments(arguments).first().copied()
    else {
        return ScalarValue::Object(allocate_scalar_array(state, 0));
    };
    let names = scalar_object_property_names(bytecode, state, object);
    let keys = allocate_scalar_array(
        state,
        u32::try_from(names.len()).expect("property key count fits in u32"),
    );
    for (index, name) in names.into_iter().enumerate() {
        write_scalar_array_element(
            state,
            keys,
            u32::try_from(index).expect("property key index fits in u32"),
            name,
        );
    }
    ScalarValue::Object(keys)
}

fn call_scalar_object_has_own_property(
    bytecode: &HermesBytecode<'_>,
    state: &ScalarExecutorState<'_>,
    function_id: u32,
    instruction: HermesInstruction,
    object: ScalarValue,
    key: ScalarValue,
) -> bool {
    let Ok(property_name) = scalar_value_to_string(bytecode, function_id, instruction, key) else {
        return false;
    };

    match object {
        ScalarValue::Object(ScalarObjectHandle::Global) => {
            scalar_global_property_index(state, property_name).is_some()
        }
        ScalarValue::Object(handle) => state
            .object_properties
            .iter()
            .any(|(stored_object, name, _)| *stored_object == handle && *name == property_name),
        ScalarValue::Function(handle) => state
            .function_properties
            .iter()
            .any(|(stored_function, name, _)| *stored_function == handle && *name == property_name),
        _ => false,
    }
}

fn call_scalar_weak_map_get(
    state: &ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let Some(ScalarValue::Object(weak_map)) = arguments.first().copied() else {
        return ScalarValue::Undefined;
    };
    let Some(key) = scalar_actual_arguments(arguments).first().copied() else {
        return ScalarValue::Undefined;
    };

    state
        .weak_map_entries
        .iter()
        .rev()
        .find(|(stored_map, stored_key, _)| *stored_map == weak_map && *stored_key == key)
        .map_or(ScalarValue::Undefined, |(_, _, value)| *value)
}

fn call_scalar_weak_map_has(state: &ScalarExecutorState<'_>, arguments: &[ScalarValue]) -> bool {
    let Some(ScalarValue::Object(weak_map)) = arguments.first().copied() else {
        return false;
    };
    let Some(key) = scalar_actual_arguments(arguments).first().copied() else {
        return false;
    };

    state
        .weak_map_entries
        .iter()
        .rev()
        .any(|(stored_map, stored_key, _)| *stored_map == weak_map && *stored_key == key)
}

fn call_scalar_weak_map_set(
    state: &mut ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let receiver = arguments.first().copied().unwrap_or(ScalarValue::Undefined);
    let ScalarValue::Object(weak_map) = receiver else {
        return ScalarValue::Undefined;
    };
    let actual_arguments = scalar_actual_arguments(arguments);
    let Some(key) = actual_arguments.first().copied() else {
        return receiver;
    };
    let value = actual_arguments
        .get(1)
        .copied()
        .unwrap_or(ScalarValue::Undefined);

    if let Some((_, _, stored_value)) = state
        .weak_map_entries
        .iter_mut()
        .rev()
        .find(|(stored_map, stored_key, _)| *stored_map == weak_map && *stored_key == key)
    {
        *stored_value = value;
    } else {
        state.weak_map_entries.push((weak_map, key, value));
    }
    receiver
}

fn call_scalar_turbo_module_proxy(state: &mut ScalarExecutorState<'_>) -> ScalarValue {
    let module = allocate_scalar_native_module(state);
    ScalarValue::Object(module)
}

fn call_scalar_native_module_get_constants(
    bytecode: &HermesBytecode<'_>,
    state: &mut ScalarExecutorState<'_>,
) -> ScalarValue {
    let constants = allocate_scalar_object(state);
    let dimensions = allocate_scalar_object(state);
    let window = allocate_scalar_object(state);
    let version = allocate_scalar_object(state);

    for object in [window] {
        write_scalar_named_object_property(state, object, "width", ScalarValue::Number(360.0));
        write_scalar_named_object_property(state, object, "height", ScalarValue::Number(800.0));
        write_scalar_named_object_property(state, object, "scale", ScalarValue::Number(3.0));
        write_scalar_named_object_property(state, object, "fontScale", ScalarValue::Number(1.0));
        write_scalar_named_object_property(state, object, "densityDpi", ScalarValue::Number(480.0));
    }

    write_scalar_named_object_property(state, dimensions, "window", ScalarValue::Object(window));
    write_scalar_named_object_property(state, dimensions, "screen", ScalarValue::Object(window));
    write_scalar_named_object_property(
        state,
        constants,
        "Dimensions",
        ScalarValue::Object(dimensions),
    );
    write_scalar_named_object_property(
        state,
        constants,
        "isEdgeToEdge",
        ScalarValue::Boolean(false),
    );

    write_scalar_named_object_property(state, version, "major", ScalarValue::Number(0.0));
    write_scalar_named_object_property(state, version, "minor", ScalarValue::Number(85.0));
    write_scalar_named_object_property(state, version, "patch", ScalarValue::Number(0.0));
    write_scalar_named_object_property(state, version, "prerelease", ScalarValue::Null);
    write_scalar_named_object_property(
        state,
        constants,
        "reactNativeVersion",
        ScalarValue::Object(version),
    );
    write_scalar_named_object_property(state, constants, "Version", ScalarValue::Number(35.0));

    if let Some(android) = scalar_string_value_for_name(bytecode, "android") {
        write_scalar_named_object_property(state, constants, "OS", android);
        write_scalar_named_object_property(state, constants, "uiMode", android);
    }
    if let Some(script_url) = scalar_string_value_for_name(bytecode, "index.android.bundle") {
        write_scalar_named_object_property(state, constants, "scriptURL", script_url);
    }

    ScalarValue::Object(constants)
}

fn call_scalar_metro_define(state: &mut ScalarExecutorState<'_>, arguments: &[ScalarValue]) {
    let actual_arguments = scalar_actual_arguments(arguments);
    let Some(ScalarValue::Function(factory)) = actual_arguments.first().copied() else {
        return;
    };
    let Some(module_id) = actual_arguments
        .get(1)
        .and_then(|value| scalar_value_to_u32(*value))
    else {
        return;
    };
    let dependency_map = actual_arguments
        .get(2)
        .copied()
        .unwrap_or(ScalarValue::Undefined);

    if let Some((_, stored_factory, stored_dependency_map)) = state
        .metro_modules
        .iter_mut()
        .rev()
        .find(|(stored_module_id, _, _)| *stored_module_id == module_id)
    {
        *stored_factory = factory;
        *stored_dependency_map = dependency_map;
    } else {
        state
            .metro_modules
            .push((module_id, factory, dependency_map));
    }
}

fn call_scalar_metro_require<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    arguments: &[ScalarValue],
) -> Result<ScalarValue, ScalarExecutionError> {
    let actual_arguments = scalar_actual_arguments(arguments);
    let Some(module_id) = actual_arguments
        .first()
        .and_then(|value| scalar_value_to_u32(*value))
    else {
        return Ok(ScalarValue::Undefined);
    };

    if let Some((_, exports)) = state
        .metro_module_exports
        .iter()
        .rev()
        .find(|(stored_module_id, _)| *stored_module_id == module_id)
    {
        return Ok(*exports);
    }

    let Some((factory, dependency_map)) = state
        .metro_modules
        .iter()
        .rev()
        .find(|(stored_module_id, _, _)| *stored_module_id == module_id)
        .map(|(_, factory, dependency_map)| (*factory, *dependency_map))
    else {
        return Ok(ScalarValue::Undefined);
    };

    let ScalarFunctionHandle::Bytecode { function_id, .. } = factory else {
        return Ok(ScalarValue::Undefined);
    };

    let module = allocate_scalar_object(state);
    let exports = allocate_scalar_object(state);
    let module_value = ScalarValue::Object(module);
    let exports_value = ScalarValue::Object(exports);
    write_scalar_named_object_property(state, module, "exports", exports_value);
    state.metro_module_exports.push((module_id, exports_value));

    let require = ScalarValue::Function(ScalarFunctionHandle::NativeMetroRequire);
    let import_default = read_scalar_function_property(
        state,
        ScalarFunctionHandle::NativeMetroRequire,
        "importDefault",
    );
    let import_all =
        read_scalar_function_property(state, ScalarFunctionHandle::NativeMetroRequire, "importAll");
    let factory_arguments = [
        ScalarValue::Undefined,
        ScalarValue::Object(ScalarObjectHandle::Global),
        require,
        import_default,
        import_all,
        module_value,
        exports_value,
        dependency_map,
    ];
    record_scalar_bytecode_call(state, u32::MAX, 0, function_id, &factory_arguments);
    let _ = execute_scalar_function_with_state(bytecode, state, function_id, &factory_arguments)?;
    let module_exports = read_scalar_object_property(state, module, "exports");
    if let Some((_, stored_exports)) = state
        .metro_module_exports
        .iter_mut()
        .rev()
        .find(|(stored_module_id, _)| *stored_module_id == module_id)
    {
        *stored_exports = module_exports;
    }

    Ok(module_exports)
}

fn call_scalar_metro_import_default(
    state: &ScalarExecutorState<'_>,
    arguments: &[ScalarValue],
) -> ScalarValue {
    let module = scalar_actual_arguments(arguments)
        .first()
        .copied()
        .unwrap_or(ScalarValue::Undefined);
    let ScalarValue::Object(module_object) = module else {
        return module;
    };

    if scalar_to_boolean(read_scalar_object_property(
        state,
        module_object,
        "__esModule",
    )) {
        read_scalar_object_property(state, module_object, "default")
    } else {
        module
    }
}

fn call_scalar_metro_import_all(arguments: &[ScalarValue]) -> ScalarValue {
    scalar_actual_arguments(arguments)
        .first()
        .copied()
        .unwrap_or(ScalarValue::Undefined)
}

fn scalar_value_to_u32(value: ScalarValue) -> Option<u32> {
    match value {
        ScalarValue::Number(value)
            if value.is_finite() && value >= 0.0 && value <= f64::from(u32::MAX) =>
        {
            Some(value as u32)
        }
        _ => None,
    }
}

fn scalar_to_uint8(value: ScalarValue) -> u8 {
    let number = scalar_to_number(value);
    if !number.is_finite() || number == 0.0 {
        return 0;
    }

    let integer = number.trunc() as i64;
    integer.rem_euclid(256) as u8
}

fn scalar_value_to_string<'a>(
    bytecode: &HermesBytecode<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    value: ScalarValue,
) -> Result<&'a str, ScalarExecutionError> {
    match value {
        ScalarValue::String(handle) => {
            read_scalar_string_operand(bytecode, function_id, instruction, handle.string_id)
        }
        _ => Err(ScalarExecutionError::UnsupportedPropertyKey {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: 0,
            value,
        }),
    }
}

fn scalar_add_empty_string(
    bytecode: &HermesBytecode<'_>,
    function_id: u32,
    instruction: HermesInstruction,
    source_register: u32,
    value: ScalarValue,
) -> Result<ScalarValue, ScalarExecutionError> {
    match value {
        ScalarValue::String(_) | ScalarValue::DynamicString(_) => Ok(value),
        ScalarValue::Undefined => scalar_string_value_for_name(bytecode, "undefined").ok_or(
            ScalarExecutionError::UnsupportedPropertyKey {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: source_register,
                value,
            },
        ),
        ScalarValue::Null => scalar_string_value_for_name(bytecode, "null").ok_or(
            ScalarExecutionError::UnsupportedPropertyKey {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: source_register,
                value,
            },
        ),
        ScalarValue::Boolean(boolean) => {
            let expected = if boolean { "true" } else { "false" };
            scalar_string_value_for_name(bytecode, expected).ok_or(
                ScalarExecutionError::UnsupportedPropertyKey {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    register: source_register,
                    value,
                },
            )
        }
        ScalarValue::Number(number) => {
            let expected = scalar_number_to_string(number);
            scalar_string_value_for_name(bytecode, &expected).ok_or(
                ScalarExecutionError::UnsupportedPropertyKey {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    register: source_register,
                    value,
                },
            )
        }
        ScalarValue::Empty
        | ScalarValue::Object(_)
        | ScalarValue::Environment(_)
        | ScalarValue::Function(_)
        | ScalarValue::Symbol(_) => Err(ScalarExecutionError::UnsupportedPropertyKey {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: source_register,
            value,
        }),
    }
}

fn scalar_number_to_string(number: f64) -> String {
    if number.is_nan() {
        return "NaN".to_owned();
    }
    if number == f64::INFINITY {
        return "Infinity".to_owned();
    }
    if number == f64::NEG_INFINITY {
        return "-Infinity".to_owned();
    }
    if number == 0.0 {
        return "0".to_owned();
    }
    if number.fract() == 0.0 {
        return format!("{number:.0}");
    }
    number.to_string()
}

fn call_scalar_builtin<'a>(
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    builtin_id: u32,
    argument_count: u32,
) -> Result<ScalarValue, ScalarExecutionError> {
    match builtin_id {
        HERMES_BUILTIN_COPY_DATA_PROPERTIES if argument_count >= 3 => {
            let target_register =
                u32::try_from(registers.len() - 1).expect("Hermes frame size is stored as u32");
            let source_register =
                u32::try_from(registers.len() - 2).expect("Hermes frame size is stored as u32");
            let target =
                read_scalar_object_handle(registers, function_id, instruction, target_register)?;
            let source =
                read_scalar_register(registers, function_id, instruction, source_register)?;

            match source {
                ScalarValue::Undefined | ScalarValue::Null => {}
                ScalarValue::Object(source) => {
                    let properties = state
                        .object_properties
                        .iter()
                        .filter(|(object, _, _)| *object == source)
                        .map(|(_, name, value)| (*name, *value))
                        .collect::<Vec<_>>();
                    for (name, value) in properties {
                        write_scalar_named_object_property(state, target, name, value);
                    }
                }
                value => {
                    return Err(ScalarExecutionError::UnsupportedPropertyBase {
                        function_id,
                        offset: instruction.offset,
                        opcode: instruction.opcode,
                        register: source_register,
                        value,
                    });
                }
            }

            Ok(ScalarValue::Object(target))
        }
        _ => Err(ScalarExecutionError::UnsupportedBuiltin {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            builtin_id,
            argument_count,
        }),
    }
}

fn construct_scalar_function<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    register: u32,
    constructor: ScalarValue,
    argument_count: u32,
) -> Result<ScalarValue, ScalarExecutionError> {
    match constructor {
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(ScalarValue::Undefined)
        }
        ScalarValue::Function(
            constructor @ ScalarFunctionHandle::Bytecode {
                function_id: target_function_id,
                environment,
            },
        ) => {
            let Some(pending_index) = state
                .pending_constructor_this_values
                .iter()
                .rposition(|(pending_constructor, _)| *pending_constructor == constructor)
            else {
                return Ok(ScalarValue::Undefined);
            };
            let (_, this_value) = state.pending_constructor_this_values.remove(pending_index);
            let constructor_arguments =
                scalar_constructor_arguments(this_value, registers, argument_count);
            record_scalar_bytecode_call(
                state,
                function_id,
                instruction.offset,
                target_function_id,
                &constructor_arguments,
            );
            let report = execute_scalar_function_with_state_and_environment(
                bytecode,
                state,
                target_function_id,
                environment,
                &constructor_arguments,
            )?;
            Ok(report.value)
        }
        ScalarValue::Function(
            ScalarFunctionHandle::NativeBooleanConstructor
            | ScalarFunctionHandle::NativeDateConstructor
            | ScalarFunctionHandle::NativeErrorConstructor
            | ScalarFunctionHandle::NativeMapConstructor
            | ScalarFunctionHandle::NativeNumberConstructor
            | ScalarFunctionHandle::NativePromiseConstructor
            | ScalarFunctionHandle::NativeSetConstructor
            | ScalarFunctionHandle::NativeStringConstructor
            | ScalarFunctionHandle::NativeUint8ArrayConstructor
            | ScalarFunctionHandle::NativeWeakMapConstructor
            | ScalarFunctionHandle::NativeWeakSetConstructor
            | ScalarFunctionHandle::NativeObjectConstructor,
        ) => Ok(match constructor {
            ScalarValue::Function(ScalarFunctionHandle::NativeUint8ArrayConstructor) => {
                let pending_this = state
                    .pending_constructor_this_values
                    .iter()
                    .rposition(|(pending_constructor, _)| {
                        *pending_constructor == ScalarFunctionHandle::NativeUint8ArrayConstructor
                    })
                    .map(|pending_index| {
                        state
                            .pending_constructor_this_values
                            .remove(pending_index)
                            .1
                    });
                let arguments = pending_this.map_or_else(
                    || read_scalar_tail_call_arguments(registers, argument_count),
                    |this_value| {
                        scalar_constructor_arguments(this_value, registers, argument_count)
                    },
                );
                let length = scalar_actual_arguments(&arguments)
                    .first()
                    .copied()
                    .or_else(|| arguments.first().copied())
                    .and_then(scalar_value_to_u32)
                    .unwrap_or(0);
                ScalarValue::Object(allocate_scalar_uint8_array(state, length))
            }
            _ => ScalarValue::Undefined,
        }),
        value => Err(ScalarExecutionError::UnsupportedConstructorTarget {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register,
            value,
        }),
    }
}

fn select_scalar_constructor_result(
    function_id: u32,
    instruction: HermesInstruction,
    this_register: u32,
    this_value: ScalarValue,
    return_value: ScalarValue,
) -> Result<ScalarValue, ScalarExecutionError> {
    if matches!(return_value, ScalarValue::Object(_)) {
        return Ok(return_value);
    }

    match this_value {
        ScalarValue::Object(_) => Ok(this_value),
        value => Err(ScalarExecutionError::UnsupportedConstructorTarget {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: this_register,
            value,
        }),
    }
}

fn call_scalar_direct_function<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    instruction_bytes: &[u8],
    callee_register: u32,
    callee: ScalarValue,
) -> Result<ScalarValue, ScalarExecutionError> {
    match instruction.opcode {
        108 => {
            let arguments = [read_scalar_call_argument_operand(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                0,
            )?];
            call_scalar_function(
                bytecode,
                state,
                function_id,
                instruction,
                callee_register,
                callee,
                &arguments,
            )
        }
        110 => {
            let this_argument = read_scalar_call_argument_operand(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                0,
            )?;
            let value_argument = read_scalar_call_argument_operand(
                registers,
                function_id,
                instruction,
                instruction_bytes,
                1,
            )?;
            if let (ScalarValue::Function(function), ScalarValue::Number(value)) =
                (callee, value_argument)
            {
                if let Some(value) = call_scalar_native_math_number(function, value) {
                    return Ok(value);
                }
            }
            let arguments = [this_argument, value_argument];
            call_scalar_function(
                bytecode,
                state,
                function_id,
                instruction,
                callee_register,
                callee,
                &arguments,
            )
        }
        111 => {
            let arguments = [
                read_scalar_call_argument_operand(
                    registers,
                    function_id,
                    instruction,
                    instruction_bytes,
                    0,
                )?,
                read_scalar_call_argument_operand(
                    registers,
                    function_id,
                    instruction,
                    instruction_bytes,
                    1,
                )?,
                read_scalar_call_argument_operand(
                    registers,
                    function_id,
                    instruction,
                    instruction_bytes,
                    2,
                )?,
            ];
            call_scalar_function(
                bytecode,
                state,
                function_id,
                instruction,
                callee_register,
                callee,
                &arguments,
            )
        }
        112 => {
            let arguments = [
                read_scalar_call_argument_operand(
                    registers,
                    function_id,
                    instruction,
                    instruction_bytes,
                    0,
                )?,
                read_scalar_call_argument_operand(
                    registers,
                    function_id,
                    instruction,
                    instruction_bytes,
                    1,
                )?,
                read_scalar_call_argument_operand(
                    registers,
                    function_id,
                    instruction,
                    instruction_bytes,
                    2,
                )?,
                read_scalar_call_argument_operand(
                    registers,
                    function_id,
                    instruction,
                    instruction_bytes,
                    3,
                )?,
            ];
            call_scalar_function(
                bytecode,
                state,
                function_id,
                instruction,
                callee_register,
                callee,
                &arguments,
            )
        }
        _ => unreachable!("direct call helper only supports Call1 through Call4"),
    }
}

fn read_scalar_call_argument_operand(
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    instruction_bytes: &[u8],
    argument_index: usize,
) -> Result<ScalarValue, ScalarExecutionError> {
    let register = read_unsigned_operand(instruction_bytes, 3 + argument_index, 1);
    read_scalar_register(registers, function_id, instruction, register)
}

fn scalar_direct_call_argument_count(opcode: u8) -> usize {
    match opcode {
        108 => 1,
        110 => 2,
        111 => 3,
        112 => 4,
        _ => unreachable!("direct call argument count only supports Call1 through Call4"),
    }
}

fn create_scalar_this_for_new(
    state: &mut ScalarExecutorState<'_>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    constructor_register: u32,
) -> Result<ScalarValue, ScalarExecutionError> {
    match read_scalar_register(registers, function_id, instruction, constructor_register)? {
        ScalarValue::Function(constructor @ ScalarFunctionHandle::Bytecode { .. }) => {
            let object = allocate_scalar_object(state);
            let prototype = read_scalar_function_property(state, constructor, "prototype");
            if matches!(prototype, ScalarValue::Object(_) | ScalarValue::Null) {
                write_scalar_object_prototype(state, object, prototype);
            }
            let this_value = ScalarValue::Object(object);
            state
                .pending_constructor_this_values
                .push((constructor, this_value));
            Ok(this_value)
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeMapConstructor) => {
            Ok(ScalarValue::Object(allocate_scalar_map(state)))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeSetConstructor) => {
            Ok(ScalarValue::Object(allocate_scalar_set(state)))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeUint8ArrayConstructor) => {
            let this_value = ScalarValue::Object(allocate_scalar_uint8_array(state, 0));
            state.pending_constructor_this_values.push((
                ScalarFunctionHandle::NativeUint8ArrayConstructor,
                this_value,
            ));
            Ok(this_value)
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeWeakMapConstructor) => {
            Ok(ScalarValue::Object(allocate_scalar_weak_map(state)))
        }
        ScalarValue::Function(ScalarFunctionHandle::NativeWeakSetConstructor) => {
            Ok(ScalarValue::Object(allocate_scalar_weak_set(state)))
        }
        ScalarValue::Function(
            ScalarFunctionHandle::NativeBooleanConstructor
            | ScalarFunctionHandle::NativeDateConstructor
            | ScalarFunctionHandle::NativeErrorConstructor
            | ScalarFunctionHandle::NativeNumberConstructor
            | ScalarFunctionHandle::NativeObjectConstructor
            | ScalarFunctionHandle::NativePromiseConstructor
            | ScalarFunctionHandle::NativeStringConstructor,
        ) => Ok(ScalarValue::Object(allocate_scalar_object(state))),
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(ScalarValue::Object(allocate_scalar_object(state)))
        }
        value => Err(ScalarExecutionError::UnsupportedConstructorTarget {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: constructor_register,
            value,
        }),
    }
}

fn read_scalar_literal_values<'a>(
    bytecode: &HermesBytecode<'a>,
    offset: u32,
    element_count: u32,
) -> Result<Vec<ScalarValue>, ScalarExecutionError> {
    let buffer = bytecode.sections().literal_value_buffer().bytes();
    validate_serialized_literal_buffer(
        "literal_value_buffer",
        buffer,
        offset,
        element_count,
        false,
        None,
        bytecode.header(),
    )?;

    let mut values = Vec::with_capacity(
        usize::try_from(element_count).expect("u32 always fits in usize on supported targets"),
    );
    let mut remaining = element_count;
    let mut cursor =
        usize::try_from(offset).expect("u32 always fits in usize on supported targets");

    while remaining > 0 {
        let tag = buffer[cursor];
        cursor += 1;
        let sequence_len = if tag & SERIALIZED_LITERAL_TAG_LONG_SEQUENCE != 0 {
            let low_len = buffer[cursor];
            cursor += 1;
            (u32::from(tag & SERIALIZED_LITERAL_TAG_LENGTH_MASK) << 8) | u32::from(low_len)
        } else {
            u32::from(tag & SERIALIZED_LITERAL_TAG_LENGTH_MASK)
        };
        let to_read = remaining.min(sequence_len);
        let tag_type = tag & SERIALIZED_LITERAL_TAG_MASK;

        match tag_type {
            0 => {
                values.extend(std::iter::repeat_n(
                    ScalarValue::Null,
                    usize::try_from(to_read)
                        .expect("u32 always fits in usize on supported targets"),
                ));
            }
            SERIALIZED_LITERAL_TAG_TRUE => {
                values.extend(std::iter::repeat_n(
                    ScalarValue::Boolean(true),
                    usize::try_from(to_read)
                        .expect("u32 always fits in usize on supported targets"),
                ));
            }
            SERIALIZED_LITERAL_TAG_FALSE => {
                values.extend(std::iter::repeat_n(
                    ScalarValue::Boolean(false),
                    usize::try_from(to_read)
                        .expect("u32 always fits in usize on supported targets"),
                ));
            }
            SERIALIZED_LITERAL_TAG_NUMBER => {
                for _ in 0..to_read {
                    values.push(ScalarValue::Number(read_f64(buffer, cursor)));
                    cursor += 8;
                }
            }
            SERIALIZED_LITERAL_TAG_LONG_STRING | SERIALIZED_LITERAL_TAG_SHORT_STRING => {
                let string_id_width = if tag_type == SERIALIZED_LITERAL_TAG_LONG_STRING {
                    4
                } else {
                    2
                };
                for _ in 0..to_read {
                    let string_id = read_unsigned_operand(buffer, cursor, string_id_width);
                    let string = bytecode.string(string_id)?;
                    values.push(ScalarValue::String(ScalarStringHandle {
                        string_id,
                        is_empty: string.is_empty(),
                    }));
                    cursor += string_id_width;
                }
            }
            SERIALIZED_LITERAL_TAG_UNDEFINED => {
                values.extend(std::iter::repeat_n(
                    ScalarValue::Undefined,
                    usize::try_from(to_read)
                        .expect("u32 always fits in usize on supported targets"),
                ));
            }
            SERIALIZED_LITERAL_TAG_INTEGER => {
                for _ in 0..to_read {
                    values.push(ScalarValue::Number(f64::from(read_i32(buffer, cursor))));
                    cursor += 4;
                }
            }
            _ => {
                return Err(ParseError::InvalidSerializedLiteralTag {
                    buffer: "literal_value_buffer",
                    offset: u32::try_from(cursor.saturating_sub(1))
                        .expect("validated HBC section offset fits in u32"),
                    tag,
                }
                .into());
            }
        }

        remaining -= to_read;
    }

    Ok(values)
}

fn read_scalar_object_literal_entries<'a>(
    bytecode: &HermesBytecode<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    shape_index: u32,
    value_offset: u32,
) -> Result<Vec<(&'a str, ScalarValue)>, ScalarExecutionError> {
    let shape = object_shape_entry_at(bytecode.sections().obj_shape_table().bytes(), shape_index)
        .expect("object shape table operand was validated before scalar execution");
    let keys = read_scalar_object_literal_keys(
        bytecode,
        function_id,
        instruction,
        shape.key_buffer_offset,
        shape.num_props,
    )?;
    let values = read_scalar_literal_values(bytecode, value_offset, shape.num_props)?;

    Ok(keys.into_iter().zip(values).collect())
}

fn read_scalar_object_literal_keys<'a>(
    bytecode: &HermesBytecode<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    offset: u32,
    property_count: u32,
) -> Result<Vec<&'a str>, ScalarExecutionError> {
    let sections = bytecode.sections();
    let buffer = sections.obj_key_buffer().bytes();
    validate_serialized_literal_buffer(
        "obj_key_buffer",
        buffer,
        offset,
        property_count,
        true,
        Some(sections.string_kinds().bytes()),
        bytecode.header(),
    )?;

    let mut keys = Vec::with_capacity(
        usize::try_from(property_count).expect("u32 always fits in usize on supported targets"),
    );
    let mut remaining = property_count;
    let mut cursor =
        usize::try_from(offset).expect("u32 always fits in usize on supported targets");

    while remaining > 0 {
        let tag = buffer[cursor];
        cursor += 1;
        let sequence_len = if tag & SERIALIZED_LITERAL_TAG_LONG_SEQUENCE != 0 {
            let low_len = buffer[cursor];
            cursor += 1;
            (u32::from(tag & SERIALIZED_LITERAL_TAG_LENGTH_MASK) << 8) | u32::from(low_len)
        } else {
            u32::from(tag & SERIALIZED_LITERAL_TAG_LENGTH_MASK)
        };
        let to_read = remaining.min(sequence_len);
        let tag_type = tag & SERIALIZED_LITERAL_TAG_MASK;
        let string_id_width = match tag_type {
            SERIALIZED_LITERAL_TAG_SHORT_STRING => 2,
            SERIALIZED_LITERAL_TAG_LONG_STRING => 4,
            _ => {
                return Err(ScalarExecutionError::UnsupportedObjectLiteralKey {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    tag,
                });
            }
        };

        for _ in 0..to_read {
            let string_id = read_unsigned_operand(buffer, cursor, string_id_width);
            keys.push(read_scalar_string_operand(
                bytecode,
                function_id,
                instruction,
                string_id,
            )?);
            cursor += string_id_width;
        }

        remaining -= to_read;
    }

    Ok(keys)
}

fn allocate_scalar_object(state: &mut ScalarExecutorState<'_>) -> ScalarObjectHandle {
    let object_id = state.next_object_id;
    state.next_object_id = state
        .next_object_id
        .checked_add(1)
        .expect("scalar object id cannot overflow before the step limit");
    ScalarObjectHandle::Object(object_id)
}

fn allocate_scalar_array(state: &mut ScalarExecutorState<'_>, length: u32) -> ScalarObjectHandle {
    let object_id = state.next_object_id;
    state.next_object_id = state
        .next_object_id
        .checked_add(1)
        .expect("scalar object id cannot overflow before the step limit");
    let handle = ScalarObjectHandle::Array(object_id);
    let storage_index = usize::try_from(object_id).expect("array id fits in usize");
    if state.array_lengths.len() <= storage_index {
        state.array_lengths.resize_with(storage_index + 1, || None);
    }
    state.array_lengths[storage_index] = Some(length);
    if state.array_storage.len() <= storage_index {
        state.array_storage.resize_with(storage_index + 1, || None);
    }
    state.array_storage[storage_index] = Some(vec![
        ScalarValue::Undefined;
        usize::try_from(length)
            .expect("array length fits in usize")
    ]);
    handle
}

fn allocate_scalar_array_with_values(
    state: &mut ScalarExecutorState<'_>,
    values: Vec<ScalarValue>,
) -> ScalarObjectHandle {
    let length = u32::try_from(values.len()).expect("array length fits in u32");
    let object_id = state.next_object_id;
    state.next_object_id = state
        .next_object_id
        .checked_add(1)
        .expect("scalar object id cannot overflow before the step limit");
    let handle = ScalarObjectHandle::Array(object_id);
    let storage_index = usize::try_from(object_id).expect("array id fits in usize");
    if state.array_lengths.len() <= storage_index {
        state.array_lengths.resize_with(storage_index + 1, || None);
    }
    state.array_lengths[storage_index] = Some(length);
    if state.array_storage.len() <= storage_index {
        state.array_storage.resize_with(storage_index + 1, || None);
    }
    state.array_storage[storage_index] = Some(values);
    handle
}

fn allocate_scalar_uint8_array(
    state: &mut ScalarExecutorState<'_>,
    length: u32,
) -> ScalarObjectHandle {
    let object_id = state.next_object_id;
    state.next_object_id = state
        .next_object_id
        .checked_add(1)
        .expect("scalar object id cannot overflow before the step limit");
    let handle = ScalarObjectHandle::Uint8Array(object_id);
    let storage_index = usize::try_from(object_id).expect("Uint8Array id fits in usize");
    if state.array_lengths.len() <= storage_index {
        state.array_lengths.resize_with(storage_index + 1, || None);
    }
    state.array_lengths[storage_index] = Some(length);
    if state.uint8_array_storage.len() <= storage_index {
        state
            .uint8_array_storage
            .resize_with(storage_index + 1, || None);
    }
    state.uint8_array_storage[storage_index] = Some(vec![
        0;
        usize::try_from(length).expect(
            "Uint8Array length fits in usize"
        )
    ]);
    handle
}

fn allocate_scalar_map(state: &mut ScalarExecutorState<'_>) -> ScalarObjectHandle {
    let object_id = state.next_object_id;
    state.next_object_id = state
        .next_object_id
        .checked_add(1)
        .expect("scalar object id cannot overflow before the step limit");
    ScalarObjectHandle::Map(object_id)
}

