fn write_scalar_array_element(
    state: &mut ScalarExecutorState<'_>,
    array: ScalarObjectHandle,
    index: u32,
    value: ScalarValue,
) {
    if let ScalarObjectHandle::Uint8Array(object_id) = array {
        let storage_index = usize::try_from(object_id).expect("Uint8Array id fits in usize");
        let Some(storage) = state
            .uint8_array_storage
            .get_mut(storage_index)
            .and_then(Option::as_mut)
        else {
            return;
        };
        let index = usize::try_from(index).expect("Uint8Array index fits in usize");
        if let Some(slot) = storage.get_mut(index) {
            *slot = scalar_to_uint8(value);
        }
        return;
    }

    if let ScalarObjectHandle::Array(object_id) = array {
        let next_length = index.saturating_add(1);
        let storage_index = usize::try_from(object_id).expect("array id fits in usize");
        if state.array_lengths.len() <= storage_index {
            state.array_lengths.resize_with(storage_index + 1, || None);
        }
        match &mut state.array_lengths[storage_index] {
            Some(stored_length) if *stored_length < next_length => {
                *stored_length = next_length;
            }
            Some(_) => {}
            length_slot @ None => {
                *length_slot = Some(next_length);
            }
        }

        if state.array_storage.len() <= storage_index {
            state.array_storage.resize_with(storage_index + 1, || None);
        }
        let storage = state.array_storage[storage_index].get_or_insert_with(Vec::new);
        let index = usize::try_from(index).expect("array index fits in usize");
        if storage.len() <= index {
            storage.resize(index + 1, ScalarValue::Undefined);
        }
        storage[index] = value;
        return;
    }

    if let Some(element_index) = state.array_element_indices.get(&(array, index)).copied() {
        state.array_elements[element_index].2 = value;
    } else {
        state
            .array_element_indices
            .insert((array, index), state.array_elements.len());
        state.array_elements.push((array, index, value));
    }
}

fn read_scalar_array_element(
    state: &ScalarExecutorState<'_>,
    array: ScalarObjectHandle,
    index: u32,
) -> ScalarValue {
    if let ScalarObjectHandle::Uint8Array(object_id) = array {
        let storage_index = usize::try_from(object_id).expect("Uint8Array id fits in usize");
        return state
            .uint8_array_storage
            .get(storage_index)
            .and_then(Option::as_ref)
            .and_then(|storage| {
                storage
                    .get(usize::try_from(index).expect("Uint8Array index fits in usize"))
                    .copied()
            })
            .map_or(ScalarValue::Undefined, |value| {
                ScalarValue::Number(f64::from(value))
            });
    }

    if let ScalarObjectHandle::Array(object_id) = array {
        let storage_index = usize::try_from(object_id).expect("array id fits in usize");
        return state
            .array_storage
            .get(storage_index)
            .and_then(Option::as_ref)
            .and_then(|storage| {
                storage
                    .get(usize::try_from(index).expect("array index fits in usize"))
                    .copied()
            })
            .unwrap_or(ScalarValue::Undefined);
    }

    state
        .array_element_indices
        .get(&(array, index))
        .map_or(ScalarValue::Undefined, |element_index| {
            state.array_elements[*element_index].2
        })
}

fn read_scalar_array_length(
    state: &ScalarExecutorState<'_>,
    array: ScalarObjectHandle,
) -> Option<u32> {
    let storage_index = match array {
        ScalarObjectHandle::Array(object_id) | ScalarObjectHandle::Uint8Array(object_id) => {
            usize::try_from(object_id).expect("array id fits in usize")
        }
        _ => return None,
    };
    state.array_lengths.get(storage_index).copied().flatten()
}

fn reindex_scalar_array_elements(state: &mut ScalarExecutorState<'_>) {
    state.array_element_indices.clear();
    for (index, (object, element_index, _)) in state.array_elements.iter().enumerate() {
        state
            .array_element_indices
            .insert((*object, *element_index), index);
    }
}

fn write_scalar_object_prototype(
    state: &mut ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
    prototype: ScalarValue,
) {
    if let Some((_, stored_prototype)) = state
        .object_prototypes
        .iter_mut()
        .rev()
        .find(|(stored_object, _)| *stored_object == object)
    {
        *stored_prototype = prototype;
    } else {
        state.object_prototypes.push((object, prototype));
    }
}

fn read_scalar_object_prototype(
    state: &ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
) -> Option<ScalarValue> {
    state
        .object_prototypes
        .iter()
        .rev()
        .find(|(stored_object, _)| *stored_object == object)
        .map(|(_, prototype)| *prototype)
}

fn scalar_object_property_names(
    bytecode: &HermesBytecode<'_>,
    state: &ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
) -> Vec<ScalarValue> {
    let names = if let Some(names) = state.object_property_names.get(&object) {
        names.clone()
    } else if state.object_property_indices_incomplete {
        scalar_linear_object_property_names(state, object)
    } else {
        Vec::new()
    };
    names
        .iter()
        .filter_map(|property_name| scalar_string_value_for_name(bytecode, property_name))
        .collect()
}

fn scalar_string_bytes<'a>(
    bytecode: &HermesBytecode<'a>,
    handle: ScalarStringHandle,
) -> Option<&'a [u8]> {
    bytecode
        .string(handle.string_id)
        .ok()
        .filter(|string| !string.is_utf16())
        .map(|string| string.bytes())
}

fn scalar_value_string_text<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &'a ScalarExecutorState<'a>,
    value: ScalarValue,
) -> Option<Cow<'a, str>> {
    match value {
        ScalarValue::String(handle) => {
            let bytes = scalar_string_bytes(bytecode, handle)?;
            std::str::from_utf8(bytes).ok().map(Cow::Borrowed)
        }
        ScalarValue::DynamicString(handle) => state
            .dynamic_strings
            .get(usize::try_from(handle.dynamic_id).expect("dynamic string id fits in usize"))
            .map(|value| Cow::Borrowed(value.as_str())),
        _ => None,
    }
}

fn allocate_scalar_dynamic_string(
    state: &mut ScalarExecutorState<'_>,
    value: String,
) -> ScalarValue {
    let dynamic_id =
        u32::try_from(state.dynamic_strings.len()).expect("dynamic string count fits in u32");
    let is_empty = value.is_empty();
    state.dynamic_strings.push(value);
    state.dynamic_string_json_values.push(None);
    state.dynamic_string_json_snapshots.push(None);
    ScalarValue::DynamicString(ScalarDynamicStringHandle {
        dynamic_id,
        is_empty,
    })
}

fn allocate_scalar_dynamic_json_string<'a>(
    state: &mut ScalarExecutorState<'a>,
    value: String,
    json_value: ScalarJsonSnapshot<'a>,
) -> ScalarValue {
    let dynamic_string = allocate_scalar_dynamic_string(state, value);
    let ScalarValue::DynamicString(handle) = dynamic_string else {
        unreachable!("dynamic string allocator returns a dynamic string");
    };
    if let Some(slot) = state
        .dynamic_string_json_snapshots
        .get_mut(usize::try_from(handle.dynamic_id).expect("dynamic string id fits in usize"))
    {
        *slot = Some(json_value);
    }
    dynamic_string
}

fn scalar_string_value_for_name(
    bytecode: &HermesBytecode<'_>,
    expected: &str,
) -> Option<ScalarValue> {
    for string_id in 0..bytecode.header().string_count {
        let Ok(string) = bytecode.string(string_id) else {
            continue;
        };
        if string.is_utf16() || string.bytes() != expected.as_bytes() {
            continue;
        }
        return Some(ScalarValue::String(ScalarStringHandle {
            string_id,
            is_empty: expected.is_empty(),
        }));
    }
    None
}

fn read_scalar_object_handle(
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    object_register: u32,
) -> Result<ScalarObjectHandle, ScalarExecutionError> {
    match read_scalar_register(registers, function_id, instruction, object_register)? {
        ScalarValue::Object(handle) => Ok(handle),
        value => Err(ScalarExecutionError::UnsupportedPropertyBase {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: object_register,
            value,
        }),
    }
}

fn write_scalar_object_slot(
    state: &mut ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
    slot: u32,
    value: ScalarValue,
) {
    if let Some((_, _, stored_value)) = state
        .object_slots
        .iter_mut()
        .rev()
        .find(|(stored_object, stored_slot, _)| *stored_object == object && *stored_slot == slot)
    {
        *stored_value = value;
    } else {
        state.object_slots.push((object, slot, value));
    }
}

fn write_scalar_object_slot_name<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    slot: u32,
    property_name: &'a str,
) {
    if let Some((_, _, stored_name)) = state
        .object_slot_names
        .iter_mut()
        .rev()
        .find(|(stored_object, stored_slot, _)| *stored_object == object && *stored_slot == slot)
    {
        *stored_name = property_name;
    } else {
        state.object_slot_names.push((object, slot, property_name));
    }
}

fn read_scalar_object_slot_name<'a>(
    state: &ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    slot: u32,
) -> Option<&'a str> {
    state
        .object_slot_names
        .iter()
        .rev()
        .find(|(stored_object, stored_slot, _)| *stored_object == object && *stored_slot == slot)
        .map(|(_, _, property_name)| *property_name)
}

fn read_scalar_object_slot_value(
    state: &ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
    slot: u32,
) -> Option<ScalarValue> {
    state
        .object_slots
        .iter()
        .rev()
        .find(|(stored_object, stored_slot, _)| *stored_object == object && *stored_slot == slot)
        .map(|(_, _, value)| *value)
}

fn allocate_scalar_environment_with_parent(
    state: &mut ScalarExecutorState<'_>,
    parent: Option<ScalarEnvironmentHandle>,
) -> ScalarEnvironmentHandle {
    let environment_id = state.next_environment_id;
    state.next_environment_id = state
        .next_environment_id
        .checked_add(1)
        .expect("scalar environment id cannot overflow before the step limit");
    let handle = ScalarEnvironmentHandle { environment_id };
    state.environment_parents.push((handle, parent));
    handle
}

fn read_scalar_environment_ancestor(
    state: &ScalarExecutorState<'_>,
    environment: ScalarEnvironmentHandle,
    level: u32,
) -> Option<ScalarEnvironmentHandle> {
    let mut current = Some(environment);
    for _ in 0..level {
        current = current.and_then(|current| read_scalar_environment_parent(state, current));
    }
    current
}

fn read_scalar_environment_parent(
    state: &ScalarExecutorState<'_>,
    environment: ScalarEnvironmentHandle,
) -> Option<ScalarEnvironmentHandle> {
    state
        .environment_parents
        .iter()
        .rev()
        .find(|(handle, _)| *handle == environment)
        .and_then(|(_, parent)| *parent)
}

fn read_scalar_environment_slot(
    state: &ScalarExecutorState<'_>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    environment_register: u32,
    slot: u32,
) -> Result<ScalarValue, ScalarExecutionError> {
    let environment_value =
        read_scalar_register(registers, function_id, instruction, environment_register)?;
    let ScalarValue::Environment(environment) = environment_value else {
        return match environment_value {
            ScalarValue::Undefined | ScalarValue::Empty if state.relaxed_host_stubs => {
                Ok(ScalarValue::Undefined)
            }
            value => Err(ScalarExecutionError::UnsupportedEnvironmentBase {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: environment_register,
                value,
            }),
        };
    };
    Ok(state
        .environment_slots
        .iter()
        .rev()
        .find(|(handle, stored_slot, _)| *handle == environment && *stored_slot == slot)
        .map_or(ScalarValue::Empty, |(_, _, value)| *value))
}

fn write_scalar_environment_slot(
    state: &mut ScalarExecutorState<'_>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    environment_register: u32,
    slot: u32,
    value: ScalarValue,
) -> Result<(), ScalarExecutionError> {
    let environment_value =
        read_scalar_register(registers, function_id, instruction, environment_register)?;
    let ScalarValue::Environment(environment) = environment_value else {
        return match environment_value {
            ScalarValue::Undefined | ScalarValue::Empty if state.relaxed_host_stubs => Ok(()),
            value => Err(ScalarExecutionError::UnsupportedEnvironmentBase {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: environment_register,
                value,
            }),
        };
    };
    if let Some((_, _, stored_value)) = state
        .environment_slots
        .iter_mut()
        .rev()
        .find(|(handle, stored_slot, _)| *handle == environment && *stored_slot == slot)
    {
        *stored_value = value;
    } else {
        state.environment_slots.push((environment, slot, value));
    }
    Ok(())
}

fn read_scalar_optional_environment_handle(
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    environment_register: u32,
) -> Result<Option<ScalarEnvironmentHandle>, ScalarExecutionError> {
    match read_scalar_register(registers, function_id, instruction, environment_register)? {
        ScalarValue::Undefined => Ok(None),
        ScalarValue::Environment(environment) => Ok(Some(environment)),
        value => Err(ScalarExecutionError::UnsupportedEnvironmentBase {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: environment_register,
            value,
        }),
    }
}

fn read_scalar_property<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    property_name: &'a str,
) -> Result<ScalarValue, ScalarExecutionError> {
    let base = read_scalar_register(registers, function_id, instruction, base_register)?;
    match base {
        ScalarValue::Object(ScalarObjectHandle::Global) => {
            Ok(read_scalar_global_property(state, property_name))
        }
        ScalarValue::Object(
            handle @ (ScalarObjectHandle::HermesInternal
            | ScalarObjectHandle::Console
            | ScalarObjectHandle::Math
            | ScalarObjectHandle::Json
            | ScalarObjectHandle::Object(_)
            | ScalarObjectHandle::NativePrototype(_)
            | ScalarObjectHandle::Array(_)
            | ScalarObjectHandle::Uint8Array(_)
            | ScalarObjectHandle::Map(_)
            | ScalarObjectHandle::Set(_)
            | ScalarObjectHandle::WeakMap(_)
            | ScalarObjectHandle::WeakSet(_)
            | ScalarObjectHandle::NativeModule(_)),
        ) => read_scalar_object_property_for_get(
            bytecode,
            state,
            function_id,
            instruction,
            ScalarValue::Object(handle),
            handle,
            property_name,
        ),
        ScalarValue::Function(handle) => {
            Ok(read_scalar_function_property(state, handle, property_name))
        }
        value @ (ScalarValue::String(_) | ScalarValue::DynamicString(_)) => Ok(
            read_scalar_string_property(bytecode, state, value, property_name),
        ),
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(ScalarValue::Undefined)
        }
        value => Err(ScalarExecutionError::UnsupportedPropertyBase {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: base_register,
            value,
        }),
    }
}

fn read_cached_scalar_property<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    string_id: u32,
    property_name: &'a str,
) -> Result<ScalarValue, ScalarExecutionError> {
    let Some(ScalarValue::Object(
        handle @ (ScalarObjectHandle::HermesInternal
        | ScalarObjectHandle::Console
        | ScalarObjectHandle::Math
        | ScalarObjectHandle::Json
        | ScalarObjectHandle::Object(_)
        | ScalarObjectHandle::NativePrototype(_)
        | ScalarObjectHandle::Array(_)
        | ScalarObjectHandle::Uint8Array(_)
        | ScalarObjectHandle::Map(_)
        | ScalarObjectHandle::Set(_)
        | ScalarObjectHandle::WeakMap(_)
        | ScalarObjectHandle::WeakSet(_)
        | ScalarObjectHandle::NativeModule(_)),
    )) = registers.get(base_register as usize).copied()
    else {
        return read_scalar_property(
            bytecode,
            state,
            registers,
            function_id,
            instruction,
            base_register,
            property_name,
        );
    };

    read_cached_scalar_object_property_for_get(
        bytecode,
        state,
        function_id,
        instruction,
        ScalarValue::Object(handle),
        handle,
        string_id,
        property_name,
    )
}

fn read_scalar_object_property_for_get<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    receiver: ScalarValue,
    handle: ScalarObjectHandle,
    property_name: &'a str,
) -> Result<ScalarValue, ScalarExecutionError> {
    if state.object_getters.is_empty() && read_scalar_object_prototype(state, handle).is_none() {
        if let Some(value) = read_scalar_own_object_property(state, handle, property_name) {
            return Ok(value);
        }
        if let Some(value) = read_scalar_intrinsic_object_property(state, handle, property_name) {
            return Ok(value);
        }
    }

    match read_scalar_object_getter_lookup(state, handle, property_name, 0) {
        ScalarObjectGetterLookup::Getter(getter @ ScalarValue::Function(_)) => {
            call_scalar_function(
                bytecode,
                state,
                function_id,
                instruction,
                0,
                getter,
                &[receiver],
            )
        }
        ScalarObjectGetterLookup::Getter(getter) => {
            Err(ScalarExecutionError::UnsupportedPropertyKey {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: 0,
                value: getter,
            })
        }
        ScalarObjectGetterLookup::DataProperty(value) => Ok(value),
        ScalarObjectGetterLookup::Missing => {
            Ok(read_scalar_object_property(state, handle, property_name))
        }
    }
}

fn read_cached_scalar_object_property_for_get<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    receiver: ScalarValue,
    handle: ScalarObjectHandle,
    string_id: u32,
    property_name: &'a str,
) -> Result<ScalarValue, ScalarExecutionError> {
    if state.object_getters.is_empty() && read_scalar_object_prototype(state, handle).is_none() {
        if let Some(value) =
            read_cached_scalar_own_object_property(state, handle, string_id, property_name)
        {
            return Ok(value);
        }
        if let Some(value) = read_scalar_intrinsic_object_property(state, handle, property_name) {
            return Ok(value);
        }
    }

    read_scalar_object_property_for_get(
        bytecode,
        state,
        function_id,
        instruction,
        receiver,
        handle,
        property_name,
    )
}

fn read_scalar_property_key<'a>(
    bytecode: &HermesBytecode<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    key_register: u32,
) -> Result<&'a str, ScalarExecutionError> {
    match read_scalar_register(registers, function_id, instruction, key_register)? {
        ScalarValue::String(handle) => {
            read_scalar_string_operand(bytecode, function_id, instruction, handle.string_id)
        }
        ScalarValue::Symbol(handle) => {
            read_scalar_string_operand(bytecode, function_id, instruction, handle.string_id)
        }
        value => Err(ScalarExecutionError::UnsupportedPropertyKey {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: key_register,
            value,
        }),
    }
}

fn read_scalar_computed_property_key<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    key_register: u32,
) -> Result<ScalarPropertyKey<'a>, ScalarExecutionError> {
    let value = read_scalar_register(registers, function_id, instruction, key_register)?;
    scalar_computed_property_key_from_value(
        bytecode,
        state,
        function_id,
        instruction,
        key_register,
        value,
    )
}

fn scalar_computed_property_key_from_value<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &ScalarExecutorState<'a>,
    function_id: u32,
    instruction: HermesInstruction,
    key_register: u32,
    value: ScalarValue,
) -> Result<ScalarPropertyKey<'a>, ScalarExecutionError> {
    match value {
        ScalarValue::String(handle) => Ok(ScalarPropertyKey::Name(read_scalar_string_operand(
            bytecode,
            function_id,
            instruction,
            handle.string_id,
        )?)),
        ScalarValue::Symbol(handle) => Ok(ScalarPropertyKey::Name(read_scalar_string_operand(
            bytecode,
            function_id,
            instruction,
            handle.string_id,
        )?)),
        ScalarValue::DynamicString(handle) => {
            let Some(value) = state
                .dynamic_strings
                .get(usize::try_from(handle.dynamic_id).expect("dynamic string id fits in usize"))
            else {
                return Err(ScalarExecutionError::UnsupportedPropertyKey {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    register: key_register,
                    value: ScalarValue::DynamicString(handle),
                });
            };
            scalar_string_value_for_name(bytecode, value)
                .and_then(|value| {
                    if let ScalarValue::String(handle) = value {
                        read_scalar_string_operand(
                            bytecode,
                            function_id,
                            instruction,
                            handle.string_id,
                        )
                        .ok()
                        .map(ScalarPropertyKey::Name)
                    } else {
                        None
                    }
                })
                .ok_or(ScalarExecutionError::UnsupportedPropertyKey {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    register: key_register,
                    value: ScalarValue::DynamicString(handle),
                })
        }
        value => {
            if let Some(index) = scalar_value_to_u32(value) {
                Ok(ScalarPropertyKey::Index(index))
            } else {
                Err(ScalarExecutionError::UnsupportedPropertyKey {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    register: key_register,
                    value,
                })
            }
        }
    }
}

fn read_scalar_computed_property<'a>(
    bytecode: &HermesBytecode<'a>,
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    property_key: ScalarPropertyKey<'a>,
) -> Result<ScalarValue, ScalarExecutionError> {
    match property_key {
        ScalarPropertyKey::Name(property_name) => read_scalar_property(
            bytecode,
            state,
            registers,
            function_id,
            instruction,
            base_register,
            property_name,
        ),
        ScalarPropertyKey::Index(index) => {
            match read_scalar_register(registers, function_id, instruction, base_register)? {
                ScalarValue::Object(handle) => Ok(read_scalar_array_element(state, handle, index)),
                ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
                    if state.relaxed_host_stubs =>
                {
                    Ok(ScalarValue::Undefined)
                }
                value => Err(ScalarExecutionError::UnsupportedPropertyBase {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    register: base_register,
                    value,
                }),
            }
        }
    }
}

fn write_scalar_computed_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    property_key: ScalarPropertyKey<'a>,
    value: ScalarValue,
) -> Result<(), ScalarExecutionError> {
    match property_key {
        ScalarPropertyKey::Name(property_name) => write_scalar_property(
            state,
            registers,
            function_id,
            instruction,
            base_register,
            property_name,
            value,
        ),
        ScalarPropertyKey::Index(index) => {
            match read_scalar_register(registers, function_id, instruction, base_register)? {
                ScalarValue::Object(handle) => {
                    write_scalar_array_element(state, handle, index, value);
                    Ok(())
                }
                ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
                    if state.relaxed_host_stubs =>
                {
                    Ok(())
                }
                value => Err(ScalarExecutionError::UnsupportedPropertyBase {
                    function_id,
                    offset: instruction.offset,
                    opcode: instruction.opcode,
                    register: base_register,
                    value,
                }),
            }
        }
    }
}

fn write_scalar_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    property_name: &'a str,
    value: ScalarValue,
) -> Result<(), ScalarExecutionError> {
    let base = read_scalar_register(registers, function_id, instruction, base_register)?;
    match base {
        ScalarValue::Object(ScalarObjectHandle::Global) => {
            write_scalar_global_property(state, property_name, value);
            Ok(())
        }
        ScalarValue::Object(
            handle @ (ScalarObjectHandle::HermesInternal
            | ScalarObjectHandle::Console
            | ScalarObjectHandle::Json
            | ScalarObjectHandle::Object(_)
            | ScalarObjectHandle::NativePrototype(_)
            | ScalarObjectHandle::Array(_)
            | ScalarObjectHandle::Uint8Array(_)
            | ScalarObjectHandle::Map(_)
            | ScalarObjectHandle::Set(_)
            | ScalarObjectHandle::WeakMap(_)
            | ScalarObjectHandle::WeakSet(_)
            | ScalarObjectHandle::NativeModule(_)),
        ) => {
            write_scalar_named_object_property(state, handle, property_name, value);
            Ok(())
        }
        ScalarValue::Function(handle) => {
            write_scalar_named_function_property(state, handle, property_name, value);
            Ok(())
        }
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(())
        }
        value => Err(ScalarExecutionError::UnsupportedPropertyBase {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: base_register,
            value,
        }),
    }
}

fn write_scalar_getter_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    property_name: &'a str,
    getter: ScalarValue,
) -> Result<(), ScalarExecutionError> {
    let base = read_scalar_register(registers, function_id, instruction, base_register)?;
    match base {
        ScalarValue::Object(handle) => {
            write_scalar_named_object_getter_property(state, handle, property_name, getter);
            Ok(())
        }
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(())
        }
        value => Err(ScalarExecutionError::UnsupportedPropertyBase {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: base_register,
            value,
        }),
    }
}

fn delete_scalar_property(
    state: &mut ScalarExecutorState<'_>,
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    base: ScalarValue,
    property_key: ScalarPropertyKey<'_>,
) -> Result<(), ScalarExecutionError> {
    let ScalarPropertyKey::Name(property_name) = property_key else {
        if let ScalarPropertyKey::Index(index) = property_key {
            match base {
                ScalarValue::Object(handle) => {
                    if let ScalarObjectHandle::Array(object_id) = handle {
                        let storage_index =
                            usize::try_from(object_id).expect("array id fits in usize");
                        if let Some(storage) = state
                            .array_storage
                            .get_mut(storage_index)
                            .and_then(Option::as_mut)
                        {
                            if let Some(slot) = storage
                                .get_mut(usize::try_from(index).expect("array index fits in usize"))
                            {
                                *slot = ScalarValue::Undefined;
                            }
                        }
                    }
                    state.array_elements.retain(|(object, element_index, _)| {
                        *object != handle || *element_index != index
                    });
                    reindex_scalar_array_elements(state);
                    return Ok(());
                }
                ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
                    if state.relaxed_host_stubs =>
                {
                    return Ok(());
                }
                value => {
                    return Err(ScalarExecutionError::UnsupportedPropertyBase {
                        function_id,
                        offset: instruction.offset,
                        opcode: instruction.opcode,
                        register: base_register,
                        value,
                    });
                }
            }
        }
        unreachable!("matched all computed property key variants");
    };

    match base {
        ScalarValue::Object(ScalarObjectHandle::Global) => {
            state
                .global_properties
                .retain(|(name, _)| *name != property_name);
            clear_scalar_global_property_operand_cache(state);
            Ok(())
        }
        ScalarValue::Object(handle) => {
            state
                .object_properties
                .retain(|(object, name, _)| *object != handle || *name != property_name);
            reindex_scalar_object_properties(state);
            Ok(())
        }
        ScalarValue::Function(handle) => {
            state
                .function_properties
                .retain(|(function, name, _)| *function != handle || *name != property_name);
            Ok(())
        }
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(())
        }
        value => Err(ScalarExecutionError::UnsupportedPropertyBase {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: base_register,
            value,
        }),
    }
}

fn scalar_computed_property_exists(
    state: &ScalarExecutorState<'_>,
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    base: ScalarValue,
    property_key: ScalarPropertyKey<'_>,
) -> Result<bool, ScalarExecutionError> {
    match property_key {
        ScalarPropertyKey::Name(property_name) => scalar_property_exists(
            state,
            function_id,
            instruction,
            base_register,
            base,
            property_name,
        ),
        ScalarPropertyKey::Index(index) => match base {
            ScalarValue::Object(handle) => Ok(state
                .array_elements
                .iter()
                .rev()
                .any(|(object, element_index, _)| *object == handle && *element_index == index)),
            ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
                if state.relaxed_host_stubs =>
            {
                Ok(false)
            }
            value => Err(ScalarExecutionError::UnsupportedPropertyBase {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                register: base_register,
                value,
            }),
        },
    }
}

fn scalar_property_exists(
    state: &ScalarExecutorState<'_>,
    function_id: u32,
    instruction: HermesInstruction,
    base_register: u32,
    base: ScalarValue,
    property_name: &str,
) -> Result<bool, ScalarExecutionError> {
    match base {
        ScalarValue::Object(ScalarObjectHandle::Global) => {
            Ok(scalar_global_property_exists(state, property_name))
        }
        ScalarValue::Object(handle) => {
            Ok(scalar_object_property_exists(state, handle, property_name))
        }
        ScalarValue::Function(handle) => Ok(scalar_function_property_exists(
            state,
            handle,
            property_name,
        )),
        ScalarValue::String(_) | ScalarValue::DynamicString(_) => {
            Ok(scalar_string_property_exists(property_name))
        }
        ScalarValue::Undefined | ScalarValue::Null | ScalarValue::Empty
            if state.relaxed_host_stubs =>
        {
            Ok(false)
        }
        value => Err(ScalarExecutionError::UnsupportedPropertyBase {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register: base_register,
            value,
        }),
    }
}

fn scalar_global_property_exists(state: &ScalarExecutorState<'_>, property_name: &str) -> bool {
    if scalar_global_property_index(state, property_name).is_some() {
        return true;
    }

    matches!(
        property_name,
        "globalThis"
            | "Array"
            | "Boolean"
            | "console"
            | "Date"
            | "DOMException"
            | "Error"
            | "Function"
            | "HermesInternal"
            | "isNaN"
            | "JSON"
            | "Map"
            | "Number"
            | "Object"
            | "Promise"
            | "Set"
            | "String"
            | "Symbol"
            | "TypeError"
            | "Uint8Array"
            | "WeakMap"
            | "WeakSet"
            | "__turboModuleProxy"
            | "nativePerformanceNow"
    ) || state
        .declared_globals
        .iter()
        .any(|name| scalar_property_name_matches(name, property_name))
}

fn scalar_object_property_exists(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
) -> bool {
    scalar_object_property_exists_with_depth(state, handle, property_name, 0)
}

fn scalar_object_property_exists_with_depth(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
    depth: u8,
) -> bool {
    if scalar_object_has_own_named_property(state, handle, property_name) {
        return true;
    }
    if handle == ScalarObjectHandle::HermesInternal && property_name == "concat" {
        return true;
    }
    if handle == ScalarObjectHandle::Console && property_name == "error" {
        return true;
    }
    if handle == ScalarObjectHandle::Math && matches!(property_name, "round" | "sin" | "sqrt") {
        return true;
    }
    if handle == ScalarObjectHandle::Json && matches!(property_name, "parse" | "stringify") {
        return true;
    }
    if matches!(
        property_name,
        "registerCallableModule" | "registerLazyCallableModule"
    ) {
        return true;
    }
    if let ScalarObjectHandle::NativePrototype(_) = handle {
        if property_name == "constructor" {
            return true;
        }
    }
    if matches!(
        handle,
        ScalarObjectHandle::Console
            | ScalarObjectHandle::Json
            | ScalarObjectHandle::Object(_)
            | ScalarObjectHandle::NativePrototype(_)
            | ScalarObjectHandle::Array(_)
            | ScalarObjectHandle::Uint8Array(_)
            | ScalarObjectHandle::Map(_)
            | ScalarObjectHandle::Set(_)
            | ScalarObjectHandle::WeakMap(_)
            | ScalarObjectHandle::WeakSet(_)
            | ScalarObjectHandle::NativeModule(_)
    ) && property_name == "hasOwnProperty"
    {
        return true;
    }
    if matches!(handle, ScalarObjectHandle::NativeModule(_)) {
        return true;
    }
    if matches!(handle, ScalarObjectHandle::Array(_)) && matches!(property_name, "forEach" | "map")
    {
        return true;
    }
    if matches!(handle, ScalarObjectHandle::Array(_)) && property_name == "length" {
        return true;
    }
    if matches!(handle, ScalarObjectHandle::Uint8Array(_))
        && matches!(property_name, "byteLength" | "length" | "set")
    {
        return true;
    }
    if matches!(
        handle,
        ScalarObjectHandle::Map(_) | ScalarObjectHandle::WeakMap(_)
    ) && matches!(property_name, "get" | "has" | "set")
    {
        return true;
    }
    if depth < 16 {
        if let Some(ScalarValue::Object(prototype)) = read_scalar_object_prototype(state, handle) {
            if scalar_object_property_exists_with_depth(state, prototype, property_name, depth + 1)
            {
                return true;
            }
        }
    }

    matches!(handle, ScalarObjectHandle::Object(_))
        && read_scalar_rn_object_stub_property(property_name).is_some()
}

fn scalar_function_property_exists(
    state: &ScalarExecutorState<'_>,
    handle: ScalarFunctionHandle,
    property_name: &str,
) -> bool {
    if state
        .function_properties
        .iter()
        .rev()
        .any(|(function, name, _)| *function == handle && *name == property_name)
    {
        return true;
    }
    if property_name == "prototype" && scalar_native_constructor_prototype(handle).is_some() {
        return true;
    }
    if handle == ScalarFunctionHandle::NativeDateConstructor && property_name == "now" {
        return true;
    }
    if handle == ScalarFunctionHandle::NativeArrayConstructor && property_name == "isArray" {
        return true;
    }
    if handle == ScalarFunctionHandle::NativeSymbolConstructor && property_name == "for" {
        return true;
    }
    if matches!(property_name, "toString" | "bind" | "call") {
        return true;
    }
    if handle == ScalarFunctionHandle::NativeFunctionToString && property_name == "call" {
        return true;
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor
        && matches!(
            property_name,
            "create"
                | "defineProperties"
                | "defineProperty"
                | "assign"
                | "freeze"
                | "getOwnPropertyDescriptor"
                | "getPrototypeOf"
                | "keys"
                | "preventExtensions"
        )
    {
        return true;
    }
    if handle == ScalarFunctionHandle::NativeObjectHasOwnProperty && property_name == "call" {
        return true;
    }

    matches!(handle, ScalarFunctionHandle::Bytecode { .. })
        && read_scalar_rn_object_stub_property(property_name).is_some()
}

fn scalar_string_property_exists(property_name: &str) -> bool {
    matches!(
        property_name,
        "charCodeAt" | "indexOf" | "length" | "replace"
    )
}

fn map_scalar_global_write(property_name: &str, value: ScalarValue) -> ScalarValue {
    match property_name {
        "__d" => ScalarValue::Function(ScalarFunctionHandle::NativeMetroDefine),
        "__r" => ScalarValue::Function(ScalarFunctionHandle::NativeMetroRequire),
        "__turboModuleProxy" => ScalarValue::Function(ScalarFunctionHandle::NativeTurboModuleProxy),
        "__registerSegment" => {
            ScalarValue::Function(ScalarFunctionHandle::NativeMetroRegisterSegment)
        }
        _ => value,
    }
}

fn write_scalar_named_object_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    property_name: &'a str,
    value: ScalarValue,
) {
    write_scalar_named_object_property_index(state, object, property_name, value);
}

fn write_scalar_named_object_property_index<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    property_name: &'a str,
    value: ScalarValue,
) -> usize {
    if !state.object_getters.is_empty() {
        state.object_getters.retain(|(stored_object, name, _)| {
            !(*stored_object == object && *name == property_name)
        });
    }
    if state.object_properties.len() <= SCALAR_LINEAR_OBJECT_PROPERTY_LIMIT
        || state.object_property_indices_incomplete
    {
        if let Some(property_index) =
            scalar_linear_own_object_property_index(state, object, property_name)
        {
            state.object_properties[property_index].2 = value;
            return property_index;
        }
    }
    let property_may_exist = state
        .object_property_names
        .get(&object)
        .is_some_and(|names| {
            names
                .iter()
                .any(|name| scalar_property_name_matches(name, property_name))
        });
    if property_may_exist {
        if let Some(property_index) = state
            .object_property_indices
            .get(&(object, property_name))
            .copied()
        {
            state.object_properties[property_index].2 = value;
            return property_index;
        }
    }

    let property_index = state.object_properties.len();
    state
        .object_property_indices
        .insert((object, property_name), property_index);
    state
        .object_property_names
        .entry(object)
        .or_default()
        .push(property_name);
    state.object_properties.push((object, property_name, value));
    property_index
}

fn write_cached_scalar_named_object_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    string_id: u32,
    property_name: &'a str,
    value: ScalarValue,
) {
    let index = write_scalar_named_object_property_index(state, object, property_name, value);
    state.object_property_operand_cache[scalar_string_operand_cache_slot(string_id)] =
        Some((object, string_id, index));
}

fn write_scalar_new_object_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    property_name: &'a str,
    value: ScalarValue,
) {
    let property_index = state.object_properties.len();
    state
        .object_property_indices
        .insert((object, property_name), property_index);
    state
        .object_property_names
        .entry(object)
        .or_default()
        .push(property_name);
    state.object_properties.push((object, property_name, value));
}

#[cfg(test)]
fn write_scalar_new_object_properties2_unindexed<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    first_name: &'a str,
    first_value: ScalarValue,
    second_name: &'a str,
    second_value: ScalarValue,
) {
    state.object_property_indices_incomplete = true;
    state
        .object_properties
        .push((object, first_name, first_value));
    state
        .object_properties
        .push((object, second_name, second_value));
}

fn write_scalar_named_object_getter_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    property_name: &'a str,
    getter: ScalarValue,
) {
    state
        .object_properties
        .retain(|(stored_object, name, _)| !(*stored_object == object && *name == property_name));
    reindex_scalar_object_properties(state);
    if let Some((_, _, stored_getter)) = state
        .object_getters
        .iter_mut()
        .rev()
        .find(|(stored_object, name, _)| *stored_object == object && *name == property_name)
    {
        *stored_getter = getter;
    } else {
        state.object_getters.push((object, property_name, getter));
    }
}

fn reindex_scalar_object_properties<'a>(state: &mut ScalarExecutorState<'a>) {
    clear_scalar_object_property_operand_cache(state);
    state.object_property_indices.clear();
    state.object_property_names.clear();
    state.object_property_indices_incomplete = false;
    for (index, (object, name, _)) in state.object_properties.iter().enumerate() {
        state
            .object_property_indices
            .insert((*object, *name), index);
        state
            .object_property_names
            .entry(*object)
            .or_default()
            .push(*name);
    }
}

fn write_scalar_named_function_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    function: ScalarFunctionHandle,
    property_name: &'a str,
    value: ScalarValue,
) {
    if let Some((_, _, stored_value)) = state
        .function_properties
        .iter_mut()
        .rev()
        .find(|(stored_function, name, _)| *stored_function == function && *name == property_name)
    {
        *stored_value = value;
    } else {
        state
            .function_properties
            .push((function, property_name, value));
    }
}

fn scalar_property_name_matches(stored: &str, requested: &str) -> bool {
    stored.len() == requested.len()
        && (stored.as_ptr() == requested.as_ptr() || stored == requested)
}

fn scalar_string_operand_cache_slot(string_id: u32) -> usize {
    usize::try_from(string_id).expect("Hermes string id fits in usize on supported targets")
        & (SCALAR_STRING_OPERAND_CACHE_SLOTS - 1)
}

fn clear_scalar_global_property_operand_cache(state: &mut ScalarExecutorState<'_>) {
    state.global_property_operand_cache = [None; SCALAR_STRING_OPERAND_CACHE_SLOTS];
}

fn clear_scalar_object_property_operand_cache(state: &mut ScalarExecutorState<'_>) {
    state.object_property_operand_cache = [None; SCALAR_STRING_OPERAND_CACHE_SLOTS];
}

fn scalar_global_property_index(
    state: &ScalarExecutorState<'_>,
    property_name: &str,
) -> Option<usize> {
    state
        .global_properties
        .iter()
        .enumerate()
        .rev()
        .find(|(_, (name, _))| scalar_property_name_matches(name, property_name))
        .map(|(index, _)| index)
}

fn read_cached_scalar_global_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    string_id: u32,
    property_name: &'a str,
) -> ScalarValue {
    let slot = scalar_string_operand_cache_slot(string_id);
    if let Some((cached_id, index)) = state.global_property_operand_cache[slot] {
        if cached_id == string_id {
            if let Some((stored_name, value)) = state.global_properties.get(index) {
                if scalar_property_name_matches(stored_name, property_name) {
                    return *value;
                }
            }
        }
    }

    if let Some(index) = scalar_global_property_index(state, property_name) {
        state.global_property_operand_cache[slot] = Some((string_id, index));
        return state.global_properties[index].1;
    }

    read_scalar_builtin_global_property(state, property_name)
}

fn write_cached_scalar_global_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    string_id: u32,
    property_name: &'a str,
    value: ScalarValue,
) {
    let index = write_scalar_global_property(state, property_name, value);
    state.global_property_operand_cache[scalar_string_operand_cache_slot(string_id)] =
        Some((string_id, index));
}

fn write_scalar_global_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    property_name: &'a str,
    value: ScalarValue,
) -> usize {
    let value = map_scalar_global_write(property_name, value);
    if let Some(index) = scalar_global_property_index(state, property_name) {
        state.global_properties[index].1 = value;
        return index;
    }

    let index = state.global_properties.len();
    state.global_properties.push((property_name, value));
    index
}

fn scalar_own_object_property_index(
    state: &ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
    property_name: &str,
) -> Option<usize> {
    if state.object_properties.len() <= SCALAR_LINEAR_OBJECT_PROPERTY_LIMIT {
        return scalar_linear_own_object_property_index(state, object, property_name);
    }

    let indexed_property = state
        .object_property_indices
        .get(&(object, property_name))
        .copied();
    if indexed_property.is_some() || !state.object_property_indices_incomplete {
        return indexed_property;
    }

    scalar_linear_own_object_property_index(state, object, property_name)
}

fn scalar_linear_own_object_property_index(
    state: &ScalarExecutorState<'_>,
    object: ScalarObjectHandle,
    property_name: &str,
) -> Option<usize> {
    state
        .object_properties
        .iter()
        .enumerate()
        .rev()
        .find(|(_, (stored_object, name, _))| {
            *stored_object == object && scalar_property_name_matches(name, property_name)
        })
        .map(|(index, _)| index)
}

fn scalar_linear_object_property_names<'a>(
    state: &ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
) -> Vec<&'a str> {
    let mut names: Vec<&'a str> = Vec::new();
    for (stored_object, name, _) in &state.object_properties {
        if *stored_object == object
            && !names
                .iter()
                .any(|stored_name| scalar_property_name_matches(*stored_name, *name))
        {
            names.push(*name);
        }
    }
    names
}

fn read_cached_scalar_own_object_property<'a>(
    state: &mut ScalarExecutorState<'a>,
    object: ScalarObjectHandle,
    string_id: u32,
    property_name: &'a str,
) -> Option<ScalarValue> {
    let slot = scalar_string_operand_cache_slot(string_id);
    if let Some((cached_object, cached_id, index)) = state.object_property_operand_cache[slot] {
        if cached_object == object && cached_id == string_id {
            if let Some((stored_object, stored_name, value)) = state.object_properties.get(index) {
                if *stored_object == object
                    && scalar_property_name_matches(stored_name, property_name)
                {
                    return Some(*value);
                }
            }
        }
    }

    let index = scalar_own_object_property_index(state, object, property_name)?;
    state.object_property_operand_cache[slot] = Some((object, string_id, index));
    Some(state.object_properties[index].2)
}

fn read_scalar_global_property(
    state: &ScalarExecutorState<'_>,
    property_name: &str,
) -> ScalarValue {
    if let Some(index) = scalar_global_property_index(state, property_name) {
        return state.global_properties[index].1;
    }

    read_scalar_builtin_global_property(state, property_name)
}

fn read_scalar_builtin_global_property(
    state: &ScalarExecutorState<'_>,
    property_name: &str,
) -> ScalarValue {
    match property_name {
        "globalThis" => ScalarValue::Object(ScalarObjectHandle::Global),
        "Array" => ScalarValue::Function(ScalarFunctionHandle::NativeArrayConstructor),
        "Boolean" => ScalarValue::Function(ScalarFunctionHandle::NativeBooleanConstructor),
        "console" => ScalarValue::Object(ScalarObjectHandle::Console),
        "Date" => ScalarValue::Function(ScalarFunctionHandle::NativeDateConstructor),
        "DOMException" => ScalarValue::Function(ScalarFunctionHandle::NativeErrorConstructor),
        "Error" => ScalarValue::Function(ScalarFunctionHandle::NativeErrorConstructor),
        "Function" => ScalarValue::Function(ScalarFunctionHandle::NativeFunctionConstructor),
        "HermesInternal" => ScalarValue::Object(ScalarObjectHandle::HermesInternal),
        "isNaN" => ScalarValue::Function(ScalarFunctionHandle::NativeIsNaN),
        "JSON" => ScalarValue::Object(ScalarObjectHandle::Json),
        "Math" => ScalarValue::Object(ScalarObjectHandle::Math),
        "Map" => ScalarValue::Function(ScalarFunctionHandle::NativeMapConstructor),
        "Number" => ScalarValue::Function(ScalarFunctionHandle::NativeNumberConstructor),
        "Object" => ScalarValue::Function(ScalarFunctionHandle::NativeObjectConstructor),
        "Promise" => ScalarValue::Function(ScalarFunctionHandle::NativePromiseConstructor),
        "Set" => ScalarValue::Function(ScalarFunctionHandle::NativeSetConstructor),
        "String" => ScalarValue::Function(ScalarFunctionHandle::NativeStringConstructor),
        "Symbol" => ScalarValue::Function(ScalarFunctionHandle::NativeSymbolConstructor),
        "TypeError" => ScalarValue::Function(ScalarFunctionHandle::NativeErrorConstructor),
        "Uint8Array" => ScalarValue::Function(ScalarFunctionHandle::NativeUint8ArrayConstructor),
        "WeakMap" => ScalarValue::Function(ScalarFunctionHandle::NativeWeakMapConstructor),
        "WeakSet" => ScalarValue::Function(ScalarFunctionHandle::NativeWeakSetConstructor),
        "__turboModuleProxy" => ScalarValue::Function(ScalarFunctionHandle::NativeTurboModuleProxy),
        "nativePerformanceNow" => ScalarValue::Function(ScalarFunctionHandle::NativePerformanceNow),
        name if state
            .declared_globals
            .iter()
            .any(|declared| scalar_property_name_matches(declared, name)) =>
        {
            ScalarValue::Undefined
        }
        _ => ScalarValue::Undefined,
    }
}

fn read_scalar_math_intrinsic_property(property_name: &str) -> Option<ScalarValue> {
    match property_name {
        "round" => Some(ScalarValue::Function(ScalarFunctionHandle::NativeMathRound)),
        "sin" => Some(ScalarValue::Function(ScalarFunctionHandle::NativeMathSin)),
        "sqrt" => Some(ScalarValue::Function(ScalarFunctionHandle::NativeMathSqrt)),
        _ => None,
    }
}

fn read_scalar_object_property(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
) -> ScalarValue {
    read_scalar_object_property_with_depth(state, handle, property_name, 0)
}

fn read_scalar_object_property_with_depth(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
    depth: u8,
) -> ScalarValue {
    if let Some(value) = read_scalar_intrinsic_object_property(state, handle, property_name) {
        return value;
    }

    if let Some(value) = read_scalar_own_object_property(state, handle, property_name) {
        return value;
    }

    if depth < 16 {
        if let Some(ScalarValue::Object(prototype)) = read_scalar_object_prototype(state, handle) {
            return read_scalar_object_property_with_depth(
                state,
                prototype,
                property_name,
                depth + 1,
            );
        }
    }

    if matches!(handle, ScalarObjectHandle::Object(_)) {
        if let Some(value) = read_scalar_rn_object_stub_property(property_name) {
            return value;
        }
    }

    ScalarValue::Undefined
}

fn read_scalar_intrinsic_object_property(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
) -> Option<ScalarValue> {
    if handle == ScalarObjectHandle::HermesInternal && property_name == "concat" {
        return Some(ScalarValue::Function(
            ScalarFunctionHandle::HermesInternalConcat,
        ));
    }
    if handle == ScalarObjectHandle::Console && property_name == "error" {
        return Some(ScalarValue::Function(
            ScalarFunctionHandle::NativeNoopFunction,
        ));
    }
    if handle == ScalarObjectHandle::Math {
        if let Some(value) = read_scalar_math_intrinsic_property(property_name) {
            return Some(value);
        }
    }
    if handle == ScalarObjectHandle::Json {
        match property_name {
            "parse" => return Some(ScalarValue::Function(ScalarFunctionHandle::NativeJsonParse)),
            "stringify" => {
                return Some(ScalarValue::Function(
                    ScalarFunctionHandle::NativeJsonStringify,
                ));
            }
            _ => {}
        }
    }
    if matches!(
        property_name,
        "registerCallableModule" | "registerLazyCallableModule"
    ) {
        return Some(ScalarValue::Function(
            ScalarFunctionHandle::NativeNoopFunction,
        ));
    }
    if let ScalarObjectHandle::NativePrototype(prototype) = handle {
        if property_name == "constructor" {
            return Some(
                scalar_native_prototype_constructor(prototype)
                    .map_or(ScalarValue::Undefined, ScalarValue::Function),
            );
        }
    }
    if matches!(
        handle,
        ScalarObjectHandle::Console
            | ScalarObjectHandle::Json
            | ScalarObjectHandle::Object(_)
            | ScalarObjectHandle::NativePrototype(_)
            | ScalarObjectHandle::Array(_)
            | ScalarObjectHandle::Uint8Array(_)
            | ScalarObjectHandle::Map(_)
            | ScalarObjectHandle::Set(_)
            | ScalarObjectHandle::WeakMap(_)
            | ScalarObjectHandle::WeakSet(_)
            | ScalarObjectHandle::NativeModule(_)
    ) && property_name == "hasOwnProperty"
    {
        return Some(ScalarValue::Function(
            ScalarFunctionHandle::NativeObjectHasOwnProperty,
        ));
    }
    if matches!(handle, ScalarObjectHandle::NativeModule(_)) {
        return Some(match property_name {
            "getConstants" => ScalarValue::Function(ScalarFunctionHandle::NativeModuleGetConstants),
            "currentTimestamp" => ScalarValue::Function(ScalarFunctionHandle::NativePerformanceNow),
            "getSupportedPerformanceEntryTypes" => {
                ScalarValue::Function(ScalarFunctionHandle::NativePerformanceGetSupportedEntryTypes)
            }
            _ => ScalarValue::Function(ScalarFunctionHandle::NativeNoopFunction),
        });
    }
    if matches!(handle, ScalarObjectHandle::Array(_)) {
        match property_name {
            "length" => {
                return Some(ScalarValue::Number(
                    read_scalar_array_length(state, handle).map_or(0.0, f64::from),
                ));
            }
            "forEach" => {
                return Some(ScalarValue::Function(
                    ScalarFunctionHandle::NativeArrayForEach,
                ));
            }
            "map" => return Some(ScalarValue::Function(ScalarFunctionHandle::NativeArrayMap)),
            _ => {}
        }
    }
    if matches!(handle, ScalarObjectHandle::Uint8Array(_)) {
        match property_name {
            "byteLength" | "length" => {
                return Some(ScalarValue::Number(
                    read_scalar_array_length(state, handle).map_or(0.0, f64::from),
                ));
            }
            "set" => {
                return Some(ScalarValue::Function(
                    ScalarFunctionHandle::NativeUint8ArraySet,
                ));
            }
            _ => {}
        }
    }
    if matches!(
        handle,
        ScalarObjectHandle::Map(_) | ScalarObjectHandle::WeakMap(_)
    ) {
        match property_name {
            "get" => {
                return Some(ScalarValue::Function(
                    ScalarFunctionHandle::NativeWeakMapGet,
                ));
            }
            "has" => {
                return Some(ScalarValue::Function(
                    ScalarFunctionHandle::NativeWeakMapHas,
                ));
            }
            "set" => {
                return Some(ScalarValue::Function(
                    ScalarFunctionHandle::NativeWeakMapSet,
                ));
            }
            _ => {}
        }
    }
    None
}

fn read_scalar_object_getter_lookup(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
    depth: u8,
) -> ScalarObjectGetterLookup {
    if let Some(value) = read_scalar_own_object_property(state, handle, property_name) {
        return ScalarObjectGetterLookup::DataProperty(value);
    }
    if let Some(getter) = read_scalar_own_object_getter_property(state, handle, property_name) {
        return ScalarObjectGetterLookup::Getter(getter);
    }
    if depth < SCALAR_PROTOTYPE_LOOKUP_DEPTH_LIMIT {
        if let Some(ScalarValue::Object(prototype)) = read_scalar_object_prototype(state, handle) {
            return read_scalar_object_getter_lookup(state, prototype, property_name, depth + 1);
        }
    }
    ScalarObjectGetterLookup::Missing
}

fn read_scalar_own_object_getter_property(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
) -> Option<ScalarValue> {
    state
        .object_getters
        .iter()
        .rev()
        .find(|(object, name, _)| *object == handle && *name == property_name)
        .map(|(_, _, getter)| *getter)
}

fn read_scalar_own_object_property(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
) -> Option<ScalarValue> {
    if let Some(value) = scalar_own_object_property_index(state, handle, property_name)
        .map(|property_index| state.object_properties[property_index].2)
    {
        return Some(value);
    }

    let slot = state
        .object_slot_names
        .iter()
        .rev()
        .find(|(object, _, name)| *object == handle && *name == property_name)
        .map(|(_, slot, _)| *slot)?;
    read_scalar_object_slot_value(state, handle, slot)
}

fn read_scalar_rn_object_stub_property(property_name: &str) -> Option<ScalarValue> {
    match property_name {
        "currentTimestamp" => Some(ScalarValue::Function(
            ScalarFunctionHandle::NativePerformanceNow,
        )),
        "addNetworkingHandler"
        | "addTimespan"
        | "append"
        | "clear"
        | "clearCompleted"
        | "close"
        | "logEverything"
        | "markPoint"
        | "removeExtra"
        | "setExtra"
        | "setReactNativeMicrotasksCallback"
        | "startTimespan"
        | "stopTimespan" => Some(ScalarValue::Function(
            ScalarFunctionHandle::NativeNoopFunction,
        )),
        _ => None,
    }
}

fn scalar_object_has_own_named_property(
    state: &ScalarExecutorState<'_>,
    handle: ScalarObjectHandle,
    property_name: &str,
) -> bool {
    scalar_own_object_property_index(state, handle, property_name).is_some()
}

fn read_scalar_function_property(
    state: &ScalarExecutorState<'_>,
    handle: ScalarFunctionHandle,
    property_name: &str,
) -> ScalarValue {
    if property_name == "prototype" {
        if let Some(prototype) = scalar_native_constructor_prototype(handle) {
            return ScalarValue::Object(ScalarObjectHandle::NativePrototype(prototype));
        }
    }
    if handle == ScalarFunctionHandle::NativeDateConstructor && property_name == "now" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeDateNow);
    }
    if handle == ScalarFunctionHandle::NativeSymbolConstructor && property_name == "for" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeSymbolFor);
    }
    if handle == ScalarFunctionHandle::NativeArrayConstructor && property_name == "isArray" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeArrayIsArray);
    }
    if property_name == "toString" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeFunctionToString);
    }
    if property_name == "bind" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeFunctionBind);
    }
    if handle == ScalarFunctionHandle::NativeFunctionToString && property_name == "call" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeFunctionToStringCall);
    }

    if handle == ScalarFunctionHandle::NativeObjectConstructor && property_name == "defineProperty"
    {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectDefineProperty);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor
        && property_name == "defineProperties"
    {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectDefineProperties);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor && property_name == "assign" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectAssign);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor && property_name == "freeze" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectFreeze);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor && property_name == "create" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectCreate);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor && property_name == "getPrototypeOf"
    {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectGetPrototypeOf);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor
        && property_name == "getOwnPropertyDescriptor"
    {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectGetOwnPropertyDescriptor);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor
        && property_name == "preventExtensions"
    {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectPreventExtensions);
    }
    if handle == ScalarFunctionHandle::NativeObjectConstructor && property_name == "keys" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectKeys);
    }
    if handle == ScalarFunctionHandle::NativeObjectHasOwnProperty && property_name == "call" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeObjectHasOwnPropertyCall);
    }
    if handle == ScalarFunctionHandle::NativeMetroRequire && property_name == "importDefault" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeMetroImportDefault);
    }
    if handle == ScalarFunctionHandle::NativeMetroRequire && property_name == "importAll" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeMetroImportAll);
    }
    if property_name == "call" {
        return ScalarValue::Function(ScalarFunctionHandle::NativeFunctionCall);
    }

    let stored_property = state
        .function_properties
        .iter()
        .rev()
        .find(|(function, name, _)| *function == handle && *name == property_name)
        .map(|(_, _, value)| *value);
    if let Some(value) = stored_property {
        return value;
    }

    if matches!(handle, ScalarFunctionHandle::Bytecode { .. }) {
        if let Some(value) = read_scalar_rn_object_stub_property(property_name) {
            return value;
        }
    }

    ScalarValue::Undefined
}

fn scalar_native_constructor_prototype(
    handle: ScalarFunctionHandle,
) -> Option<ScalarNativePrototype> {
    match handle {
        ScalarFunctionHandle::NativeArrayConstructor => Some(ScalarNativePrototype::Array),
        ScalarFunctionHandle::NativeUint8ArrayConstructor => {
            Some(ScalarNativePrototype::Uint8Array)
        }
        ScalarFunctionHandle::NativeBooleanConstructor => Some(ScalarNativePrototype::Boolean),
        ScalarFunctionHandle::NativeDateConstructor => Some(ScalarNativePrototype::Date),
        ScalarFunctionHandle::NativeFunctionConstructor => Some(ScalarNativePrototype::Function),
        ScalarFunctionHandle::NativeMapConstructor => Some(ScalarNativePrototype::Map),
        ScalarFunctionHandle::NativeNumberConstructor => Some(ScalarNativePrototype::Number),
        ScalarFunctionHandle::NativeObjectConstructor => Some(ScalarNativePrototype::Object),
        ScalarFunctionHandle::NativePromiseConstructor => Some(ScalarNativePrototype::Promise),
        ScalarFunctionHandle::NativeSetConstructor => Some(ScalarNativePrototype::Set),
        ScalarFunctionHandle::NativeStringConstructor => Some(ScalarNativePrototype::String),
        ScalarFunctionHandle::NativeWeakMapConstructor => Some(ScalarNativePrototype::WeakMap),
        ScalarFunctionHandle::NativeWeakSetConstructor => Some(ScalarNativePrototype::WeakSet),
        _ => None,
    }
}

fn scalar_native_prototype_constructor(
    prototype: ScalarNativePrototype,
) -> Option<ScalarFunctionHandle> {
    match prototype {
        ScalarNativePrototype::Array => Some(ScalarFunctionHandle::NativeArrayConstructor),
        ScalarNativePrototype::Uint8Array => {
            Some(ScalarFunctionHandle::NativeUint8ArrayConstructor)
        }
        ScalarNativePrototype::Boolean => Some(ScalarFunctionHandle::NativeBooleanConstructor),
        ScalarNativePrototype::Date => Some(ScalarFunctionHandle::NativeDateConstructor),
        ScalarNativePrototype::Function => Some(ScalarFunctionHandle::NativeFunctionConstructor),
        ScalarNativePrototype::Map => Some(ScalarFunctionHandle::NativeMapConstructor),
        ScalarNativePrototype::Number => Some(ScalarFunctionHandle::NativeNumberConstructor),
        ScalarNativePrototype::Object => Some(ScalarFunctionHandle::NativeObjectConstructor),
        ScalarNativePrototype::Promise => Some(ScalarFunctionHandle::NativePromiseConstructor),
        ScalarNativePrototype::Set => Some(ScalarFunctionHandle::NativeSetConstructor),
        ScalarNativePrototype::String => Some(ScalarFunctionHandle::NativeStringConstructor),
        ScalarNativePrototype::WeakMap => Some(ScalarFunctionHandle::NativeWeakMapConstructor),
        ScalarNativePrototype::WeakSet => Some(ScalarFunctionHandle::NativeWeakSetConstructor),
    }
}

fn read_scalar_string_property(
    bytecode: &HermesBytecode<'_>,
    state: &ScalarExecutorState<'_>,
    value: ScalarValue,
    property_name: &str,
) -> ScalarValue {
    match property_name {
        "charCodeAt" => ScalarValue::Function(ScalarFunctionHandle::NativeStringCharCodeAt),
        "indexOf" => ScalarValue::Function(ScalarFunctionHandle::NativeStringIndexOf),
        "length" => scalar_value_string_text(bytecode, state, value)
            .map_or(ScalarValue::Undefined, |value| {
                ScalarValue::Number(value.chars().count() as f64)
            }),
        "replace" => ScalarValue::Function(ScalarFunctionHandle::NativeStringReplace),
        _ => ScalarValue::Undefined,
    }
}

fn write_scalar_destination(
    registers: &mut [ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    instruction_bytes: &[u8],
    value: ScalarValue,
) -> Result<(), ScalarExecutionError> {
    let destination = read_unsigned_operand(instruction_bytes, 1, 1);
    write_scalar_register(registers, function_id, instruction, destination, value)
}

fn read_scalar_register(
    registers: &[ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    register: u32,
) -> Result<ScalarValue, ScalarExecutionError> {
    registers.get(register as usize).copied().ok_or_else(|| {
        ScalarExecutionError::RegisterOutOfBounds {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register,
            frame_size: u32::try_from(registers.len()).expect("Hermes frame size is stored as u32"),
        }
    })
}

fn write_scalar_register(
    registers: &mut [ScalarValue],
    function_id: u32,
    instruction: HermesInstruction,
    register: u32,
    value: ScalarValue,
) -> Result<(), ScalarExecutionError> {
    let Some(register_slot) = registers.get_mut(register as usize) else {
        return Err(ScalarExecutionError::RegisterOutOfBounds {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            register,
            frame_size: u32::try_from(registers.len()).expect("Hermes frame size is stored as u32"),
        });
    };
    *register_slot = value;
    Ok(())
}

/// Describe the current Iris scalar executor coverage against a Hermes bytecode bundle.
pub fn describe_hbc_execution_gap(bytes: &[u8]) -> Result<String, ParseError> {
    let bytecode = HermesBytecode::parse(bytes)?;
    let header = bytecode.header();
    let mut opcode_counts = [0_u32; HERMES_OPCODE_COUNT];
    let mut first_offsets = [u32::MAX; HERMES_OPCODE_COUNT];
    let mut instruction_count = 0_u32;
    let mut supported_instruction_count = 0_u32;
    let mut first_unsupported = None;

    for instruction in bytecode.function_instructions(header.global_code_index)? {
        let instruction = instruction?;
        let opcode_index = usize::from(instruction.opcode);
        opcode_counts[opcode_index] += 1;
        first_offsets[opcode_index] = first_offsets[opcode_index].min(instruction.offset);
        instruction_count += 1;

        if iris_scalar_executor_supports_opcode(instruction.opcode) {
            supported_instruction_count += 1;
        } else if first_unsupported.is_none() {
            first_unsupported = Some(instruction);
        }
    }

    let unique_opcode_count = opcode_counts.iter().filter(|&&count| count > 0).count();
    let supported_unique_opcode_count = opcode_counts
        .iter()
        .enumerate()
        .filter(|&(opcode, &count)| {
            count > 0 && iris_scalar_executor_supports_opcode(opcode_index_to_u8(opcode))
        })
        .count();
    let unsupported_unique_opcode_count = unique_opcode_count - supported_unique_opcode_count;
    let mut unsupported_opcodes = opcode_counts
        .iter()
        .enumerate()
        .filter(|&(opcode, &count)| {
            count > 0 && !iris_scalar_executor_supports_opcode(opcode_index_to_u8(opcode))
        })
        .map(|(opcode, &count)| (opcode_index_to_u8(opcode), count, first_offsets[opcode]))
        .collect::<Vec<_>>();

    unsupported_opcodes
        .sort_by(|left, right| right.1.cmp(&left.1).then_with(|| left.0.cmp(&right.0)));

    let mut report = format!(
        "Iris scalar executor coverage: supportedInstructions={supported_instruction_count}/{instruction_count}, supportedUniqueOpcodes={supported_unique_opcode_count}/{unique_opcode_count}, unsupportedUniqueOpcodes={unsupported_unique_opcode_count}",
    );

    if let Some(instruction) = first_unsupported {
        let _ = write!(
            report,
            ", firstUnsupported={}({})@{}",
            hermes_opcode_name(instruction.opcode),
            instruction.opcode,
            instruction.offset,
        );
    } else {
        report.push_str(", firstUnsupported=none");
    }

    if !unsupported_opcodes.is_empty() {
        report.push_str(", topUnsupported=[");
        for (index, (opcode, count, first_offset)) in unsupported_opcodes
            .iter()
            .take(EXECUTION_GAP_TOP_LIMIT)
            .enumerate()
        {
            if index > 0 {
                report.push_str(", ");
            }
            let _ = write!(
                report,
                "{}({}):{}@{}",
                hermes_opcode_name(*opcode),
                opcode,
                count,
                first_offset,
            );
        }
        report.push(']');
    }

    Ok(report)
}

fn hermes_opcode_name(opcode: u8) -> &'static str {
    HERMES_OPCODE_NAMES
        .get(usize::from(opcode))
        .copied()
        .unwrap_or("Unknown")
}

fn opcode_index_to_u8(opcode: usize) -> u8 {
    u8::try_from(opcode).expect("Hermes opcode table has fewer than 256 entries")
}

fn iris_scalar_executor_supports_opcode(opcode: u8) -> bool {
    matches!(
        opcode,
        1 | 2
            | 4
            | 6
            | 7
            | 8
            | 15
            | 16
            | 19
            | 21
            | 49
            | 51
            | 55
            | 56
            | 57
            | 58
            | 59
            | 60
            | 61
            | 62
            | 64
            | 66
            | 67
            | 68
            | 69
            | 72
            | 74
            | 75
            | 82
            | 83
            | 86
            | 87
            | 93
            | 96
            | 97
            | 99
            | 107
            | 108
            | 110
            | 111
            | 112
            | 115
            | 116
            | 118
            | 121
            | 132
            | 133
            | 134
            | 136
            | 139
            | 140
            | 141
            | 144
            | 153
            | 157
            | 174
            | 175
            | 176
            | 177
            | 178
            | 179
            | 180
            | 181
            | 182
            | 183..=214
    ) || scalar_common_constant(opcode).is_some()
}

fn scalar_common_constant(opcode: u8) -> Option<ScalarValue> {
    match opcode {
        146 => Some(ScalarValue::Empty),
        147 => Some(ScalarValue::Undefined),
        148 => Some(ScalarValue::Null),
        149 => Some(ScalarValue::Boolean(true)),
        150 => Some(ScalarValue::Boolean(false)),
        151 => Some(ScalarValue::Number(0.0)),
        _ => None,
    }
}

fn validate_header_counts(header: HermesBytecodeHeader) -> Result<(), ParseError> {
    if header.identifier_count > header.string_count {
        return Err(ParseError::InvalidHeaderCount {
            field: "identifier_count",
            value: header.identifier_count,
            limit: header.string_count,
        });
    }
    if header.function_count == 0 {
        if header.global_code_index != 0 {
            return Err(ParseError::InvalidHeaderCount {
                field: "global_code_index",
                value: header.global_code_index,
                limit: 0,
            });
        }
    } else if header.global_code_index >= header.function_count {
        return Err(ParseError::InvalidHeaderCount {
            field: "global_code_index",
            value: header.global_code_index,
            limit: header.function_count - 1,
        });
    }
    Ok(())
}

fn take_section<'a>(
    file_bytes: &'a [u8],
    cursor: &mut usize,
    section: &'static str,
    count: u32,
    entry_size: usize,
) -> Result<SectionView<'a>, ParseError> {
    *cursor = align_offset(*cursor, section)?;
    let size = section_size(section, count, entry_size)?;
    let offset = *cursor;
    let end = offset
        .checked_add(size)
        .ok_or(ParseError::SectionOutOfBounds {
            section,
            offset,
            size,
            file_length: file_bytes.len(),
        })?;

    let bytes = file_bytes
        .get(offset..end)
        .ok_or(ParseError::SectionOutOfBounds {
            section,
            offset,
            size,
            file_length: file_bytes.len(),
        })?;
    *cursor = end;

    let offset_u32 =
        u32::try_from(offset).map_err(|_| ParseError::OffsetExceedsU32 { section, offset })?;
    Ok(SectionView {
        offset: offset_u32,
        bytes,
    })
}

fn align_offset(offset: usize, section: &'static str) -> Result<usize, ParseError> {
    offset
        .checked_add(HERMES_BYTECODE_ALIGNMENT - 1)
        .map(|adjusted| adjusted / HERMES_BYTECODE_ALIGNMENT * HERMES_BYTECODE_ALIGNMENT)
        .ok_or(ParseError::OffsetExceedsU32 { section, offset })
}

fn section_size(section: &'static str, count: u32, entry_size: usize) -> Result<usize, ParseError> {
    usize::try_from(count)
        .expect("u32 always fits in usize on supported targets")
        .checked_mul(entry_size)
        .ok_or(ParseError::SectionSizeOverflow {
            section,
            count,
            entry_size,
        })
}

fn validate_string_kind_runs(
    bytes: &[u8],
    string_count: u32,
    identifier_count: u32,
) -> Result<(), ParseError> {
    let mut run_length = 0_u32;
    let mut identifier_run_length = 0_u32;
    for entry in bytes.chunks_exact(STRING_KIND_ENTRY_SIZE) {
        let datum = read_u32(entry, 0);
        let count = datum & 0x7fff_ffff;
        run_length =
            run_length
                .checked_add(count)
                .ok_or(ParseError::InvalidStringKindRunLength {
                    string_count,
                    run_length: u32::MAX,
                })?;
        if datum & 0x8000_0000 != 0 {
            identifier_run_length = identifier_run_length.checked_add(count).ok_or(
                ParseError::InvalidStringKindIdentifierCount {
                    identifier_count,
                    run_length: u32::MAX,
                },
            )?;
        }
    }
    if run_length != string_count {
        return Err(ParseError::InvalidStringKindRunLength {
            string_count,
            run_length,
        });
    }
    if identifier_run_length != identifier_count {
        return Err(ParseError::InvalidStringKindIdentifierCount {
            identifier_count,
            run_length: identifier_run_length,
        });
    }
    Ok(())
}

fn validate_string_table(
    small_entries: &[u8],
    overflow_entries: &[u8],
    overflow_count: u32,
    storage_size: u32,
) -> Result<(), ParseError> {
    for (index, entry) in small_entries
        .chunks_exact(SMALL_STRING_TABLE_ENTRY_SIZE)
        .enumerate()
    {
        let small = read_u32(entry, 0);
        let string_index = u32::try_from(index).expect("validated string table index fits in u32");
        let entry =
            decode_string_table_entry(small, string_index, overflow_entries, overflow_count)?;

        if entry
            .offset
            .checked_add(entry.length)
            .is_none_or(|end| end > storage_size)
        {
            return Err(ParseError::StringTableEntryOutOfBounds {
                string_index,
                offset: entry.offset,
                length: entry.length,
                storage_size,
            });
        }
    }
    Ok(())
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct DecodedStringTableEntry {
    offset: u32,
    length: u32,
    is_utf16: bool,
}

fn decode_string_table_entry(
    small: u32,
    string_index: u32,
    overflow_entries: &[u8],
    overflow_count: u32,
) -> Result<DecodedStringTableEntry, ParseError> {
    let is_utf16 = small & SMALL_STRING_UTF16_FLAG != 0;
    let offset_or_overflow_index = (small >> SMALL_STRING_OFFSET_SHIFT) & SMALL_STRING_OFFSET_MASK;
    let length = small >> SMALL_STRING_LENGTH_SHIFT;

    if length != SMALL_STRING_OVERFLOW_LENGTH {
        return Ok(DecodedStringTableEntry {
            offset: offset_or_overflow_index,
            length,
            is_utf16,
        });
    }

    if offset_or_overflow_index >= overflow_count {
        return Err(ParseError::InvalidOverflowStringIndex {
            string_index,
            overflow_index: offset_or_overflow_index,
            overflow_count,
        });
    }

    let overflow_offset = usize::try_from(offset_or_overflow_index)
        .expect("u32 always fits in usize on supported targets")
        * OVERFLOW_STRING_TABLE_ENTRY_SIZE;
    let overflow =
        &overflow_entries[overflow_offset..overflow_offset + OVERFLOW_STRING_TABLE_ENTRY_SIZE];

    Ok(DecodedStringTableEntry {
        offset: read_u32(overflow, 0),
        length: read_u32(overflow, 4),
        is_utf16,
    })
}

fn string_at<'a>(
    header: HermesBytecodeHeader,
    sections: &HermesBytecodeSections<'a>,
    string_id: u32,
) -> Result<HermesString<'a>, ParseError> {
    if string_id >= header.string_count {
        return Err(ParseError::InvalidStringIndex {
            string_id,
            string_count: header.string_count,
        });
    }

    let small_offset = usize::try_from(string_id)
        .expect("u32 always fits in usize on supported targets")
        * SMALL_STRING_TABLE_ENTRY_SIZE;
    let small = read_u32(sections.small_string_table().bytes(), small_offset);
    let entry = decode_string_table_entry(
        small,
        string_id,
        sections.overflow_string_table().bytes(),
        header.overflow_string_count,
    )?;

    if entry
        .offset
        .checked_add(entry.length)
        .is_none_or(|end| end > header.string_storage_size)
    {
        return Err(ParseError::StringTableEntryOutOfBounds {
            string_index: string_id,
            offset: entry.offset,
            length: entry.length,
            storage_size: header.string_storage_size,
        });
    }

    let start =
        usize::try_from(entry.offset).expect("u32 always fits in usize on supported targets");
    let end = usize::try_from(entry.offset + entry.length)
        .expect("u32 always fits in usize on supported targets");

    Ok(HermesString {
        string_id,
        offset: entry.offset,
        bytes: &sections.string_storage().bytes()[start..end],
        is_utf16: entry.is_utf16,
    })
}

fn validate_storage_table(
    section: &'static str,
    entries: &[u8],
    storage_size: u32,
) -> Result<(), ParseError> {
    for (index, entry) in entries.chunks_exact(U32_PAIR_ENTRY_SIZE).enumerate() {
        let offset = read_u32(entry, 0);
        let length = read_u32(entry, 4);
        if offset
            .checked_add(length)
            .is_none_or(|end| end > storage_size)
        {
            return Err(ParseError::StorageTableEntryOutOfBounds {
                section,
                entry_index: u32::try_from(index)
                    .expect("validated storage table index fits in u32"),
                offset,
                length,
                storage_size,
            });
        }
    }
    Ok(())
}

fn validate_object_shape_table(
    entries: &[u8],
    obj_key_buffer: &[u8],
    string_kinds: &[u8],
    header: HermesBytecodeHeader,
) -> Result<(), ParseError> {
    for entry in entries.chunks_exact(SHAPE_TABLE_ENTRY_SIZE) {
        let shape = object_shape_entry(entry);
        validate_serialized_literal_buffer(
            "obj_key_buffer",
            obj_key_buffer,
            shape.key_buffer_offset,
            shape.num_props,
            true,
            Some(string_kinds),
            header,
        )?;
    }
    Ok(())
}

fn object_shape_entry(bytes: &[u8]) -> ObjectShapeEntry {
    ObjectShapeEntry {
        key_buffer_offset: read_u32(bytes, 0),
        num_props: read_u32(bytes, 4),
    }
}

fn object_shape_entry_at(entries: &[u8], shape_index: u32) -> Option<ObjectShapeEntry> {
    let start = usize::try_from(shape_index)
        .expect("u32 always fits in usize on supported targets")
        .checked_mul(SHAPE_TABLE_ENTRY_SIZE)?;
    let end = start.checked_add(SHAPE_TABLE_ENTRY_SIZE)?;
    entries.get(start..end).map(object_shape_entry)
}

fn validate_serialized_literal_buffer(
    buffer_name: &'static str,
    buffer: &[u8],
    offset: u32,
    element_count: u32,
    is_key_buffer: bool,
    identifier_string_kinds: Option<&[u8]>,
    header: HermesBytecodeHeader,
) -> Result<(), ParseError> {
    let buffer_size =
        u32::try_from(buffer.len()).expect("validated HBC section length fits in u32");
    if offset > buffer_size {
        return Err(ParseError::InvalidSerializedLiteralBuffer {
            buffer: buffer_name,
            offset,
            element_count,
            buffer_size,
        });
    }

    let mut remaining = element_count;
    let mut cursor =
        usize::try_from(offset).expect("u32 always fits in usize on supported targets");
    while remaining > 0 {
        let tag_offset = cursor;
        let Some(&tag) = buffer.get(cursor) else {
            return Err(ParseError::InvalidSerializedLiteralBuffer {
                buffer: buffer_name,
                offset,
                element_count,
                buffer_size,
            });
        };
        cursor += 1;

        let sequence_len = if tag & SERIALIZED_LITERAL_TAG_LONG_SEQUENCE != 0 {
            let Some(&low_len) = buffer.get(cursor) else {
                return Err(ParseError::InvalidSerializedLiteralBuffer {
                    buffer: buffer_name,
                    offset,
                    element_count,
                    buffer_size,
                });
            };
            cursor += 1;
            (u32::from(tag & SERIALIZED_LITERAL_TAG_LENGTH_MASK) << 8) | u32::from(low_len)
        } else {
            u32::from(tag & SERIALIZED_LITERAL_TAG_LENGTH_MASK)
        };
        if sequence_len == 0 {
            return Err(ParseError::InvalidSerializedLiteralBuffer {
                buffer: buffer_name,
                offset,
                element_count,
                buffer_size,
            });
        }

        let tag_type = tag & SERIALIZED_LITERAL_TAG_MASK;
        if is_key_buffer
            && matches!(
                tag_type,
                SERIALIZED_LITERAL_TAG_TRUE
                    | SERIALIZED_LITERAL_TAG_FALSE
                    | SERIALIZED_LITERAL_TAG_UNDEFINED
            )
        {
            return Err(ParseError::InvalidSerializedLiteralTag {
                buffer: buffer_name,
                offset: u32::try_from(tag_offset)
                    .expect("validated HBC section offset fits in u32"),
                tag,
            });
        }

        let to_read = remaining.min(sequence_len);
        let data_size = serialized_literal_data_size(tag_type);
        let bytes_to_read =
            to_read
                .checked_mul(data_size)
                .ok_or(ParseError::InvalidSerializedLiteralBuffer {
                    buffer: buffer_name,
                    offset,
                    element_count,
                    buffer_size,
                })?;
        let end = cursor
            .checked_add(
                usize::try_from(bytes_to_read)
                    .expect("u32 always fits in usize on supported targets"),
            )
            .ok_or(ParseError::InvalidSerializedLiteralBuffer {
                buffer: buffer_name,
                offset,
                element_count,
                buffer_size,
            })?;
        if end > buffer.len() {
            return Err(ParseError::InvalidSerializedLiteralBuffer {
                buffer: buffer_name,
                offset,
                element_count,
                buffer_size,
            });
        }

        validate_serialized_literal_strings(
            buffer_name,
            buffer,
            cursor,
            to_read,
            tag_type,
            header,
            identifier_string_kinds,
        )?;
        cursor = end;
        remaining -= to_read;
    }
    Ok(())
}

fn serialized_literal_data_size(tag_type: u8) -> u32 {
    match tag_type {
        SERIALIZED_LITERAL_TAG_SHORT_STRING => 2,
        SERIALIZED_LITERAL_TAG_LONG_STRING
        | SERIALIZED_LITERAL_TAG_INTEGER
        | SERIALIZED_LITERAL_TAG_NUMBER => {
            if tag_type == SERIALIZED_LITERAL_TAG_NUMBER {
                8
            } else {
                4
            }
        }
        _ => 0,
    }
}

fn validate_serialized_literal_strings(
    buffer_name: &'static str,
    buffer: &[u8],
    start: usize,
    element_count: u32,
    tag_type: u8,
    header: HermesBytecodeHeader,
    identifier_string_kinds: Option<&[u8]>,
) -> Result<(), ParseError> {
    match tag_type {
        SERIALIZED_LITERAL_TAG_SHORT_STRING => {
            for index in 0..element_count {
                let offset = start
                    + usize::try_from(index)
                        .expect("u32 always fits in usize on supported targets")
                        * 2;
                let string_id = u32::from(u16::from_le_bytes(
                    buffer[offset..offset + 2]
                        .try_into()
                        .expect("validated serialized literal string id has u16 width"),
                ));
                validate_serialized_literal_string(
                    buffer_name,
                    offset,
                    string_id,
                    header,
                    identifier_string_kinds,
                )?;
            }
        }
        SERIALIZED_LITERAL_TAG_LONG_STRING => {
            for index in 0..element_count {
                let offset = start
                    + usize::try_from(index)
                        .expect("u32 always fits in usize on supported targets")
                        * 4;
                validate_serialized_literal_string(
                    buffer_name,
                    offset,
                    read_u32(buffer, offset),
                    header,
                    identifier_string_kinds,
                )?;
            }
        }
        _ => {}
    }
    Ok(())
}

fn validate_serialized_literal_string(
    buffer_name: &'static str,
    offset: usize,
    string_id: u32,
    header: HermesBytecodeHeader,
    identifier_string_kinds: Option<&[u8]>,
) -> Result<(), ParseError> {
    if string_id >= header.string_count
        || identifier_string_kinds
            .is_some_and(|string_kinds| !is_identifier_string_id(string_kinds, string_id))
    {
        return Err(ParseError::InvalidSerializedLiteralStringReference {
            buffer: buffer_name,
            offset: u32::try_from(offset).expect("validated HBC section offset fits in u32"),
            string_id,
            string_count: header.string_count,
        });
    }
    Ok(())
}

fn is_identifier_string_id(string_kinds: &[u8], string_id: u32) -> bool {
    let mut run_start = 0_u32;
    for entry in string_kinds.chunks_exact(STRING_KIND_ENTRY_SIZE) {
        let datum = read_u32(entry, 0);
        let run_len = datum & 0x7fff_ffff;
        let run_end = run_start.saturating_add(run_len);

        if string_id < run_end {
            return datum & 0x8000_0000 != 0;
        }

        run_start = run_end;
    }
    false
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct DecodedSmallFunctionHeader {
    header: HermesFunctionHeader,
    overflowed: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct DecodedFunctionHeader {
    header: HermesFunctionHeader,
    large_header_offset: Option<u32>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct DebugInfoBounds {
    debug_data_offset: u32,
    debug_data_size: u32,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct DebugSourceStream {
    source_locations: u32,
    end_offset: u32,
}

fn function_header_at(
    bytes: &[u8],
    header: HermesBytecodeHeader,
    function_headers: SectionView<'_>,
    function_id: u32,
) -> Result<HermesFunctionHeader, ParseError> {
    decoded_function_header_at(bytes, header, function_headers, function_id)
        .map(|decoded| decoded.header)
}

fn decoded_function_header_at(
    bytes: &[u8],
    header: HermesBytecodeHeader,
    function_headers: SectionView<'_>,
    function_id: u32,
) -> Result<DecodedFunctionHeader, ParseError> {
    if function_id >= header.function_count {
        return Err(ParseError::InvalidFunctionIndex {
            function_id,
            function_count: header.function_count,
        });
    }

    let function_index =
        usize::try_from(function_id).expect("u32 always fits in usize on supported targets");
    let offset = function_index * SMALL_FUNC_HEADER_SIZE;
    let small_header = &function_headers.bytes[offset..offset + SMALL_FUNC_HEADER_SIZE];
    let decoded = parse_small_function_header(small_header);
    if !decoded.overflowed {
        return Ok(DecodedFunctionHeader {
            header: decoded.header,
            large_header_offset: None,
        });
    }

    let large_header_offset = large_header_offset_from_small(decoded.header);
    let large_header_start = usize::try_from(large_header_offset)
        .expect("u32 always fits in usize on supported targets");
    let file_length =
        usize::try_from(header.file_length).expect("u32 always fits in usize on supported targets");
    let large_header_end = large_header_start
        .checked_add(LARGE_FUNC_HEADER_SIZE)
        .ok_or(ParseError::LargeFunctionHeaderOutOfBounds {
            function_id,
            offset: large_header_offset,
            file_length: header.file_length,
        })?;
    if large_header_end > file_length {
        return Err(ParseError::LargeFunctionHeaderOutOfBounds {
            function_id,
            offset: large_header_offset,
            file_length: header.file_length,
        });
    }

    Ok(DecodedFunctionHeader {
        header: parse_large_function_header(&bytes[large_header_start..large_header_end]),
        large_header_offset: Some(large_header_offset),
    })
}

fn parse_small_function_header(bytes: &[u8]) -> DecodedSmallFunctionHeader {
    let first_word = read_u32(bytes, 0);
    let second_word = read_u32(bytes, 4);
    let frame_size = bytes[8];
    let read_cache_size = bytes[9];
    let cache_sizes = bytes[10];
    let flags = bytes[11];

    DecodedSmallFunctionHeader {
        header: HermesFunctionHeader {
            offset: first_word & 0x01ff_ffff,
            param_count: (first_word >> 25) & 0x1f,
            loop_depth: (first_word >> 30) & 0x03,
            bytecode_size_in_bytes: second_word & 0x3fff,
            function_name: (second_word >> 14) & 0xff,
            number_reg_count: (second_word >> 22) & 0x1f,
            non_ptr_reg_count: (second_word >> 27) & 0x1f,
            frame_size: u32::from(frame_size),
            read_cache_size,
            write_cache_size: cache_sizes & 0x7f,
            private_name_cache_size: cache_sizes >> 7,
            flags,
        },
        overflowed: flags & 0b0010_0000 != 0,
    }
}

fn parse_large_function_header(bytes: &[u8]) -> HermesFunctionHeader {
    HermesFunctionHeader {
        offset: read_u32(bytes, 0),
        param_count: read_u32(bytes, 4),
        loop_depth: read_u32(bytes, 8),
        bytecode_size_in_bytes: read_u32(bytes, 12),
        function_name: read_u32(bytes, 16),
        number_reg_count: read_u32(bytes, 20),
        non_ptr_reg_count: read_u32(bytes, 24),
        frame_size: read_u32(bytes, 28),
        read_cache_size: bytes[32],
        write_cache_size: bytes[33],
        private_name_cache_size: bytes[34],
        flags: bytes[35],
    }
}

fn large_header_offset_from_small(header: HermesFunctionHeader) -> u32 {
    ((header.function_name & 0xff) << 24) | (header.offset & 0x00ff_ffff)
}

fn parse_debug_info(
    bytes: &[u8],
    header: HermesBytecodeHeader,
) -> Result<Option<DebugInfoBounds>, ParseError> {
    if header.debug_info_offset == 0 {
        return Ok(None);
    }

    let limit = header
        .file_length
        .saturating_sub(HERMES_BYTECODE_FOOTER_SIZE as u32);
    let debug_header = debug_info_bytes(
        bytes,
        header.debug_info_offset,
        DEBUG_INFO_HEADER_SIZE as u32,
        limit,
    )?;
    let filename_count = read_u32(debug_header, 0);
    let filename_storage_size = read_u32(debug_header, 4);
    let file_region_count = read_u32(debug_header, 8);
    let debug_data_size = read_u32(debug_header, 12);

    let filename_table_size = filename_count
        .checked_mul(STRING_TABLE_ENTRY_SIZE as u32)
        .ok_or(ParseError::DebugInfoOutOfBounds {
            offset: header
                .debug_info_offset
                .saturating_add(DEBUG_INFO_HEADER_SIZE as u32),
            size: u32::MAX,
            limit,
        })?;
    let file_region_table_size = file_region_count
        .checked_mul(DEBUG_FILE_REGION_SIZE as u32)
        .ok_or(ParseError::DebugInfoOutOfBounds {
            offset: header
                .debug_info_offset
                .saturating_add(DEBUG_INFO_HEADER_SIZE as u32),
            size: u32::MAX,
            limit,
        })?;

    let mut cursor = header
        .debug_info_offset
        .checked_add(DEBUG_INFO_HEADER_SIZE as u32)
        .ok_or(ParseError::DebugInfoOutOfBounds {
            offset: header.debug_info_offset,
            size: DEBUG_INFO_HEADER_SIZE as u32,
            limit,
        })?;
    let filename_table_offset = cursor;
    cursor = checked_debug_info_end(cursor, filename_table_size, limit)?;
    let filename_storage_offset = cursor;
    cursor = checked_debug_info_end(cursor, filename_storage_size, limit)?;
    let file_region_table_offset = cursor;
    cursor = checked_debug_info_end(cursor, file_region_table_size, limit)?;
    let debug_data_offset = cursor;
    checked_debug_info_end(cursor, debug_data_size, limit)?;

    let filename_table =
        debug_info_bytes(bytes, filename_table_offset, filename_table_size, limit)?;
    validate_debug_filename_table(filename_table, filename_storage_size)?;
    debug_info_bytes(bytes, filename_storage_offset, filename_storage_size, limit)?;
    let file_region_table = debug_info_bytes(
        bytes,
        file_region_table_offset,
        file_region_table_size,
        limit,
    )?;
    validate_debug_file_regions(file_region_table, filename_count, debug_data_size)?;

    Ok(Some(DebugInfoBounds {
        debug_data_offset,
        debug_data_size,
    }))
}

fn validate_debug_filename_table(bytes: &[u8], storage_size: u32) -> Result<(), ParseError> {
    for (index, entry) in bytes.chunks_exact(STRING_TABLE_ENTRY_SIZE).enumerate() {
        let offset = read_u32(entry, 0);
        let raw_length = read_u32(entry, 4);
        let length = raw_length & !STRING_TABLE_ENTRY_UTF16_MASK;
        let byte_length = if raw_length & STRING_TABLE_ENTRY_UTF16_MASK == 0 {
            length
        } else {
            length
                .checked_mul(2)
                .ok_or(ParseError::DebugFilenameOutOfBounds {
                    filename_index: u32::try_from(index)
                        .expect("validated debug filename index fits in u32"),
                    offset,
                    length: u32::MAX,
                    storage_size,
                })?
        };
        if offset
            .checked_add(byte_length)
            .is_none_or(|end| end > storage_size)
        {
            return Err(ParseError::DebugFilenameOutOfBounds {
                filename_index: u32::try_from(index)
                    .expect("validated debug filename index fits in u32"),
                offset,
                length: byte_length,
                storage_size,
            });
        }
    }
    Ok(())
}

fn validate_debug_file_regions(
    bytes: &[u8],
    filename_count: u32,
    debug_data_size: u32,
) -> Result<(), ParseError> {
    let mut previous_from_address = None;
    for (index, region) in bytes.chunks_exact(DEBUG_FILE_REGION_SIZE).enumerate() {
        let from_address = read_u32(region, 0);
        let filename_id = read_u32(region, 4);
        let source_mapping_url_id = read_u32(region, 8);
        if index == 0 && from_address != 0 {
            return Err(ParseError::InvalidDebugFileRegionStart { from_address });
        }
        if let Some(previous) = previous_from_address {
            if from_address <= previous {
                return Err(ParseError::InvalidDebugFileRegionOrder {
                    region_index: u32::try_from(index)
                        .expect("validated debug file region index fits in u32"),
                    previous_from_address: previous,
                    from_address,
                });
            }
        }
        let valid_source_mapping_url = source_mapping_url_id == DEBUG_SOURCE_MAPPING_URL_INVALID
            || source_mapping_url_id < filename_count;
        if from_address >= debug_data_size
            || filename_id >= filename_count
            || !valid_source_mapping_url
        {
            return Err(ParseError::InvalidDebugFileRegion {
                region_index: u32::try_from(index)
                    .expect("validated debug file region index fits in u32"),
                from_address,
                filename_id,
                source_mapping_url_id,
                filename_count,
                debug_data_size,
            });
        }
        previous_from_address = Some(from_address);
    }
    Ok(())
}

fn checked_debug_info_end(offset: u32, size: u32, limit: u32) -> Result<u32, ParseError> {
    let end = offset
        .checked_add(size)
        .ok_or(ParseError::DebugInfoOutOfBounds {
            offset,
            size,
            limit,
        })?;
    if end > limit {
        return Err(ParseError::DebugInfoOutOfBounds {
            offset,
            size,
            limit,
        });
    }
    Ok(end)
}

fn debug_info_bytes(bytes: &[u8], offset: u32, size: u32, limit: u32) -> Result<&[u8], ParseError> {
    let end = checked_debug_info_end(offset, size, limit)?;
    let start = usize::try_from(offset).expect("u32 always fits in usize on supported targets");
    let end = usize::try_from(end).expect("u32 always fits in usize on supported targets");
    bytes
        .get(start..end)
        .ok_or(ParseError::DebugInfoOutOfBounds {
            offset,
            size,
            limit,
        })
}

fn validate_function_headers(
    bytes: &[u8],
    header: HermesBytecodeHeader,
    function_headers: SectionView<'_>,
    function_bodies_offset: u32,
    literal_value_buffer: SectionView<'_>,
    obj_shape_table: SectionView<'_>,
    debug_info: Option<DebugInfoBounds>,
) -> Result<(), ParseError> {
    let body_limit = function_body_limit(bytes, header, function_headers)?;
    let mut decoded_headers = Vec::with_capacity(
        usize::try_from(header.function_count)
            .expect("u32 always fits in usize on supported targets"),
    );
    for function_id in 0..header.function_count {
        decoded_headers.push(decoded_function_header_at(
            bytes,
            header,
            function_headers,
            function_id,
        )?);
    }

    let mut debug_streams = Vec::new();
    for function_id in 0..header.function_count {
        let decoded = decoded_headers
            [usize::try_from(function_id).expect("u32 always fits in usize on supported targets")];
        let function_header = decoded.header;
        let function_region_limit = function_region_limit(function_header, &decoded_headers)
            .unwrap_or(body_limit)
            .min(body_limit);
        validate_function_body(
            bytes,
            function_id,
            function_header,
            function_bodies_offset,
            function_region_limit,
            InstructionValidationContext {
                header,
                function_region_limit,
                literal_value_buffer: literal_value_buffer.bytes,
                obj_shape_table: obj_shape_table.bytes,
            },
        )?;
        if let Some(stream) = validate_function_info(
            bytes,
            function_id,
            decoded,
            function_info_region_limit(header, decoded.large_header_offset, &decoded_headers),
            debug_info,
        )? {
            debug_streams.push(stream);
        }
    }
    if let Some(debug_info) = debug_info {
        validate_debug_data_coverage(debug_info.debug_data_size, &mut debug_streams)?;
    }
    Ok(())
}

fn validate_function_body(
    bytes: &[u8],
    function_id: u32,
    function_header: HermesFunctionHeader,
    function_bodies_offset: u32,
    limit: u32,
    context: InstructionValidationContext<'_>,
) -> Result<(), ParseError> {
    let body_end = function_header
        .offset
        .checked_add(function_header.bytecode_size_in_bytes);
    if function_header.offset < function_bodies_offset || body_end.is_none_or(|end| end > limit) {
        return Err(ParseError::FunctionBodyOutOfBounds {
            function_id,
            offset: function_header.offset,
            size: function_header.bytecode_size_in_bytes,
            function_bodies_offset,
            limit,
        });
    }
    validate_instruction_stream(
        bytes,
        function_id,
        function_body(bytes, function_id, function_header)?,
        context,
    )
}

fn validate_function_info(
    bytes: &[u8],
    function_id: u32,
    decoded: DecodedFunctionHeader,
    limit: u32,
    debug_info: Option<DebugInfoBounds>,
) -> Result<Option<DebugSourceStream>, ParseError> {
    if !decoded.header.has_exception_handler() && !decoded.header.has_debug_info() {
        return Ok(None);
    }
    let Some(info_offset) = decoded.large_header_offset else {
        return Err(ParseError::MissingFunctionInfo { function_id });
    };

    let mut cursor = info_offset
        .checked_add(LARGE_FUNC_HEADER_SIZE as u32)
        .and_then(|offset| align_u32(offset, FUNCTION_INFO_ALIGNMENT))
        .ok_or(ParseError::FunctionInfoOutOfBounds {
            function_id,
            offset: u32::MAX,
            size: EXCEPTION_HANDLER_TABLE_HEADER_SIZE as u32,
            limit,
        })?;

    if decoded.header.has_exception_handler() {
        let table_header = function_info_bytes(
            bytes,
            function_id,
            cursor,
            EXCEPTION_HANDLER_TABLE_HEADER_SIZE as u32,
            limit,
        )?;
        let entry_count = read_u32(table_header, 0);
        let table_offset = cursor
            .checked_add(EXCEPTION_HANDLER_TABLE_HEADER_SIZE as u32)
            .ok_or(ParseError::FunctionInfoOutOfBounds {
                function_id,
                offset: cursor,
                size: EXCEPTION_HANDLER_TABLE_HEADER_SIZE as u32,
                limit,
            })?;
        let table_size = entry_count
            .checked_mul(EXCEPTION_HANDLER_ENTRY_SIZE as u32)
            .ok_or(ParseError::FunctionInfoOutOfBounds {
                function_id,
                offset: table_offset,
                size: u32::MAX,
                limit,
            })?;
        let table_end =
            table_offset
                .checked_add(table_size)
                .ok_or(ParseError::FunctionInfoOutOfBounds {
                    function_id,
                    offset: table_offset,
                    size: table_size,
                    limit,
                })?;
        let table = function_info_bytes(bytes, function_id, table_offset, table_size, limit)?;
        let body = function_body(bytes, function_id, decoded.header)?;
        let boundaries = instruction_boundaries(function_id, body)?;

        for (entry_index, entry) in table.chunks_exact(EXCEPTION_HANDLER_ENTRY_SIZE).enumerate() {
            validate_exception_handler(
                function_id,
                body,
                &boundaries,
                u32::try_from(entry_index).expect("validated exception handler index fits in u32"),
                read_u32(entry, 0),
                read_u32(entry, 4),
                read_u32(entry, 8),
            )?;
        }
        cursor = table_end;
    }

    if decoded.header.has_debug_info() {
        let debug_offsets_offset = align_u32(cursor, FUNCTION_INFO_ALIGNMENT).ok_or(
            ParseError::FunctionInfoOutOfBounds {
                function_id,
                offset: cursor,
                size: DEBUG_OFFSETS_SIZE as u32,
                limit,
            },
        )?;
        let debug_offsets = function_info_bytes(
            bytes,
            function_id,
            debug_offsets_offset,
            DEBUG_OFFSETS_SIZE as u32,
            limit,
        )?;
        let body = function_body(bytes, function_id, decoded.header)?;
        let boundaries = instruction_boundaries(function_id, body)?;
        validate_debug_offsets(
            bytes,
            function_id,
            body,
            &boundaries,
            read_u32(debug_offsets, 0),
            debug_info,
        )
    } else {
        Ok(None)
    }
}

fn validate_debug_offsets(
    bytes: &[u8],
    function_id: u32,
    body: SectionView<'_>,
    boundaries: &[u32],
    source_locations: u32,
    debug_info: Option<DebugInfoBounds>,
) -> Result<Option<DebugSourceStream>, ParseError> {
    if source_locations == DEBUG_OFFSETS_NO_OFFSET {
        return Ok(None);
    }
    let Some(debug_info) = debug_info else {
        return Err(ParseError::InvalidDebugOffset {
            function_id,
            source_locations,
            debug_data_size: 0,
        });
    };
    let debug_data_size = debug_info.debug_data_size;
    if source_locations >= debug_data_size {
        return Err(ParseError::InvalidDebugOffset {
            function_id,
            source_locations,
            debug_data_size,
        });
    }

    let stream_offset = debug_info
        .debug_data_offset
        .checked_add(source_locations)
        .ok_or(ParseError::InvalidDebugData {
            function_id,
            offset: source_locations,
            reason: DEBUG_DATA_ADDRESS_OUT_OF_BOUNDS,
        })?;
    let stream_size =
        debug_data_size
            .checked_sub(source_locations)
            .ok_or(ParseError::InvalidDebugOffset {
                function_id,
                source_locations,
                debug_data_size,
            })?;
    let stream = debug_info_bytes(bytes, stream_offset, stream_size, u32::MAX).map_err(|_| {
        ParseError::InvalidDebugData {
            function_id,
            offset: source_locations,
            reason: DEBUG_DATA_TRUNCATED_LEB,
        }
    })?;
    let end_offset =
        validate_debug_source_locations(function_id, body, boundaries, source_locations, stream)?;
    Ok(Some(DebugSourceStream {
        source_locations,
        end_offset,
    }))
}

fn validate_debug_source_locations(
    function_id: u32,
    body: SectionView<'_>,
    boundaries: &[u32],
    source_locations: u32,
    data: &[u8],
) -> Result<u32, ParseError> {
    let mut cursor = 0_usize;
    let stream_function_id = read_signed_leb128(data, &mut cursor, function_id, source_locations)?;
    if stream_function_id < 0 || u32::try_from(stream_function_id).ok() != Some(function_id) {
        return Err(ParseError::InvalidDebugData {
            function_id,
            offset: source_locations,
            reason: DEBUG_DATA_FUNCTION_MISMATCH,
        });
    }

    let mut current_line = read_debug_u32(data, &mut cursor, function_id, source_locations)?;
    let mut current_column = read_debug_u32(data, &mut cursor, function_id, source_locations)?;
    let mut current_statement = 0_u32;
    let mut current_env_idx = read_debug_u32(data, &mut cursor, function_id, source_locations)?;
    validate_debug_location_line_column(
        function_id,
        source_locations,
        current_line,
        current_column,
        true,
    )?;

    let mut current_address = 0_i64;
    loop {
        let address_delta_offset = debug_data_offset(source_locations, cursor);
        let address_delta = read_signed_leb128(data, &mut cursor, function_id, source_locations)?;
        if address_delta == -1 {
            let relative_end =
                u32::try_from(cursor).expect("debug source-location stream cursor fits in u32");
            return Ok(source_locations + relative_end);
        }
        current_address =
            current_address
                .checked_add(address_delta)
                .ok_or(ParseError::InvalidDebugData {
                    function_id,
                    offset: address_delta_offset,
                    reason: DEBUG_DATA_ADDRESS_OUT_OF_BOUNDS,
                })?;
        if current_address < 0 || current_address >= i64::from(body.len()) {
            return Err(ParseError::InvalidDebugData {
                function_id,
                offset: address_delta_offset,
                reason: DEBUG_DATA_ADDRESS_OUT_OF_BOUNDS,
            });
        }
        let relative_address =
            u32::try_from(current_address).expect("validated non-negative address fits in u32");
        if !relative_instruction_boundary(body, relative_address, boundaries, false) {
            return Err(ParseError::InvalidDebugData {
                function_id,
                offset: address_delta_offset,
                reason: DEBUG_DATA_ADDRESS_NOT_BOUNDARY,
            });
        }

        let line_delta_offset = debug_data_offset(source_locations, cursor);
        let line_delta = read_signed_leb128(data, &mut cursor, function_id, source_locations)?;
        if line_delta & 1 == 0 {
            continue;
        }
        let column_delta_offset = debug_data_offset(source_locations, cursor);
        let column_delta = read_signed_leb128(data, &mut cursor, function_id, source_locations)?;
        let mut statement_delta = 0_i64;
        if line_delta & 2 != 0 {
            statement_delta = read_signed_leb128(data, &mut cursor, function_id, source_locations)?;
        }
        let mut env_idx_delta = 0_i64;
        if line_delta & 4 != 0 {
            env_idx_delta = read_signed_leb128(data, &mut cursor, function_id, source_locations)?;
        }
        current_line = add_debug_u32_delta(
            current_line,
            line_delta >> 3,
            function_id,
            line_delta_offset,
        )?;
        current_column = add_debug_u32_delta(
            current_column,
            column_delta,
            function_id,
            column_delta_offset,
        )?;
        current_statement = add_debug_u32_delta(
            current_statement,
            statement_delta,
            function_id,
            line_delta_offset,
        )?;
        current_env_idx = add_debug_u32_delta(
            current_env_idx,
            env_idx_delta,
            function_id,
            line_delta_offset,
        )?;
        validate_debug_location_line_column(
            function_id,
            line_delta_offset,
            current_line,
            current_column,
            false,
        )?;
    }
}

fn validate_debug_data_coverage(
    debug_data_size: u32,
    streams: &mut [DebugSourceStream],
) -> Result<(), ParseError> {
    if streams.is_empty() {
        return Ok(());
    }
    streams.sort_by_key(|stream| stream.source_locations);
    let mut expected_offset = 0_u32;
    for stream in streams {
        if stream.source_locations != expected_offset {
            return Err(ParseError::InvalidDebugDataCoverage {
                expected_offset,
                actual_offset: stream.source_locations,
                debug_data_size,
            });
        }
        expected_offset = stream.end_offset;
    }
    if expected_offset != debug_data_size {
        return Err(ParseError::InvalidDebugDataCoverage {
            expected_offset,
            actual_offset: debug_data_size,
            debug_data_size,
        });
    }
    Ok(())
}

fn read_debug_u32(
    data: &[u8],
    cursor: &mut usize,
    function_id: u32,
    source_locations: u32,
) -> Result<u32, ParseError> {
    let start = *cursor;
    let value = read_signed_leb128(data, cursor, function_id, source_locations)?;
    u32::try_from(value).map_err(|_| ParseError::InvalidDebugData {
        function_id,
        offset: debug_data_offset(source_locations, start),
        reason: DEBUG_DATA_SOURCE_VALUE_OUT_OF_BOUNDS,
    })
}

fn add_debug_u32_delta(
    value: u32,
    delta: i64,
    function_id: u32,
    offset: u32,
) -> Result<u32, ParseError> {
    let value = i128::from(value) + i128::from(delta);
    u32::try_from(value).map_err(|_| ParseError::InvalidDebugData {
        function_id,
        offset,
        reason: DEBUG_DATA_SOURCE_VALUE_OUT_OF_BOUNDS,
    })
}

fn validate_debug_location_line_column(
    function_id: u32,
    offset: u32,
    line: u32,
    column: u32,
    allow_missing_location: bool,
) -> Result<(), ParseError> {
    if allow_missing_location && line == 0 && column == 0 {
        return Ok(());
    }
    if line == 0 || column == 0 {
        return Err(ParseError::InvalidDebugData {
            function_id,
            offset,
            reason: DEBUG_DATA_LOCATION_NOT_ONE_BASED,
        });
    }
    Ok(())
}

fn read_signed_leb128(
    data: &[u8],
    cursor: &mut usize,
    function_id: u32,
    source_locations: u32,
) -> Result<i64, ParseError> {
    let start = *cursor;
    let mut result = 0_i128;
    let mut shift = 0_u32;
    for _ in 0..10 {
        let Some(byte) = data.get(*cursor).copied() else {
            return Err(ParseError::InvalidDebugData {
                function_id,
                offset: debug_data_offset(source_locations, start),
                reason: DEBUG_DATA_TRUNCATED_LEB,
            });
        };
        *cursor += 1;
        result |= i128::from(byte & 0x7f) << shift;
        shift += 7;

        if byte & 0x80 == 0 {
            if shift < 64 && byte & 0x40 != 0 {
                result |= (!0_i128) << shift;
            }
            return i64::try_from(result).map_err(|_| ParseError::InvalidDebugData {
                function_id,
                offset: debug_data_offset(source_locations, start),
                reason: DEBUG_DATA_LEB_OVERFLOW,
            });
        }
    }

    Err(ParseError::InvalidDebugData {
        function_id,
        offset: debug_data_offset(source_locations, start),
        reason: DEBUG_DATA_LEB_OVERFLOW,
    })
}

fn debug_data_offset(source_locations: u32, relative_offset: usize) -> u32 {
    source_locations.saturating_add(u32::try_from(relative_offset).unwrap_or(u32::MAX))
}

fn function_info_bytes(
    bytes: &[u8],
    function_id: u32,
    offset: u32,
    size: u32,
    limit: u32,
) -> Result<&[u8], ParseError> {
    let end = offset
        .checked_add(size)
        .ok_or(ParseError::FunctionInfoOutOfBounds {
            function_id,
            offset,
            size,
            limit,
        })?;
    if end > limit {
        return Err(ParseError::FunctionInfoOutOfBounds {
            function_id,
            offset,
            size,
            limit,
        });
    }

    let start = usize::try_from(offset).expect("u32 always fits in usize on supported targets");
    let end = usize::try_from(end).expect("u32 always fits in usize on supported targets");
    bytes
        .get(start..end)
        .ok_or(ParseError::FunctionInfoOutOfBounds {
            function_id,
            offset,
            size,
            limit,
        })
}

fn instruction_boundaries(function_id: u32, body: SectionView<'_>) -> Result<Vec<u32>, ParseError> {
    let mut boundaries = Vec::new();
    for instruction in HermesInstructionStream::new(function_id, body) {
        boundaries.push(instruction?.offset);
    }
    Ok(boundaries)
}

fn validate_exception_handler(
    function_id: u32,
    body: SectionView<'_>,
    boundaries: &[u32],
    entry_index: u32,
    start: u32,
    end: u32,
    target: u32,
) -> Result<(), ParseError> {
    let body_size = body.len();
    let valid = start <= end
        && relative_instruction_boundary(body, start, boundaries, false)
        && relative_instruction_boundary(body, end, boundaries, true)
        && relative_instruction_boundary(body, target, boundaries, false);
    if !valid {
        return Err(ParseError::InvalidExceptionHandler {
            function_id,
            entry_index,
            start,
            end,
            target,
            body_size,
        });
    }
    Ok(())
}

fn relative_instruction_boundary(
    body: SectionView<'_>,
    relative_offset: u32,
    boundaries: &[u32],
    allow_body_end: bool,
) -> bool {
    if allow_body_end && relative_offset == body.len() {
        return true;
    }
    let Some(target) = body.offset.checked_add(relative_offset) else {
        return false;
    };
    is_instruction_boundary(body, i64::from(target), boundaries)
}

fn function_region_limit(
    function_header: HermesFunctionHeader,
    function_headers: &[DecodedFunctionHeader],
) -> Option<u32> {
    function_headers
        .iter()
        .map(|decoded| decoded.header.offset)
        .filter(|offset| *offset > function_header.offset)
        .min()
}

fn function_info_region_limit(
    header: HermesBytecodeHeader,
    large_header_offset: Option<u32>,
    function_headers: &[DecodedFunctionHeader],
) -> u32 {
    let fallback = if header.debug_info_offset == 0 {
        header
            .file_length
            .saturating_sub(HERMES_BYTECODE_FOOTER_SIZE as u32)
    } else {
        header.debug_info_offset
    };
    let Some(large_header_offset) = large_header_offset else {
        return fallback;
    };
    function_headers
        .iter()
        .filter_map(|decoded| decoded.large_header_offset)
        .filter(|offset| *offset > large_header_offset)
        .min()
        .unwrap_or(fallback)
}

fn function_body_limit(
    bytes: &[u8],
    header: HermesBytecodeHeader,
    function_headers: SectionView<'_>,
) -> Result<u32, ParseError> {
    let fallback = if header.debug_info_offset == 0 {
        header
            .file_length
            .saturating_sub(HERMES_BYTECODE_FOOTER_SIZE as u32)
    } else {
        header.debug_info_offset
    };

    let mut limit = fallback;
    for function_id in 0..header.function_count {
        let decoded = decoded_function_header_at(bytes, header, function_headers, function_id)?;
        if let Some(large_header_offset) = decoded.large_header_offset {
            limit = limit.min(large_header_offset);
        }
    }
    Ok(limit)
}

fn function_body<'a>(
    bytes: &'a [u8],
    function_id: u32,
    function_header: HermesFunctionHeader,
) -> Result<SectionView<'a>, ParseError> {
    let start = usize::try_from(function_header.offset)
        .expect("u32 always fits in usize on supported targets");
    let size = usize::try_from(function_header.bytecode_size_in_bytes)
        .expect("u32 always fits in usize on supported targets");
    let end = start
        .checked_add(size)
        .ok_or(ParseError::FunctionBodyOutOfBounds {
            function_id,
            offset: function_header.offset,
            size: function_header.bytecode_size_in_bytes,
            function_bodies_offset: function_header.offset,
            limit: u32::MAX,
        })?;
    let body = bytes
        .get(start..end)
        .ok_or(ParseError::FunctionBodyOutOfBounds {
            function_id,
            offset: function_header.offset,
            size: function_header.bytecode_size_in_bytes,
            function_bodies_offset: 0,
            limit: u32::try_from(bytes.len()).unwrap_or(u32::MAX),
        })?;
    Ok(SectionView {
        offset: function_header.offset,
        bytes: body,
    })
}

fn validate_instruction_stream(
    bytes: &[u8],
    function_id: u32,
    body: SectionView<'_>,
    context: InstructionValidationContext<'_>,
) -> Result<(), ParseError> {
    let mut boundaries = Vec::new();
    let mut instructions = Vec::new();
    for instruction in HermesInstructionStream::new(function_id, body) {
        let instruction = instruction?;
        boundaries.push(instruction.offset);
        instructions.push(instruction);
    }

    for instruction in instructions {
        validate_instruction_table_operands(function_id, body, instruction, context.header)?;
        validate_instruction_literal_operands(function_id, body, instruction, context)?;
        validate_instruction_jump_operands(function_id, body, instruction, &boundaries)?;
        validate_switch_instruction(bytes, function_id, body, instruction, context, &boundaries)?;
    }
    Ok(())
}

fn validate_instruction_table_operands(
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    header: HermesBytecodeHeader,
) -> Result<(), ParseError> {
    let instruction_bytes = instruction_bytes(body, instruction);
    for operand in BYTECODE_TABLE_OPERANDS
        .iter()
        .filter(|operand| operand.opcode == instruction.opcode)
    {
        let index = read_unsigned_operand(
            instruction_bytes,
            usize::from(operand.offset),
            usize::from(operand.width),
        );
        let limit = operand.table.limit(header);
        if index >= limit {
            return Err(ParseError::InvalidInstructionTableReference {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                table: operand.table.name(),
                index,
                limit,
            });
        }
    }
    Ok(())
}

fn validate_instruction_literal_operands(
    _function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    context: InstructionValidationContext<'_>,
) -> Result<(), ParseError> {
    let instruction_bytes = instruction_bytes(body, instruction);
    for operand in OBJECT_LITERAL_OPERANDS
        .iter()
        .filter(|operand| operand.opcode == instruction.opcode)
    {
        let shape_index = read_unsigned_operand(
            instruction_bytes,
            usize::from(operand.shape_offset),
            usize::from(operand.shape_width),
        );
        let shape = object_shape_entry_at(context.obj_shape_table, shape_index)
            .expect("object shape table operand was validated before literal buffer parsing");
        let value_offset = read_unsigned_operand(
            instruction_bytes,
            usize::from(operand.value_offset),
            usize::from(operand.value_width),
        );
        validate_serialized_literal_buffer(
            "literal_value_buffer",
            context.literal_value_buffer,
            value_offset,
            shape.num_props,
            false,
            None,
            context.header,
        )?;
    }

    for operand in ARRAY_LITERAL_OPERANDS
        .iter()
        .filter(|operand| operand.opcode == instruction.opcode)
    {
        let element_count = read_unsigned_operand(
            instruction_bytes,
            usize::from(operand.element_count_offset),
            usize::from(operand.element_count_width),
        );
        let value_offset = read_unsigned_operand(
            instruction_bytes,
            usize::from(operand.value_offset),
            usize::from(operand.value_width),
        );
        validate_serialized_literal_buffer(
            "literal_value_buffer",
            context.literal_value_buffer,
            value_offset,
            element_count,
            false,
            None,
            context.header,
        )?;
    }
    Ok(())
}

fn validate_instruction_jump_operands(
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    boundaries: &[u32],
) -> Result<(), ParseError> {
    let instruction_bytes = instruction_bytes(body, instruction);
    for operand in JUMP_OPERANDS
        .iter()
        .filter(|operand| operand.opcode == instruction.opcode)
    {
        let delta = read_signed_operand(
            instruction_bytes,
            usize::from(operand.offset),
            usize::from(operand.width),
        );
        validate_jump_target(function_id, body, instruction, delta, boundaries)?;
    }
    Ok(())
}

fn validate_switch_instruction(
    bytes: &[u8],
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    context: InstructionValidationContext<'_>,
    boundaries: &[u32],
) -> Result<(), ParseError> {
    match instruction.opcode {
        UINT_SWITCH_IMM_OPCODE => validate_uint_switch_instruction(
            bytes,
            function_id,
            body,
            instruction,
            context,
            boundaries,
        ),
        STRING_SWITCH_IMM_OPCODE => validate_string_switch_instruction(
            bytes,
            function_id,
            body,
            instruction,
            context,
            boundaries,
        ),
        _ => Ok(()),
    }
}

fn validate_uint_switch_instruction(
    bytes: &[u8],
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    context: InstructionValidationContext<'_>,
    boundaries: &[u32],
) -> Result<(), ParseError> {
    let instruction_bytes = instruction_bytes(body, instruction);
    let table_offset = read_unsigned_operand(instruction_bytes, 2, 4);
    let default_delta = read_signed_operand(instruction_bytes, 6, 4);
    let minimum = read_unsigned_operand(instruction_bytes, 10, 4);
    let maximum = read_unsigned_operand(instruction_bytes, 14, 4);

    validate_jump_target(function_id, body, instruction, default_delta, boundaries)?;
    if maximum < minimum {
        return Err(ParseError::InvalidSwitchTableRange {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            minimum,
            maximum,
        });
    }

    let entry_count = maximum
        .checked_sub(minimum)
        .and_then(|span| span.checked_add(1))
        .ok_or(ParseError::InvalidSwitchTableRange {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            minimum,
            maximum,
        })?;
    let table_bytes = checked_table_size(entry_count, size_of::<u32>() as u32);
    let table = switch_table_bytes(
        bytes,
        function_id,
        body,
        instruction,
        table_offset,
        table_bytes,
        context.function_region_limit,
    )?;

    for (entry_index, entry) in table.chunks_exact(size_of::<u32>()).enumerate() {
        let delta = i64::from(i32::from_le_bytes(
            entry
                .try_into()
                .expect("switch table entry is exactly u32 sized"),
        ));
        validate_switch_table_target(
            function_id,
            body,
            instruction,
            u32::try_from(entry_index).expect("switch table entry index fits in u32"),
            delta,
            boundaries,
        )?;
    }
    Ok(())
}

fn validate_string_switch_instruction(
    bytes: &[u8],
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    context: InstructionValidationContext<'_>,
    boundaries: &[u32],
) -> Result<(), ParseError> {
    let instruction_bytes = instruction_bytes(body, instruction);
    let switch_index = read_unsigned_operand(instruction_bytes, 2, 4);
    let table_offset = read_unsigned_operand(instruction_bytes, 6, 4);
    let default_delta = read_signed_operand(instruction_bytes, 10, 4);
    let entry_count = read_unsigned_operand(instruction_bytes, 14, 4);

    if switch_index >= context.header.num_string_switch_imms {
        return Err(ParseError::InvalidInstructionTableReference {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            table: "string_switch",
            index: switch_index,
            limit: context.header.num_string_switch_imms,
        });
    }

    validate_jump_target(function_id, body, instruction, default_delta, boundaries)?;
    let table_bytes = checked_table_size(entry_count, SWITCH_TABLE_CASE_SIZE as u32);
    let table = switch_table_bytes(
        bytes,
        function_id,
        body,
        instruction,
        table_offset,
        table_bytes,
        context.function_region_limit,
    )?;

    for (entry_index, entry) in table.chunks_exact(SWITCH_TABLE_CASE_SIZE).enumerate() {
        let string_id = read_u32(entry, 0);
        if string_id >= context.header.string_count {
            return Err(ParseError::InvalidInstructionTableReference {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                table: "string",
                index: string_id,
                limit: context.header.string_count,
            });
        }
        let delta = i64::from(i32::from_le_bytes(
            entry[4..8]
                .try_into()
                .expect("string switch target entry is exactly i32 sized"),
        ));
        validate_switch_table_target(
            function_id,
            body,
            instruction,
            u32::try_from(entry_index).expect("switch table entry index fits in u32"),
            delta,
            boundaries,
        )?;
    }
    Ok(())
}

fn switch_table_bytes<'a>(
    bytes: &'a [u8],
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    table_offset: u32,
    table_size: u32,
    region_limit: u32,
) -> Result<&'a [u8], ParseError> {
    let table_start = instruction
        .offset
        .checked_add(table_offset)
        .and_then(|offset| align_u32(offset, SWITCH_TABLE_ALIGNMENT))
        .ok_or(ParseError::SwitchTableOutOfBounds {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            table_start: u32::MAX,
            table_size,
            region_limit,
        })?;
    let table_end =
        table_start
            .checked_add(table_size)
            .ok_or(ParseError::SwitchTableOutOfBounds {
                function_id,
                offset: instruction.offset,
                opcode: instruction.opcode,
                table_start,
                table_size,
                region_limit,
            })?;

    if table_start < body.offset + body.len() || table_end > region_limit {
        return Err(ParseError::SwitchTableOutOfBounds {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            table_start,
            table_size,
            region_limit,
        });
    }

    let start =
        usize::try_from(table_start).expect("u32 always fits in usize on supported targets");
    let end = usize::try_from(table_end).expect("u32 always fits in usize on supported targets");
    bytes
        .get(start..end)
        .ok_or(ParseError::SwitchTableOutOfBounds {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            table_start,
            table_size,
            region_limit,
        })
}

fn validate_jump_target(
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    delta: i64,
    boundaries: &[u32],
) -> Result<(), ParseError> {
    let target = i64::from(instruction.offset) + delta;
    if !is_instruction_boundary(body, target, boundaries) {
        return Err(ParseError::InvalidJumpTarget {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            target,
            body_start: body.offset,
            body_end: body.offset + body.len(),
        });
    }
    Ok(())
}

fn validate_switch_table_target(
    function_id: u32,
    body: SectionView<'_>,
    instruction: HermesInstruction,
    entry_index: u32,
    delta: i64,
    boundaries: &[u32],
) -> Result<(), ParseError> {
    let target = i64::from(instruction.offset) + delta;
    if !is_instruction_boundary(body, target, boundaries) {
        return Err(ParseError::InvalidSwitchTableTarget {
            function_id,
            offset: instruction.offset,
            opcode: instruction.opcode,
            entry_index,
            target,
            body_start: body.offset,
            body_end: body.offset + body.len(),
        });
    }
    Ok(())
}

fn is_instruction_boundary(body: SectionView<'_>, target: i64, boundaries: &[u32]) -> bool {
    if target < i64::from(body.offset) || target >= i64::from(body.offset + body.len()) {
        return false;
    }
    u32::try_from(target)
        .ok()
        .is_some_and(|target| boundaries.binary_search(&target).is_ok())
}

fn instruction_bytes(body: SectionView<'_>, instruction: HermesInstruction) -> &[u8] {
    let start = usize::try_from(instruction.offset - body.offset)
        .expect("instruction offset was validated inside the function body");
    let end = start + usize::from(instruction.width);
    &body.bytes[start..end]
}

fn read_unsigned_operand(bytes: &[u8], offset: usize, width: usize) -> u32 {
    match width {
        1 => u32::from(bytes[offset]),
        2 => u32::from(bytes[offset]) | (u32::from(bytes[offset + 1]) << 8),
        4 => {
            u32::from(bytes[offset])
                | (u32::from(bytes[offset + 1]) << 8)
                | (u32::from(bytes[offset + 2]) << 16)
                | (u32::from(bytes[offset + 3]) << 24)
        }
        _ => unreachable!("Hermes integer operand width is 1, 2, or 4 bytes"),
    }
}

fn read_signed_operand(bytes: &[u8], offset: usize, width: usize) -> i64 {
    match width {
        1 => i64::from(i8::from_le_bytes([bytes[offset]])),
        4 => {
            let value = u32::from(bytes[offset])
                | (u32::from(bytes[offset + 1]) << 8)
                | (u32::from(bytes[offset + 2]) << 16)
                | (u32::from(bytes[offset + 3]) << 24);
            i64::from(value as i32)
        }
        _ => unreachable!("Hermes jump operand width is 1 or 4 bytes"),
    }
}

fn checked_table_size(entry_count: u32, entry_size: u32) -> u32 {
    entry_count.checked_mul(entry_size).unwrap_or(u32::MAX)
}

fn align_u32(offset: u32, alignment: u32) -> Option<u32> {
    offset
        .checked_add(alignment - 1)
        .map(|adjusted| adjusted / alignment * alignment)
}

fn count_function_instructions(function_id: u32, body: SectionView<'_>) -> Result<u32, ParseError> {
    let mut count = 0_u32;
    for instruction in HermesInstructionStream::new(function_id, body) {
        instruction?;
        count = count
            .checked_add(1)
            .expect("instruction count cannot exceed u32 because HBC file length is u32");
    }
    Ok(count)
}

fn hermes_opcode_width(opcode: u8) -> Option<u8> {
    HERMES_OPCODE_WIDTHS.get(usize::from(opcode)).copied()
}

fn validate_cjs_module_table(bytes: &[u8], header: HermesBytecodeHeader) -> Result<(), ParseError> {
    for (index, entry) in bytes.chunks_exact(U32_PAIR_ENTRY_SIZE).enumerate() {
        let first = read_u32(entry, 0);
        let second = read_u32(entry, 4);
        let statically_resolved = header.options.cjs_modules_statically_resolved();
        let invalid = if statically_resolved {
            second >= header.function_count
        } else {
            first >= header.string_count || second >= header.function_count
        };
        if invalid {
            return Err(ParseError::InvalidCjsModuleEntry {
                entry_index: u32::try_from(index)
                    .expect("validated CJS module table index fits in u32"),
                first,
                second,
                statically_resolved,
            });
        }
    }
    Ok(())
}

fn validate_function_source_table(
    bytes: &[u8],
    header: HermesBytecodeHeader,
) -> Result<(), ParseError> {
    for (index, entry) in bytes.chunks_exact(U32_PAIR_ENTRY_SIZE).enumerate() {
        let function_id = read_u32(entry, 0);
        let string_id = read_u32(entry, 4);
        if function_id >= header.function_count || string_id >= header.string_count {
            return Err(ParseError::InvalidFunctionSourceEntry {
                entry_index: u32::try_from(index)
                    .expect("validated function source table index fits in u32"),
                function_id,
                string_id,
            });
        }
    }
    Ok(())
}

fn read_u32(bytes: &[u8], offset: usize) -> u32 {
    u32::from_le_bytes(bytes[offset..offset + size_of::<u32>()].try_into().expect(
        "HermesBytecodeHeader::parse validates the full header length before reading fields",
    ))
}

fn read_i32(bytes: &[u8], offset: usize) -> i32 {
    i32::from_le_bytes(bytes[offset..offset + size_of::<i32>()].try_into().expect(
        "HermesBytecodeHeader::parse validates the full header length before reading fields",
    ))
}

fn read_u64(bytes: &[u8], offset: usize) -> u64 {
    u64::from_le_bytes(bytes[offset..offset + size_of::<u64>()].try_into().expect(
        "HermesBytecodeHeader::parse validates the full header length before reading fields",
    ))
}

fn read_f64(bytes: &[u8], offset: usize) -> f64 {
    f64::from_le_bytes(
        bytes[offset..offset + size_of::<f64>()]
            .try_into()
            .expect("validated Hermes double operand has f64 width"),
    )
}

