    #[test]
    fn scalar_global_number_add_put_candidate_updates_global_number() {
        let bytes = fixture_bytecode();
        let bytecode = HermesBytecode::parse(&bytes).expect("valid Hermes bytecode");
        let mut state = ScalarExecutorState::default();
        let mut registers = [
            ScalarValue::Empty,
            ScalarValue::Number(2.0),
            ScalarValue::Object(ScalarObjectHandle::Global),
        ];
        let instructions = [
            HermesInstruction {
                offset: 100,
                opcode: GET_BY_ID_SHORT_OPCODE,
                width: 6,
            },
            HermesInstruction {
                offset: 106,
                opcode: 30,
                width: 4,
            },
            HermesInstruction {
                offset: 110,
                opcode: PUT_BY_ID_LOOSE_OPCODE,
                width: 6,
            },
        ];
        let get_bytes = [GET_BY_ID_SHORT_OPCODE, 0, 2, 0, 1, 0];
        let add_bytes = [30, 0, 0, 1];
        let put_bytes = [PUT_BY_ID_LOOSE_OPCODE, 2, 0, 0, 1, 0];
        let instruction_bytes = [&get_bytes[..], &add_bytes[..], &put_bytes[..]];
        let mut string_operand_cache = ScalarStringOperandCache::default();

        write_cached_scalar_global_property(&mut state, 1, "cdef", ScalarValue::Number(10.0));
        assert_eq!(
            try_execute_scalar_global_number_add_put_candidate(
                &bytecode,
                &mut state,
                &mut registers,
                1,
                &instructions,
                &instruction_bytes,
                &mut string_operand_cache,
                0,
            ),
            Ok(Some(3)),
        );
        assert_eq!(registers[0], ScalarValue::Number(12.0));
        assert_eq!(
            read_cached_scalar_global_property(&mut state, 1, "cdef"),
            ScalarValue::Number(12.0),
        );

        registers[0] = ScalarValue::Number(999.0);
        registers[1] = ScalarValue::Number(2.0);
        let add_self_bytes = [30, 0, 0, 0];
        let instruction_bytes = [&get_bytes[..], &add_self_bytes[..], &put_bytes[..]];
        write_cached_scalar_global_property(&mut state, 1, "cdef", ScalarValue::Number(5.0));
        assert_eq!(
            try_execute_scalar_global_number_add_put_candidate(
                &bytecode,
                &mut state,
                &mut registers,
                1,
                &instructions,
                &instruction_bytes,
                &mut string_operand_cache,
                0,
            ),
            Ok(Some(3)),
        );
        assert_eq!(registers[0], ScalarValue::Number(10.0));
        assert_eq!(
            read_cached_scalar_global_property(&mut state, 1, "cdef"),
            ScalarValue::Number(10.0),
        );

        registers[0] = ScalarValue::Empty;
        registers[1] = ScalarValue::String(ScalarStringHandle {
            string_id: 1,
            is_empty: false,
        });
        let instruction_bytes = [&get_bytes[..], &add_bytes[..], &put_bytes[..]];
        assert_eq!(
            try_execute_scalar_global_number_add_put_candidate(
                &bytecode,
                &mut state,
                &mut registers,
                1,
                &instructions,
                &instruction_bytes,
                &mut string_operand_cache,
                0,
            ),
            Ok(None),
        );
        assert_eq!(registers[0], ScalarValue::Empty);
    }

    #[test]
    fn scalar_global_number_checksum_sequence_candidate_updates_global_number() {
        let bytes = fixture_bytecode();
        let bytecode = HermesBytecode::parse(&bytes).expect("valid Hermes bytecode");
        let mut state = ScalarExecutorState::default();
        let mut registers = [
            ScalarValue::Empty,
            ScalarValue::Empty,
            ScalarValue::Empty,
            ScalarValue::Number(6.0),
            ScalarValue::Number(3.0),
            ScalarValue::Number(7.0),
            ScalarValue::Object(ScalarObjectHandle::Global),
        ];
        let instructions = [
            HermesInstruction {
                offset: 100,
                opcode: GET_BY_ID_SHORT_OPCODE,
                width: 6,
            },
            HermesInstruction {
                offset: 106,
                opcode: GET_BY_ID_SHORT_OPCODE,
                width: 6,
            },
            HermesInstruction {
                offset: 112,
                opcode: 37,
                width: 4,
            },
            HermesInstruction {
                offset: 116,
                opcode: 34,
                width: 4,
            },
            HermesInstruction {
                offset: 120,
                opcode: 30,
                width: 4,
            },
            HermesInstruction {
                offset: 124,
                opcode: GET_BY_ID_SHORT_OPCODE,
                width: 6,
            },
            HermesInstruction {
                offset: 130,
                opcode: 37,
                width: 4,
            },
            HermesInstruction {
                offset: 134,
                opcode: 38,
                width: 4,
            },
            HermesInstruction {
                offset: 138,
                opcode: PUT_BY_ID_LOOSE_OPCODE,
                width: 6,
            },
        ];
        let target_get_bytes = [GET_BY_ID_SHORT_OPCODE, 2, 6, 0, 1, 0];
        let source_get_bytes = [GET_BY_ID_SHORT_OPCODE, 1, 6, 0, 1, 0];
        let first_mod_bytes = [37, 0, 1, 3];
        let mul_bytes = [34, 0, 0, 4];
        let add_bytes = [30, 2, 2, 0];
        let second_source_get_bytes = [GET_BY_ID_SHORT_OPCODE, 1, 6, 0, 1, 0];
        let second_mod_bytes = [37, 0, 1, 5];
        let sub_bytes = [38, 0, 2, 0];
        let put_bytes = [PUT_BY_ID_LOOSE_OPCODE, 6, 0, 0, 1, 0];
        let instruction_bytes = [
            &target_get_bytes[..],
            &source_get_bytes[..],
            &first_mod_bytes[..],
            &mul_bytes[..],
            &add_bytes[..],
            &second_source_get_bytes[..],
            &second_mod_bytes[..],
            &sub_bytes[..],
            &put_bytes[..],
        ];
        let mut string_operand_cache = ScalarStringOperandCache::default();

        write_cached_scalar_global_property(&mut state, 1, "cdef", ScalarValue::Number(23.0));
        assert_eq!(
            try_execute_scalar_global_number_checksum_sequence_candidate(
                &bytecode,
                &mut state,
                &mut registers,
                1,
                &instructions,
                &instruction_bytes,
                &mut string_operand_cache,
                0,
            ),
            Ok(Some(9)),
        );
        assert_eq!(registers[2], ScalarValue::Number(38.0));
        assert_eq!(registers[1], ScalarValue::Number(23.0));
        assert_eq!(registers[0], ScalarValue::Number(36.0));
        assert_eq!(
            read_cached_scalar_global_property(&mut state, 1, "cdef"),
            ScalarValue::Number(36.0),
        );

        write_cached_scalar_global_property(&mut state, 1, "cdef", ScalarValue::Number(23.0));
        let aliased_first_mod_bytes = [37, 0, 1, 2];
        let aliased_instruction_bytes = [
            &target_get_bytes[..],
            &source_get_bytes[..],
            &aliased_first_mod_bytes[..],
            &mul_bytes[..],
            &add_bytes[..],
            &second_source_get_bytes[..],
            &second_mod_bytes[..],
            &sub_bytes[..],
            &put_bytes[..],
        ];
        assert_eq!(
            try_execute_scalar_global_number_checksum_sequence_candidate(
                &bytecode,
                &mut state,
                &mut registers,
                1,
                &instructions,
                &aliased_instruction_bytes,
                &mut string_operand_cache,
                0,
            ),
            Ok(None),
        );

        write_cached_scalar_global_property(
            &mut state,
            1,
            "cdef",
            ScalarValue::String(ScalarStringHandle {
                string_id: 1,
                is_empty: false,
            }),
        );
        assert_eq!(
            try_execute_scalar_global_number_checksum_sequence_candidate(
                &bytecode,
                &mut state,
                &mut registers,
                1,
                &instructions,
                &instruction_bytes,
                &mut string_operand_cache,
                0,
            ),
            Ok(None),
        );
    }

